const EPISODES = [{"id": 1, "key": "myguichet", "number": "Episode 1", "title": "MyGuichet.lu – Your Online Door to Luxembourg’s Administration", "description": "What MyGuichet.lu is, what you can do with it, and how to register with your matricule and a secure login such as LuxTrust, the Luxembourg eID or a European eIDAS login.", "audio": "podcast_myguichet.mp3", "duration": 623.88, "topics": ["What MyGuichet.lu is", "Your personal eSpace", "Online procedures", "Registering (matricule)", "LuxTrust & eID login", "eIDAS European login", "Available languages", "Mobile app"], "segments": [{"speaker": "Anna", "text": "Hello, and welcome!", "t": 0.0}, {"speaker": "Anna", "text": "It's really nice to have you with us today.", "t": 2.26}, {"speaker": "Tom", "text": "Hello everyone!", "t": 6.12}, {"speaker": "Anna", "text": "This episode is part of the Biergerpakt.", "t": 8.64}, {"speaker": "Anna", "text": "That's a programme of living together in Luxembourg.", "t": 11.6}, {"speaker": "Anna", "text": "The idea is simple...", "t": 15.34}, {"speaker": "Anna", "text": "we want to help residents, and also cross-border workers, to discover Luxembourg — or maybe re-discover it — and to meet new people.", "t": 16.92}, {"speaker": "Anna", "text": "So you can connect, and exchange ideas.", "t": 25.54}, {"speaker": "Tom", "text": "Exactly.", "t": 29.42}, {"speaker": "Tom", "text": "And today we talk about something very useful.", "t": 31.4}, {"speaker": "Tom", "text": "Especially if you just arrived in Luxembourg.", "t": 35.26}, {"speaker": "Tom", "text": "It's called MyGuichet.lu.", "t": 38.68}, {"speaker": "Anna", "text": "Right.", "t": 42.1}, {"speaker": "Anna", "text": "So, Tom...", "t": 43.28}, {"speaker": "Anna", "text": "let's start at the beginning.", "t": 44.8}, {"speaker": "Anna", "text": "What is MyGuichet.lu?", "t": 46.62}, {"speaker": "Tom", "text": "Okay, so...", "t": 49.54}, {"speaker": "Tom", "text": "MyGuichet.lu is the official online platform of the Luxembourg government.", "t": 53.06}, {"speaker": "Tom", "text": "It's secure, and it's your...", "t": 57.02}, {"speaker": "Tom", "text": "let's say, your single point of contact with the public administration.", "t": 59.12}, {"speaker": "Tom", "text": "So instead of going to an office, you can do many administrative things from home.", "t": 64.22}, {"speaker": "Tom", "text": "On your computer, or on your phone.", "t": 69.62}, {"speaker": "Anna", "text": "So it's like...", "t": 73.62}, {"speaker": "Anna", "text": "an online counter?", "t": 74.64}, {"speaker": "Tom", "text": "Yes!", "t": 77.14}, {"speaker": "Tom", "text": "Actually, that's what the word means.", "t": 78.86}, {"speaker": "Tom", "text": "\"Guichet\" is a French word.", "t": 82.72}, {"speaker": "Tom", "text": "It means \"counter\" — you know, the desk with the small window, where you go in an office to ask for something.", "t": 83.96}, {"speaker": "Anna", "text": "Ah, okay.", "t": 93.08}, {"speaker": "Anna", "text": "So MyGuichet is...", "t": 94.64}, {"speaker": "Anna", "text": "\"my counter\".", "t": 96.66}, {"speaker": "Anna", "text": "My personal counter with the State.", "t": 98.06}, {"speaker": "Tom", "text": "Exactly.", "t": 101.52}, {"speaker": "Tom", "text": "But online.", "t": 103.28}, {"speaker": "Tom", "text": "Open every day, at any hour.", "t": 105.16}, {"speaker": "Anna", "text": "Nice.", "t": 108.78}, {"speaker": "Anna", "text": "And, hmm...", "t": 110.02}, {"speaker": "Anna", "text": "what can I actually do with it?", "t": 111.2}, {"speaker": "Tom", "text": "Quite a lot, really.", "t": 114.1}, {"speaker": "Tom", "text": "The main thing is...", "t": 116.6}, {"speaker": "Tom", "text": "you can do administrative procedures online.", "t": 117.9}, {"speaker": "Tom", "text": "The website has these step-by-step forms — they call them \"online assistants\".", "t": 121.32}, {"speaker": "Tom", "text": "They guide you through the questions, one by one.", "t": 126.8}, {"speaker": "Tom", "text": "You fill them in, you add your documents, and you send everything directly to the right administration.", "t": 130.28}, {"speaker": "Anna", "text": "Without printing anything?", "t": 138.02}, {"speaker": "Tom", "text": "For many procedures, yes.", "t": 140.6}, {"speaker": "Tom", "text": "No printing, no envelope, no stamp.", "t": 143.42}, {"speaker": "Tom", "text": "And there's more.", "t": 147.64}, {"speaker": "Tom", "text": "On MyGuichet, you have your own personal space.", "t": 149.54}, {"speaker": "Tom", "text": "They call it an \"eSpace\".", "t": 153.7}, {"speaker": "Tom", "text": "In your eSpace, you can follow the status of your requests...", "t": 156.24}, {"speaker": "Tom", "text": "so you can see, okay, my file arrived, it is being processed, and so on.", "t": 159.66}, {"speaker": "Anna", "text": "That's good.", "t": 167.0}, {"speaker": "Anna", "text": "Because normally you send a letter and then...", "t": 168.4}, {"speaker": "Anna", "text": "silence.", "t": 171.24}, {"speaker": "Tom", "text": "Yes, exactly.", "t": 172.98}, {"speaker": "Tom", "text": "And in your eSpace you can also see the personal data the State has about you.", "t": 175.58}, {"speaker": "Tom", "text": "The official data — for example from the national registry.", "t": 180.0}, {"speaker": "Tom", "text": "You can also receive official messages and documents there, electronically.", "t": 185.42}, {"speaker": "Tom", "text": "And...", "t": 190.52}, {"speaker": "Tom", "text": "one more thing...", "t": 190.74}, {"speaker": "Tom", "text": "you can book appointments online with some administrations.", "t": 192.02}, {"speaker": "Anna", "text": "Okay, wait, let me repeat that.", "t": 196.8}, {"speaker": "Anna", "text": "So I can...", "t": 200.12}, {"speaker": "Anna", "text": "do procedures online, follow my files, check my official data, receive documents, and book appointments.", "t": 200.88}, {"speaker": "Tom", "text": "That's it.", "t": 210.06}, {"speaker": "Tom", "text": "And you can also store important documents in your eSpace, so they are always with you.", "t": 211.1}, {"speaker": "Tom", "text": "Oh — and there is a mobile app, too.", "t": 217.08}, {"speaker": "Tom", "text": "MyGuichet.lu, for your smartphone.", "t": 222.22}, {"speaker": "Anna", "text": "Very complete.", "t": 224.98}, {"speaker": "Anna", "text": "Now...", "t": 226.7}, {"speaker": "Anna", "text": "the big question.", "t": 227.34}, {"speaker": "Anna", "text": "Why should I use it?", "t": 229.0}, {"speaker": "Anna", "text": "I mean, I can still go to the office, no?", "t": 230.72}, {"speaker": "Tom", "text": "Of course, you can.", "t": 234.0}, {"speaker": "Tom", "text": "But the offices are open during the day, when many of us are at work.", "t": 237.46}, {"speaker": "Tom", "text": "MyGuichet is open twenty-four hours, seven days a week.", "t": 243.16}, {"speaker": "Tom", "text": "You save time — no queue, no waiting.", "t": 247.22}, {"speaker": "Tom", "text": "And everything stays in one place.", "t": 251.34}, {"speaker": "Anna", "text": "And it's in English?", "t": 254.96}, {"speaker": "Tom", "text": "The website, yes — Guichet.lu exists in French, German and English.", "t": 256.12}, {"speaker": "Tom", "text": "And many procedures too.", "t": 263.74}, {"speaker": "Tom", "text": "Not all of them, but many.", "t": 266.24}, {"speaker": "Tom", "text": "So for someone who just arrived and doesn't speak French yet...", "t": 268.76}, {"speaker": "Tom", "text": "it really helps.", "t": 272.08}, {"speaker": "Anna", "text": "Mmm, that's important.", "t": 275.26}, {"speaker": "Anna", "text": "Okay.", "t": 276.96}, {"speaker": "Anna", "text": "So now, how do I start?", "t": 278.18}, {"speaker": "Anna", "text": "What do I need?", "t": 280.58}, {"speaker": "Tom", "text": "Right, so...", "t": 282.5}, {"speaker": "Tom", "text": "to register on MyGuichet.lu, you need a few things.", "t": 283.94}, {"speaker": "Tom", "text": "First, you must be at least sixteen years old.", "t": 288.58}, {"speaker": "Tom", "text": "Then you need your Luxembourg national identification number.", "t": 292.66}, {"speaker": "Tom", "text": "That's a thirteen-digit number — people here call it the \"matricule\".", "t": 297.04}, {"speaker": "Tom", "text": "You get it when you register in Luxembourg, or when you start working here.", "t": 301.88}, {"speaker": "Anna", "text": "The matricule, okay.", "t": 306.5}, {"speaker": "Anna", "text": "Cross-border workers have one too, right?", "t": 310.06}, {"speaker": "Tom", "text": "Yes, if you work in Luxembourg, you have one.", "t": 313.76}, {"speaker": "Tom", "text": "It's on your social security card, for example.", "t": 314.44}, {"speaker": "Tom", "text": "Then you need an email address, a computer or a smartphone...", "t": 315.13}, {"speaker": "Tom", "text": "and one more thing.", "t": 315.81}, {"speaker": "Tom", "text": "A way to prove your identity online.", "t": 316.49}, {"speaker": "Tom", "text": "A secure login, let's say.", "t": 317.18}, {"speaker": "Anna", "text": "Ah, and this is where LuxTrust comes in?", "t": 317.86}, {"speaker": "Tom", "text": "Exactly.", "t": 321.6}, {"speaker": "Tom", "text": "So...", "t": 323.6}, {"speaker": "Tom", "text": "LuxTrust.", "t": 325.27}, {"speaker": "Tom", "text": "Let me explain, because everyone in Luxembourg talks about LuxTrust.", "t": 326.94}, {"speaker": "Anna", "text": "True!", "t": 332.82}, {"speaker": "Tom", "text": "LuxTrust is a company that provides secure digital identity.", "t": 335.1}, {"speaker": "Tom", "text": "The most popular product is LuxTrust Mobile — an app on your phone.", "t": 339.34}, {"speaker": "Tom", "text": "When you log in somewhere, the app asks you to confirm.", "t": 344.38}, {"speaker": "Tom", "text": "Many people already use it for their online banking here.", "t": 348.58}, {"speaker": "Anna", "text": "Okay, so the question many listeners will have...", "t": 353.42}, {"speaker": "Anna", "text": "do I need LuxTrust to use MyGuichet?", "t": 356.84}, {"speaker": "Tom", "text": "Good question.", "t": 360.0}, {"speaker": "Tom", "text": "The answer is...", "t": 362.34}, {"speaker": "Tom", "text": "not necessarily.", "t": 363.5}, {"speaker": "Tom", "text": "You need *one* secure way to log in, but you have a choice.", "t": 365.7}, {"speaker": "Tom", "text": "It can be a LuxTrust product, yes.", "t": 370.32}, {"speaker": "Tom", "text": "Or the Luxembourg electronic identity card — the eID — if you have a Luxembourg ID card with the certificates activated.", "t": 373.74}, {"speaker": "Tom", "text": "Or, and this is interesting for people from other European countries...", "t": 382.66}, {"speaker": "Tom", "text": "an eIDAS login from your own country.", "t": 387.56}, {"speaker": "Anna", "text": "eIDAS...", "t": 389.77}, {"speaker": "Anna", "text": "that's the European system, right?", "t": 391.98}, {"speaker": "Anna", "text": "So I could use, for example, my Belgian or German electronic ID?", "t": 394.86}, {"speaker": "Tom", "text": "Exactly.", "t": 401.2}, {"speaker": "Tom", "text": "If your country has one of these national systems, you can often use it to log in to MyGuichet.", "t": 402.8}, {"speaker": "Tom", "text": "And one more thing — some simple procedures work even *without* logging in at all.", "t": 409.24}, {"speaker": "Tom", "text": "But then you have fewer options.", "t": 414.84}, {"speaker": "Tom", "text": "You can't save the form and continue later, and you can't follow the status.", "t": 417.28}, {"speaker": "Tom", "text": "So...", "t": 423.0}, {"speaker": "Tom", "text": "having a real account is much better.", "t": 423.44}, {"speaker": "Tom", "text": "But honestly, if you live or work here, LuxTrust Mobile is the easy way.", "t": 426.96}, {"speaker": "Tom", "text": "You install the app once, and...", "t": 432.8}, {"speaker": "Tom", "text": "that's it.", "t": 434.9}, {"speaker": "Tom", "text": "And if you already use it for your bank, you can use the same one.", "t": 436.62}, {"speaker": "Anna", "text": "Good.", "t": 441.76}, {"speaker": "Anna", "text": "So, let's say I have my matricule and my LuxTrust.", "t": 443.08}, {"speaker": "Anna", "text": "What do I do?", "t": 447.2}, {"speaker": "Tom", "text": "It's quite simple.", "t": 449.4}, {"speaker": "Tom", "text": "You go to Guichet.lu, you click on \"Log in\", and you follow the steps with your email and your matricule.", "t": 451.46}, {"speaker": "Tom", "text": "Then you create your personal eSpace.", "t": 458.68}, {"speaker": "Tom", "text": "It takes a few minutes.", "t": 461.96}, {"speaker": "Tom", "text": "And there are tutorials on the website, step by step.", "t": 464.4}, {"speaker": "Anna", "text": "Perfect.", "t": 469.32}, {"speaker": "Anna", "text": "Now...", "t": 470.74}, {"speaker": "Anna", "text": "what kind of procedures are we talking about?", "t": 471.5}, {"speaker": "Anna", "text": "Which areas?", "t": 474.82}, {"speaker": "Tom", "text": "Almost everything in daily life, really.", "t": 476.64}, {"speaker": "Tom", "text": "Let's see...", "t": 480.16}, {"speaker": "Tom", "text": "citizenship — so identity card, passport, criminal record.", "t": 481.22}, {"speaker": "Tom", "text": "And here is a nice one: as a foreign resident, you can apply to register on the electoral rolls — so you can vote in the communal elections, and in the European elections.", "t": 486.68}, {"speaker": "Tom", "text": "Then immigration — residence permits, for example.", "t": 496.5}, {"speaker": "Tom", "text": "Very important when you arrive.", "t": 502.14}, {"speaker": "Tom", "text": "Then family and education...", "t": 504.82}, {"speaker": "Tom", "text": "taxation — yes, you can do your tax return online.", "t": 506.8}, {"speaker": "Tom", "text": "Transport — your driving licence, registering a car.", "t": 511.32}, {"speaker": "Tom", "text": "Health and social security.", "t": 516.12}, {"speaker": "Tom", "text": "Housing.", "t": 518.94}, {"speaker": "Tom", "text": "Financial aid.", "t": 520.66}, {"speaker": "Tom", "text": "Work and pension...", "t": 522.76}, {"speaker": "Tom", "text": "and even leisure, like fishing permits.", "t": 524.02}, {"speaker": "Anna", "text": "Wow.", "t": 527.66}, {"speaker": "Anna", "text": "So really...", "t": 529.2}, {"speaker": "Anna", "text": "from the passport to the fishing permit.", "t": 530.26}, {"speaker": "Tom", "text": "That's right.", "t": 533.76}, {"speaker": "Tom", "text": "And maybe one sentence for the entrepreneurs listening: businesses can use MyGuichet too, with a business eSpace, for things like tax and VAT declarations, social security declarations for their staff, or applying for permits and licences.", "t": 535.68}, {"speaker": "Anna", "text": "Good to know.", "t": 552.2}, {"speaker": "Anna", "text": "Okay, Tom, let's wrap up.", "t": 553.42}, {"speaker": "Anna", "text": "Short summary?", "t": 556.42}, {"speaker": "Tom", "text": "Sure.", "t": 558.54}, {"speaker": "Tom", "text": "MyGuichet.lu is the secure online platform of the Luxembourg State.", "t": 561.22}, {"speaker": "Tom", "text": "You can do your administrative procedures from home, follow your files, receive official documents, and book appointments.", "t": 564.6}, {"speaker": "Tom", "text": "To use it fully, you register with your matricule and a secure login — LuxTrust, the Luxembourg eID, or a European eIDAS login from your country.", "t": 573.52}, {"speaker": "Anna", "text": "And if you need help, there are tutorials on Guichet.lu, and a helpdesk — you can even book a video call.", "t": 584.64}, {"speaker": "Anna", "text": "So...", "t": 592.64}, {"speaker": "Anna", "text": "don't be afraid to try.", "t": 593.16}, {"speaker": "Tom", "text": "Really, it makes life in Luxembourg easier.", "t": 595.96}, {"speaker": "Tom", "text": "Especially in the first months.", "t": 599.92}, {"speaker": "Anna", "text": "That was our episode about MyGuichet.lu, part of the Biergerpakt — living together in Luxembourg, discovering the country, and meeting new people.", "t": 603.24}, {"speaker": "Anna", "text": "Thank you so much for listening.", "t": 612.86}, {"speaker": "Tom", "text": "Thank you, everyone.", "t": 616.3}, {"speaker": "Tom", "text": "Take care...", "t": 618.76}, {"speaker": "Tom", "text": "and see you next time!", "t": 619.58}, {"speaker": "Anna", "text": "Bye bye!", "t": 622.72}], "questions": [{"text": "What is MyGuichet.lu?", "options": ["A paid subscription service for legal advice", "The official, secure online platform of the Luxembourg government – your single point of contact with the public administration", "A private online banking application", "A social network for residents of Luxembourg"], "correct": 1, "explanation": "MyGuichet.lu is the official, secure online platform of the Luxembourg State. It works like an online counter (“guichet”) where you can carry out administrative procedures from home instead of going to an office."}, {"text": "What does the French word “guichet” mean?", "options": ["Counter – the desk with a small window where you ask for something in an office", "Citizen", "Computer", "Government"], "correct": 0, "explanation": "“Guichet” means “counter”. So MyGuichet is, in effect, “my counter” with the State – but online and open 24/7."}, {"text": "What do you need in order to register on MyGuichet.lu?", "options": ["To be at least 16 years old and have your 13-digit national identification number (the “matricule”)", "To be a Luxembourg citizen and pay a registration fee", "A Luxembourg passport and a residence permit", "Only an email address"], "correct": 0, "explanation": "To register you must be at least 16, have your 13-digit matricule (on your social security card), an email address, a device, and a secure way to prove your identity online."}, {"text": "Which secure logins can you use for MyGuichet.lu?", "options": ["Just a username and password you choose yourself", "A simple Google or Facebook account", "Only a LuxTrust product", "A LuxTrust product, the Luxembourg eID card, or an eIDAS login from your own European country"], "correct": 3, "explanation": "You need one secure login, but you have a choice: a LuxTrust product (such as LuxTrust Mobile), the Luxembourg electronic ID card, or an eIDAS login from another European country."}, {"text": "What can you do in your personal eSpace on MyGuichet.lu?", "options": ["Nothing – you still have to visit an office for everything", "Trade shares and cryptocurrencies", "Follow the status of your requests, view your official data, receive documents and book appointments", "Only file your annual tax return"], "correct": 2, "explanation": "In your eSpace you can follow your files, see the official data the State holds about you, receive official documents electronically, store documents, and book appointments with some administrations."}]}, {"id": 2, "key": "dsp_cns", "number": "Episode 2", "title": "Your Health, Online – The DSP and How the CNS Pays You Back", "description": "Two practical things that touch everybody: your online shared health file (Dossier de Soins Partagé) and how reimbursement works with the national health insurance, the CNS.", "audio": "podcast_dsp_cns.mp3", "duration": 592.27, "topics": ["Dossier de Soins Partagé (DSP)", "Agence eSanté", "Patient controls access", "Activating via MyGuichet", "CNS reimbursement", "Paying first, getting paid back", "Tiers payant (pharmacy)", "Tiers payant social"], "segments": [{"speaker": "Anna", "text": "Hello, and welcome!", "t": 0.0}, {"speaker": "Anna", "text": "It's really nice to have you with us today.", "t": 2.02}, {"speaker": "Tom", "text": "Hello everyone!", "t": 5.5}, {"speaker": "Anna", "text": "This episode is part of the Biergerpakt.", "t": 7.82}, {"speaker": "Anna", "text": "That's a programme of living together in Luxembourg.", "t": 10.46}, {"speaker": "Anna", "text": "The idea is simple...", "t": 13.82}, {"speaker": "Anna", "text": "we want to help residents, and also cross-border workers, to discover Luxembourg — or re-discover it — and to meet new people.", "t": 15.22}, {"speaker": "Tom", "text": "Exactly.", "t": 23.28}, {"speaker": "Tom", "text": "And today we talk about two things that touch everybody — your health, and your money.", "t": 24.9}, {"speaker": "Tom", "text": "First, your online health file, the Dossier de Soins Partagé.", "t": 29.2}, {"speaker": "Tom", "text": "And second, how you get your money back from the health insurance, the CNS.", "t": 34.86}, {"speaker": "Anna", "text": "Two very practical things.", "t": 40.46}, {"speaker": "Anna", "text": "Okay, Tom — let's start with the health file.", "t": 42.62}, {"speaker": "Anna", "text": "What is the Dossier de Soins Partagé?", "t": 45.86}, {"speaker": "Tom", "text": "So...", "t": 49.18}, {"speaker": "Tom", "text": "\"Dossier de Soins Partagé\" is French.", "t": 50.66}, {"speaker": "Tom", "text": "\"Dossier\" means file.", "t": 53.94}, {"speaker": "Tom", "text": "\"Soins\" means care.", "t": 56.7}, {"speaker": "Tom", "text": "\"Partagé\" means shared.", "t": 58.9}, {"speaker": "Tom", "text": "So — a \"shared care file\".", "t": 60.72}, {"speaker": "Tom", "text": "People also call it the DSP.", "t": 63.34}, {"speaker": "Anna", "text": "A shared care file.", "t": 66.68}, {"speaker": "Anna", "text": "So it's my medical file, but online?", "t": 68.38}, {"speaker": "Tom", "text": "Exactly.", "t": 71.78}, {"speaker": "Tom", "text": "The DSP is a free, personal, and secure electronic health file.", "t": 73.54}, {"speaker": "Tom", "text": "It brings together your important health information in one place — your treatments, your test results, your medical reports, your allergies, and so on.", "t": 78.62}, {"speaker": "Anna", "text": "And who creates it?", "t": 88.34}, {"speaker": "Tom", "text": "It's the official national system, run by the Agence eSanté — the public agency for digital health in Luxembourg.", "t": 90.62}, {"speaker": "Tom", "text": "The information is added by the health professionals who treat you — your doctor, the hospital, the laboratory.", "t": 97.72}, {"speaker": "Anna", "text": "So why is this useful?", "t": 104.88}, {"speaker": "Anna", "text": "My doctor already knows my history.", "t": 106.84}, {"speaker": "Tom", "text": "Your doctor does — but other people who treat you may not.", "t": 109.96}, {"speaker": "Tom", "text": "Imagine you go to the hospital at night, and your own doctor is not there.", "t": 113.56}, {"speaker": "Tom", "text": "With the DSP, the doctor on duty can see your essential information.", "t": 118.52}, {"speaker": "Tom", "text": "Your allergies, your current medication...", "t": 123.3}, {"speaker": "Tom", "text": "That can be very important, even life-saving.", "t": 126.42}, {"speaker": "Tom", "text": "And it avoids repeating the same exam twice, because the result is already there.", "t": 130.12}, {"speaker": "Anna", "text": "Ah, that's the key idea.", "t": 135.54}, {"speaker": "Anna", "text": "All the people caring for me can see the same file.", "t": 137.78}, {"speaker": "Tom", "text": "Exactly.", "t": 141.68}, {"speaker": "Tom", "text": "The whole point is better coordination — continuity and safety of care.", "t": 143.28}, {"speaker": "Tom", "text": "Everyone treating you works from the same, complete picture.", "t": 148.3}, {"speaker": "Anna", "text": "Now...", "t": 152.7}, {"speaker": "Anna", "text": "health data is very private.", "t": 153.38}, {"speaker": "Anna", "text": "Is it safe?", "t": 155.56}, {"speaker": "Tom", "text": "Very good question, and the answer is yes.", "t": 157.5}, {"speaker": "Tom", "text": "The data is encrypted, and it's kept in a kind of digital safe — they call it the \"coffre-fort\", the safe — located here in Luxembourg.", "t": 160.94}, {"speaker": "Tom", "text": "And the most important point — you are in control.", "t": 168.26}, {"speaker": "Anna", "text": "In control how?", "t": 173.54}, {"speaker": "Tom", "text": "It's you, the patient, who decides who can look at your DSP.", "t": 175.78}, {"speaker": "Tom", "text": "You give access, and you can take it away.", "t": 180.0}, {"speaker": "Tom", "text": "You can see who consulted your file.", "t": 183.52}, {"speaker": "Tom", "text": "You can even hide certain documents if you want.", "t": 186.6}, {"speaker": "Tom", "text": "So it's your file, and you hold the keys.", "t": 189.88}, {"speaker": "Anna", "text": "I like that.", "t": 193.72}, {"speaker": "Anna", "text": "It's mine, and I decide.", "t": 194.88}, {"speaker": "Anna", "text": "So how do I actually open a DSP?", "t": 197.16}, {"speaker": "Tom", "text": "Every person affiliated to the Luxembourg health insurance can have one.", "t": 200.5}, {"speaker": "Tom", "text": "To use it yourself online, you activate your \"eSanté account\".", "t": 204.98}, {"speaker": "Tom", "text": "And here's good news — it recently became much easier.", "t": 208.44}, {"speaker": "Tom", "text": "You can now activate it directly through MyGuichet.lu.", "t": 213.32}, {"speaker": "Anna", "text": "Ah — MyGuichet again!", "t": 217.92}, {"speaker": "Anna", "text": "We did a whole episode on that.", "t": 219.78}, {"speaker": "Tom", "text": "Yes!", "t": 222.6}, {"speaker": "Tom", "text": "So if you already use MyGuichet with your LuxTrust login, you can activate your eSanté account online, right away.", "t": 224.04}, {"speaker": "Tom", "text": "Before, you often had to wait for a code by post.", "t": 231.16}, {"speaker": "Tom", "text": "Now it's immediate.", "t": 235.08}, {"speaker": "Anna", "text": "That's a nice link between the services.", "t": 237.62}, {"speaker": "Anna", "text": "And once it's active, how do I look at it?", "t": 238.14}, {"speaker": "Tom", "text": "You log in to your DSP online, through the eSanté portal.", "t": 238.66}, {"speaker": "Tom", "text": "And there's also a mobile app — it's called MyDSP — so you can check your health file from your phone.", "t": 242.92}, {"speaker": "Anna", "text": "Very practical.", "t": 249.98}, {"speaker": "Anna", "text": "So, to sum up the first half — the DSP is my free, secure, online health file, run by the Agence eSanté, it helps all my carers work together, I control who sees it, and I activate it through MyGuichet.", "t": 251.72}, {"speaker": "Tom", "text": "Perfect summary.", "t": 264.62}, {"speaker": "Anna", "text": "Okay.", "t": 268.06}, {"speaker": "Anna", "text": "Now the second topic — money.", "t": 268.78}, {"speaker": "Anna", "text": "The CNS.", "t": 271.26}, {"speaker": "Anna", "text": "Tom, first...", "t": 272.64}, {"speaker": "Anna", "text": "what is the CNS?", "t": 274.02}, {"speaker": "Tom", "text": "CNS stands for Caisse Nationale de Santé — the National Health Fund.", "t": 276.26}, {"speaker": "Tom", "text": "It's the main public health insurance in Luxembourg.", "t": 280.94}, {"speaker": "Tom", "text": "If you work or live here and are affiliated, you're covered — cross-border workers too.", "t": 284.52}, {"speaker": "Tom", "text": "You get a social security card with your matricule, the thirteen-digit number, and you show it at the doctor or the pharmacy.", "t": 289.46}, {"speaker": "Anna", "text": "Good.", "t": 297.68}, {"speaker": "Anna", "text": "Now, the part that confuses a lot of newcomers.", "t": 298.66}, {"speaker": "Anna", "text": "When I go to the doctor here...", "t": 302.2}, {"speaker": "Anna", "text": "do I pay, or not?", "t": 303.94}, {"speaker": "Tom", "text": "Right, this is the important part.", "t": 306.46}, {"speaker": "Tom", "text": "The Luxembourg system traditionally works by reimbursement.", "t": 309.42}, {"speaker": "Tom", "text": "That means — for a normal visit to the doctor, you pay first, and then the CNS pays you back most of it.", "t": 313.54}, {"speaker": "Anna", "text": "So I pay the full price at the doctor, and then get money back later.", "t": 320.28}, {"speaker": "Tom", "text": "Exactly.", "t": 325.52}, {"speaker": "Tom", "text": "The CNS reimburses a large part of the cost — for most care it's around eighty to one hundred percent.", "t": 327.1}, {"speaker": "Tom", "text": "So you carry a small part yourself, and the rest comes back to you.", "t": 333.6}, {"speaker": "Anna", "text": "And how do I get that money back?", "t": 338.58}, {"speaker": "Anna", "text": "What do I do with the bill?", "t": 340.94}, {"speaker": "Tom", "text": "Simple.", "t": 343.38}, {"speaker": "Tom", "text": "The doctor gives you an invoice — a paper bill — and you pay it.", "t": 344.84}, {"speaker": "Tom", "text": "Then you send that original, paid invoice to the CNS.", "t": 348.52}, {"speaker": "Tom", "text": "You can send it by post, or drop it in one of their boxes.", "t": 353.3}, {"speaker": "Tom", "text": "The CNS then pays the reimbursement straight into your bank account.", "t": 357.72}, {"speaker": "Anna", "text": "Into my bank account directly.", "t": 362.98}, {"speaker": "Anna", "text": "How long does it take?", "t": 365.26}, {"speaker": "Tom", "text": "Usually about three weeks.", "t": 367.64}, {"speaker": "Tom", "text": "And you get a written statement explaining what was reimbursed.", "t": 370.08}, {"speaker": "Tom", "text": "So — tip for our listeners — give the CNS your bank account number, your IBAN, so they can pay you directly.", "t": 374.08}, {"speaker": "Tom", "text": "And keep your invoices.", "t": 381.12}, {"speaker": "Anna", "text": "Good tips.", "t": 383.96}, {"speaker": "Anna", "text": "But wait — paying the full amount first...", "t": 385.16}, {"speaker": "Anna", "text": "for a big bill, that could be hard for some people.", "t": 387.38}, {"speaker": "Tom", "text": "True.", "t": 391.32}, {"speaker": "Tom", "text": "And that's why the system has exceptions, where you do NOT pay everything first.", "t": 392.58}, {"speaker": "Tom", "text": "The most common one — medicines.", "t": 397.56}, {"speaker": "Anna", "text": "At the pharmacy?", "t": 400.78}, {"speaker": "Tom", "text": "Yes.", "t": 402.72}, {"speaker": "Tom", "text": "At the pharmacy, you usually don't pay the full price.", "t": 404.22}, {"speaker": "Tom", "text": "You show your social security card and your prescription, and you only pay your own small share.", "t": 407.88}, {"speaker": "Tom", "text": "The pharmacy settles the rest directly with the CNS.", "t": 412.86}, {"speaker": "Tom", "text": "That's called third-party payment — in French, \"tiers payant\".", "t": 417.2}, {"speaker": "Anna", "text": "So for medicine, I only pay my little part.", "t": 422.5}, {"speaker": "Anna", "text": "The CNS handles the rest behind the scenes.", "t": 425.74}, {"speaker": "Tom", "text": "Exactly.", "t": 429.78}, {"speaker": "Tom", "text": "And it's the same idea for a normal hospital stay.", "t": 431.22}, {"speaker": "Tom", "text": "The hospital bills the CNS directly for the care.", "t": 434.8}, {"speaker": "Tom", "text": "You mainly pay a small daily contribution, and your personal extras.", "t": 438.16}, {"speaker": "Anna", "text": "That makes it much easier.", "t": 443.98}, {"speaker": "Anna", "text": "So...", "t": 445.8}, {"speaker": "Anna", "text": "medicines and hospital — I pay only my share.", "t": 446.48}, {"speaker": "Anna", "text": "The normal doctor visit — I pay first and get reimbursed.", "t": 448.05}, {"speaker": "Tom", "text": "That's a good way to remember it.", "t": 449.62}, {"speaker": "Tom", "text": "And there's one more thing that's really important for people with low income.", "t": 452.02}, {"speaker": "Anna", "text": "Tell me.", "t": 457.16}, {"speaker": "Tom", "text": "It's called the social third-party payment — \"tiers payant social\".", "t": 458.5}, {"speaker": "Tom", "text": "If someone is in a difficult financial situation, this system means they don't have to pay the medical costs up front at all.", "t": 462.86}, {"speaker": "Tom", "text": "The CNS covers the eligible care directly, so money is not a barrier to seeing a doctor.", "t": 470.06}, {"speaker": "Anna", "text": "That's really important.", "t": 476.42}, {"speaker": "Anna", "text": "So nobody should avoid the doctor just because they can't pay first.", "t": 478.28}, {"speaker": "Tom", "text": "Exactly.", "t": 483.02}, {"speaker": "Tom", "text": "If that's your situation, you can ask about the tiers payant social — often through your doctor or the social office.", "t": 484.5}, {"speaker": "Anna", "text": "Wonderful.", "t": 492.24}, {"speaker": "Anna", "text": "Okay, Tom — let's bring it together.", "t": 493.22}, {"speaker": "Anna", "text": "A short summary of everything?", "t": 495.64}, {"speaker": "Tom", "text": "Sure.", "t": 498.82}, {"speaker": "Tom", "text": "Part one — the DSP is your free, secure, online health file.", "t": 500.12}, {"speaker": "Tom", "text": "It helps everyone who treats you work from the same information, you control who can see it, and you activate it easily through MyGuichet.lu — or check it on the MyDSP app.", "t": 505.46}, {"speaker": "Anna", "text": "And part two?", "t": 516.4}, {"speaker": "Tom", "text": "Part two — the CNS, the national health insurance.", "t": 518.44}, {"speaker": "Tom", "text": "For a normal doctor visit, you pay first and the CNS reimburses most of it into your bank account, in about three weeks.", "t": 522.22}, {"speaker": "Tom", "text": "For medicines and hospital, you usually pay only your small share.", "t": 530.3}, {"speaker": "Tom", "text": "And if money is tight, the social third-party payment means you don't pay up front.", "t": 534.74}, {"speaker": "Anna", "text": "So the message is — get your health file active, keep your invoices, give the CNS your bank details, and don't be afraid to ask for help if you need it.", "t": 540.0}, {"speaker": "Tom", "text": "Exactly.", "t": 549.76}, {"speaker": "Tom", "text": "A little bit of admin now...", "t": 551.34}, {"speaker": "Tom", "text": "saves you a lot of worry later.", "t": 552.84}, {"speaker": "Anna", "text": "And where can people learn more?", "t": 555.84}, {"speaker": "Tom", "text": "For the health file, the website is esante.lu.", "t": 558.52}, {"speaker": "Tom", "text": "For the insurance and reimbursements, it's cns.lu.", "t": 562.68}, {"speaker": "Tom", "text": "And the procedures are explained on Guichet.lu, in English too.", "t": 566.04}, {"speaker": "Anna", "text": "That was our episode about your online health file and the CNS, part of the Biergerpakt — living together in Luxembourg, discovering the country, and meeting new people.", "t": 572.44}, {"speaker": "Anna", "text": "Thank you so much for listening.", "t": 582.2}, {"speaker": "Tom", "text": "Thank you, everyone.", "t": 584.92}, {"speaker": "Tom", "text": "Take care...", "t": 587.08}, {"speaker": "Tom", "text": "and see you next time!", "t": 588.02}, {"speaker": "Anna", "text": "Bye bye!", "t": 590.74}], "questions": [{"text": "What is the DSP (Dossier de Soins Partagé)?", "options": ["A private insurance contract", "A paper booklet you carry to every appointment", "A tax file held by the administration", "A free, personal and secure electronic health file that brings your health information together in one place"], "correct": 3, "explanation": "The DSP is a free, personal and secure online health file run by the Agence eSanté. It gathers your treatments, results, reports and allergies so everyone treating you works from the same picture."}, {"text": "Who decides who can look at your DSP?", "options": ["You, the patient – you give and remove access and can see who consulted your file", "Only your general practitioner", "Your employer", "The Ministry of Health"], "correct": 0, "explanation": "You are in control: you decide who can access your DSP, you can withdraw access, see who consulted it, and even hide certain documents. It’s your file and you hold the keys."}, {"text": "For a normal visit to the doctor, how does payment usually work with the CNS?", "options": ["The CNS pays you in cash at the reception desk", "The visit is always completely free", "You never pay anything at any point", "You pay the full price first, then the CNS reimburses most of it (around 80–100%) into your bank account"], "correct": 3, "explanation": "Luxembourg traditionally works by reimbursement: you pay the doctor first, send the paid invoice to the CNS, and they pay most of it back into your bank account, usually within about three weeks."}, {"text": "What is “tiers payant” (third-party payment), for example at the pharmacy?", "options": ["You pay only your small share, and the pharmacy settles the rest directly with the CNS", "The State pays nothing and you pay everything", "You always pay the full price and claim it later", "You pay double and get refunded"], "correct": 0, "explanation": "With third-party payment (“tiers payant”), used at the pharmacy and for hospital stays, you only pay your small share and the provider bills the CNS directly for the rest."}, {"text": "How can you now activate your eSanté account to use your DSP online?", "options": ["Directly through MyGuichet.lu, immediately, with your LuxTrust login", "You cannot activate it yourself", "Only in person at a hospital", "Only by waiting for a code sent by post"], "correct": 0, "explanation": "It recently became much easier: you can activate your eSanté account directly through MyGuichet.lu with your LuxTrust login, right away, instead of waiting for a code by post."}]}, {"id": 3, "key": "eltereforum", "number": "Episode 3", "title": "Eltereforum – Strong Parents, Strong Children", "description": "A welcoming network of parent forums in Luxembourg: what the Eltereforum offers, who runs it, where to find one, and the Elteremobil that comes to you.", "audio": "podcast_eltereforum.mp3", "duration": 596.54, "topics": ["Meaning of “Eltereforum”", "For all parents", "Ministry of Education", "“Strong parents, strong children”", "Meetings, courses & talks", "Mostly free", "Regional forums", "The Elteremobil"], "segments": [{"speaker": "Anna", "text": "Hello, and welcome!", "t": 0.0}, {"speaker": "Anna", "text": "It's really nice to have you with us today.", "t": 2.02}, {"speaker": "Tom", "text": "Hello everyone!", "t": 5.52}, {"speaker": "Anna", "text": "This episode is part of the Biergerpakt.", "t": 7.8}, {"speaker": "Anna", "text": "That's a programme of living together in Luxembourg.", "t": 10.46}, {"speaker": "Anna", "text": "The idea is simple...", "t": 13.82}, {"speaker": "Anna", "text": "we want to help residents, and also cross-border workers, to discover Luxembourg — or re-discover it — and to meet new people.", "t": 15.22}, {"speaker": "Tom", "text": "Exactly.", "t": 23.44}, {"speaker": "Tom", "text": "And today's topic is for anyone who has children, or who is about to have children.", "t": 24.98}, {"speaker": "Tom", "text": "It's a service called the Eltereforum.", "t": 29.34}, {"speaker": "Anna", "text": "Eltereforum.", "t": 32.07}, {"speaker": "Anna", "text": "Okay, Tom — that's a Luxembourgish word.", "t": 34.8}, {"speaker": "Anna", "text": "Let's start there.", "t": 38.12}, {"speaker": "Anna", "text": "What does it mean?", "t": 39.58}, {"speaker": "Tom", "text": "So...", "t": 41.38}, {"speaker": "Tom", "text": "\"Elteren\" means \"parents\", and \"Forum\" means a place to meet and talk.", "t": 43.22}, {"speaker": "Tom", "text": "So Eltereforum is, literally, a \"parents' forum\".", "t": 47.64}, {"speaker": "Tom", "text": "In English you could say a \"parent forum\".", "t": 51.86}, {"speaker": "Anna", "text": "A parents' forum.", "t": 54.82}, {"speaker": "Anna", "text": "So it's a place for parents.", "t": 57.08}, {"speaker": "Tom", "text": "Exactly.", "t": 59.76}, {"speaker": "Tom", "text": "The official description is very warm.", "t": 61.22}, {"speaker": "Tom", "text": "The parent forums are welcoming places for discussion, information and support — for all parents.", "t": 64.2}, {"speaker": "Anna", "text": "For all parents.", "t": 71.24}, {"speaker": "Anna", "text": "So not only for parents with problems?", "t": 72.84}, {"speaker": "Tom", "text": "No, no — and this is important.", "t": 76.16}, {"speaker": "Tom", "text": "It's for everyone.", "t": 79.36}, {"speaker": "Tom", "text": "The Eltereforum is generalist.", "t": 81.14}, {"speaker": "Tom", "text": "It's a normal, friendly place where any parent can come, ask questions, learn something, and meet other parents.", "t": 83.08}, {"speaker": "Tom", "text": "You don't need a special reason.", "t": 91.26}, {"speaker": "Tom", "text": "You don't need to have a problem.", "t": 93.74}, {"speaker": "Anna", "text": "Good.", "t": 96.42}, {"speaker": "Anna", "text": "Because sometimes people think, \"I'll ask for help only if something is wrong.\"", "t": 97.42}, {"speaker": "Tom", "text": "Right.", "t": 102.44}, {"speaker": "Tom", "text": "But raising a child is a big job for everybody.", "t": 103.92}, {"speaker": "Tom", "text": "So the idea is to support parents from the very beginning, and along the whole way.", "t": 107.28}, {"speaker": "Anna", "text": "From the very beginning — what does that mean exactly?", "t": 112.54}, {"speaker": "Tom", "text": "It means from the moment you start your \"parental project\" — so, even before the baby is born, when you are planning or expecting — all the way through every stage of the child's life, until they become an adult.", "t": 116.76}, {"speaker": "Anna", "text": "Wow.", "t": 128.84}, {"speaker": "Anna", "text": "So from pregnancy until the child is eighteen.", "t": 129.82}, {"speaker": "Tom", "text": "Yes.", "t": 133.58}, {"speaker": "Tom", "text": "The whole journey.", "t": 135.0}, {"speaker": "Tom", "text": "Every age has its questions.", "t": 136.82}, {"speaker": "Tom", "text": "A baby who doesn't sleep.", "t": 138.5}, {"speaker": "Tom", "text": "A small child and screens.", "t": 141.84}, {"speaker": "Tom", "text": "School.", "t": 144.52}, {"speaker": "Tom", "text": "Teenagers.", "t": 145.88}, {"speaker": "Tom", "text": "The Eltereforum is there for all of it.", "t": 147.56}, {"speaker": "Anna", "text": "That's reassuring.", "t": 150.94}, {"speaker": "Anna", "text": "Now tell me — who is behind this?", "t": 152.62}, {"speaker": "Anna", "text": "Is it official?", "t": 155.04}, {"speaker": "Tom", "text": "It is fully official.", "t": 157.04}, {"speaker": "Tom", "text": "The Eltereforum is coordinated by the Ministry of Education, Children and Youth.", "t": 159.1}, {"speaker": "Tom", "text": "So it's a public service of the Luxembourg State.", "t": 164.48}, {"speaker": "Tom", "text": "And there's a nice slogan behind it — \"Strong parents, strong children\".", "t": 167.14}, {"speaker": "Tom", "text": "The idea being: when parents feel supported and confident, the children do better too.", "t": 172.94}, {"speaker": "Anna", "text": "Strong parents, strong children.", "t": 179.28}, {"speaker": "Anna", "text": "I like that.", "t": 181.9}, {"speaker": "Anna", "text": "Okay, so practically — what actually happens at an Eltereforum?", "t": 183.14}, {"speaker": "Anna", "text": "What can I do there?", "t": 187.66}, {"speaker": "Tom", "text": "Lots of things.", "t": 190.0}, {"speaker": "Tom", "text": "Let me list the main ones.", "t": 191.74}, {"speaker": "Tom", "text": "There are parent meetings — so, moments to get together and exchange with other parents.", "t": 194.0}, {"speaker": "Tom", "text": "There are parenting classes — like little courses on raising children.", "t": 199.66}, {"speaker": "Tom", "text": "There are activities for parents together with their children.", "t": 204.14}, {"speaker": "Tom", "text": "And there are themed evenings, talks and lectures — for example, an evening about sleep, or about screens, or about reading.", "t": 207.08}, {"speaker": "Anna", "text": "So courses, evenings, meetings, and parent-child activities.", "t": 216.92}, {"speaker": "Tom", "text": "Exactly.", "t": 222.1}, {"speaker": "Tom", "text": "And they also run information campaigns.", "t": 223.7}, {"speaker": "Tom", "text": "The whole thing is built so that you get good-quality information, and at the same time a place to meet other parents and professionals.", "t": 226.92}, {"speaker": "Anna", "text": "That second part is lovely — meeting other parents.", "t": 234.24}, {"speaker": "Anna", "text": "Because parenting can feel lonely sometimes.", "t": 238.14}, {"speaker": "Tom", "text": "It really can.", "t": 241.98}, {"speaker": "Tom", "text": "And here you realise — okay, other parents have the same questions as me.", "t": 243.6}, {"speaker": "Tom", "text": "I'm not alone.", "t": 248.76}, {"speaker": "Tom", "text": "That alone helps a lot.", "t": 250.46}, {"speaker": "Anna", "text": "Now, the question many will have — does it cost money?", "t": 253.1}, {"speaker": "Tom", "text": "Good question.", "t": 257.36}, {"speaker": "Tom", "text": "The support is, in very large part, free.", "t": 259.02}, {"speaker": "Tom", "text": "Most of what the Eltereforum offers is free of charge, and it's adapted to your situation in life.", "t": 262.78}, {"speaker": "Anna", "text": "Mostly free.", "t": 269.86}, {"speaker": "Anna", "text": "That's great.", "t": 270.92}, {"speaker": "Anna", "text": "And the professionals you mentioned — what if I have a serious, specific problem?", "t": 272.18}, {"speaker": "Anna", "text": "Can they handle everything?", "t": 276.96}, {"speaker": "Tom", "text": "That's an important point.", "t": 279.46}, {"speaker": "Tom", "text": "The Eltereforum is generalist — it does not give specialised treatment.", "t": 281.68}, {"speaker": "Tom", "text": "It's not a clinic or a therapy centre.", "t": 286.4}, {"speaker": "Tom", "text": "But if you need something more specific, the team listens to you and guides you.", "t": 289.14}, {"speaker": "Tom", "text": "They point you to the right specialised service.", "t": 293.84}, {"speaker": "Tom", "text": "So it's also a door — a first place to go, that sends you in the right direction.", "t": 297.04}, {"speaker": "Anna", "text": "So even if they can't solve everything, they help me find who can.", "t": 302.76}, {"speaker": "Tom", "text": "Exactly.", "t": 307.7}, {"speaker": "Tom", "text": "A friendly first step.", "t": 309.2}, {"speaker": "Anna", "text": "Okay, Tom — where are these forums?", "t": 311.88}, {"speaker": "Anna", "text": "Are they all in the capital?", "t": 314.86}, {"speaker": "Tom", "text": "No, and that's the nice part.", "t": 317.28}, {"speaker": "Tom", "text": "They are regional.", "t": 320.22}, {"speaker": "Tom", "text": "They're being opened all across the country, step by step.", "t": 321.94}, {"speaker": "Tom", "text": "The first one opened in Niederanven, in February 2023.", "t": 325.84}, {"speaker": "Tom", "text": "Then came Bettembourg, Marnach, Bertrange, Esch-Belval, Ettelbruck, Hesperange, Lorentzweiler, Wiltz...", "t": 330.66}, {"speaker": "Tom", "text": "and the tenth one opened in Differdange, in June 2026.", "t": 337.72}, {"speaker": "Anna", "text": "Ten forums already, across the regions.", "t": 343.08}, {"speaker": "Anna", "text": "So there's probably one not too far from home.", "t": 346.4}, {"speaker": "Tom", "text": "That's the goal — that every region has one nearby.", "t": 349.98}, {"speaker": "Tom", "text": "Each regional forum works together with the local players — the municipalities, the schools, the day-care centres, the local associations.", "t": 353.76}, {"speaker": "Tom", "text": "So it's really rooted in the community.", "t": 362.6}, {"speaker": "Anna", "text": "And for parents who can't easily travel to a forum?", "t": 365.76}, {"speaker": "Tom", "text": "Ah — for that, there's something really charming.", "t": 370.24}, {"speaker": "Tom", "text": "It's called the Elteremobil.", "t": 373.4}, {"speaker": "Anna", "text": "The Elteremobil?", "t": 376.18}, {"speaker": "Anna", "text": "Let me guess...", "t": 377.94}, {"speaker": "Anna", "text": "\"Eltere\" for parents, and \"mobil\"...", "t": 379.72}, {"speaker": "Tom", "text": "Exactly.", "t": 382.6}, {"speaker": "Tom", "text": "It's a little mini-bus that travels around the country to go and meet parents, directly, where they are.", "t": 384.08}, {"speaker": "Tom", "text": "So the Eltereforum doesn't only wait for you to come — sometimes it comes to you.", "t": 390.32}, {"speaker": "Anna", "text": "That's wonderful.", "t": 396.06}, {"speaker": "Anna", "text": "A parents' forum on wheels.", "t": 397.32}, {"speaker": "Tom", "text": "A parents' forum on wheels.", "t": 400.04}, {"speaker": "Tom", "text": "I love that.", "t": 402.58}, {"speaker": "Anna", "text": "Okay.", "t": 404.17}, {"speaker": "Anna", "text": "And there's also a website, right?", "t": 405.76}, {"speaker": "Tom", "text": "Yes.", "t": 408.9}, {"speaker": "Tom", "text": "The website is eltereforum dot l-u.", "t": 410.44}, {"speaker": "Tom", "text": "That's e-l-t-e-r-e-f-o-r-u-m dot l-u.", "t": 413.8}, {"speaker": "Tom", "text": "It's an information platform in itself.", "t": 417.45}, {"speaker": "Tom", "text": "Roughly every two months, it gives parents information on educational topics.", "t": 420.8}, {"speaker": "Anna", "text": "What kind of topics?", "t": 426.6}, {"speaker": "Tom", "text": "Everyday ones, very concrete.", "t": 429.24}, {"speaker": "Tom", "text": "For example — children and media, so screens and phones.", "t": 431.72}, {"speaker": "Tom", "text": "Reading.", "t": 434.79}, {"speaker": "Tom", "text": "Play and movement.", "t": 437.86}, {"speaker": "Tom", "text": "How to organise your child's free time and leisure.", "t": 439.84}, {"speaker": "Tom", "text": "The practical questions every parent has.", "t": 443.16}, {"speaker": "Anna", "text": "So even from home, on the website, I already get something useful.", "t": 447.12}, {"speaker": "Tom", "text": "Yes.", "t": 452.2}, {"speaker": "Tom", "text": "And on the website you also find the agenda — the calendar of all the activities, evenings and courses at the different forums.", "t": 452.73}, {"speaker": "Tom", "text": "So you can see what's happening near you, and when.", "t": 453.27}, {"speaker": "Anna", "text": "Perfect.", "t": 453.8}, {"speaker": "Anna", "text": "So let's make it really practical.", "t": 454.96}, {"speaker": "Anna", "text": "If I'm a parent listening right now, and I want to get started — what do I do?", "t": 457.32}, {"speaker": "Tom", "text": "Very simple.", "t": 462.78}, {"speaker": "Tom", "text": "First, go to the website, eltereforum.lu.", "t": 464.5}, {"speaker": "Tom", "text": "Look at the agenda, and find the forum closest to you.", "t": 468.68}, {"speaker": "Tom", "text": "Then just look at what's on offer — a talk, a course, a parent-child activity — and come along.", "t": 472.62}, {"speaker": "Tom", "text": "You don't need a big reason.", "t": 479.0}, {"speaker": "Tom", "text": "You're a parent, and that's enough.", "t": 481.26}, {"speaker": "Anna", "text": "And it doesn't matter what age my child is?", "t": 484.54}, {"speaker": "Tom", "text": "Doesn't matter at all.", "t": 488.08}, {"speaker": "Tom", "text": "Expecting a baby, a toddler, a school child, a teenager — there's something for every stage.", "t": 490.32}, {"speaker": "Tom", "text": "And remember, it's for all parents, mostly free, and there's no problem too small to bring.", "t": 496.64}, {"speaker": "Anna", "text": "That's the message I'd love people to take away.", "t": 503.54}, {"speaker": "Anna", "text": "You don't have to wait for things to go wrong.", "t": 506.5}, {"speaker": "Anna", "text": "You can just go, to learn, and to meet other parents.", "t": 509.14}, {"speaker": "Tom", "text": "Exactly.", "t": 513.64}, {"speaker": "Tom", "text": "Think of it as a friendly place that's on your side.", "t": 515.14}, {"speaker": "Tom", "text": "Strong parents, strong children.", "t": 518.6}, {"speaker": "Anna", "text": "Okay, Tom — short summary to finish?", "t": 522.06}, {"speaker": "Tom", "text": "Sure.", "t": 525.84}, {"speaker": "Tom", "text": "The Eltereforum is a network of parent forums in Luxembourg, coordinated by the Ministry of Education, Children and Youth.", "t": 527.22}, {"speaker": "Tom", "text": "They're welcoming places for information, exchange and support — for all parents, from the very start of parenthood until the child is grown.", "t": 535.3}, {"speaker": "Tom", "text": "They offer meetings, courses, talks and parent-child activities, mostly for free.", "t": 543.42}, {"speaker": "Anna", "text": "And how to find it?", "t": 550.28}, {"speaker": "Tom", "text": "Go to eltereforum.lu, check the agenda, and find your nearest forum — there are now ten across the country.", "t": 552.38}, {"speaker": "Tom", "text": "And if you can't come to them, the Elteremobil may come to you.", "t": 559.98}, {"speaker": "Anna", "text": "Beautiful.", "t": 564.54}, {"speaker": "Anna", "text": "So...", "t": 565.88}, {"speaker": "Anna", "text": "if you're a parent, you are not alone.", "t": 566.34}, {"speaker": "Anna", "text": "There's a whole network here to support you.", "t": 568.98}, {"speaker": "Tom", "text": "Really.", "t": 572.22}, {"speaker": "Tom", "text": "Just go once.", "t": 573.62}, {"speaker": "Tom", "text": "You'll feel it.", "t": 575.5}, {"speaker": "Anna", "text": "That was our episode about the Eltereforum, part of the Biergerpakt — living together in Luxembourg, discovering the country, and meeting new people.", "t": 577.7}, {"speaker": "Anna", "text": "Thank you so much for listening.", "t": 586.46}, {"speaker": "Tom", "text": "Thank you, everyone.", "t": 588.12}, {"speaker": "Tom", "text": "Take care...", "t": 591.44}, {"speaker": "Tom", "text": "and see you next time!", "t": 592.1}, {"speaker": "Anna", "text": "Bye bye!", "t": 595.02}], "questions": [{"text": "What is the Eltereforum?", "options": ["An online shop for baby products", "A school for children", "A “parents’ forum” – a welcoming place for discussion, information and support for all parents", "A political party for parents"], "correct": 2, "explanation": "“Elteren” means parents and “Forum” a place to meet, so Eltereforum is a parents’ forum: a friendly, generalist place where any parent can ask questions, learn and meet other parents – no special reason needed."}, {"text": "Who coordinates the Eltereforum?", "options": ["A single local parents’ association", "The Ministry of Education, Children and Youth – it is a public service of the Luxembourg State", "The national health insurance (CNS)", "A private company"], "correct": 1, "explanation": "The Eltereforum is coordinated by the Ministry of Education, Children and Youth, with the guiding idea “Strong parents, strong children” – supported, confident parents help their children do better."}, {"text": "From when does the Eltereforum support parents?", "options": ["Only during the teenage years", "Only once the child starts school", "Only from ages 0 to 3", "From the start of the “parental project” – even before birth – all the way until the child is grown"], "correct": 3, "explanation": "It supports parents along the whole journey: from when you are planning or expecting a baby, through every stage of childhood, until the child becomes an adult."}, {"text": "Does using the Eltereforum cost money?", "options": ["No – the support is, in very large part, free of charge", "It is free only for Luxembourg citizens", "Yes, there is a monthly subscription", "It is expensive per session"], "correct": 0, "explanation": "Most of what the Eltereforum offers – meetings, courses, talks and parent-child activities – is free of charge and adapted to your situation in life."}, {"text": "What is the “Elteremobil”?", "options": ["A mini-bus that travels around the country to meet parents directly, where they are", "A school bus for children", "A parenting smartphone app", "A baby stroller you can rent"], "correct": 0, "explanation": "The Elteremobil is a little mini-bus that travels around Luxembourg to meet parents where they are – so the Eltereforum doesn’t only wait for you to come, sometimes it comes to you."}]}, {"id": 4, "key": "benevolat", "number": "Episode 4", "title": "Volunteering in Luxembourg – Give the Time You Want", "description": "A flexible way to meet people and give something back: what volunteering is, why it matters, the Agence du Bénévolat and benevolat.lu, and how to start with no long-term commitment.", "audio": "podcast_benevolat.mp3", "duration": 601.46, "topics": ["Definition of a volunteer", "Why volunteering matters", "35% of the population", "Agence du Bénévolat", "benevolat.lu platform", "No long commitment needed", "Short, one-time missions", "Voluntary service (under 30s)"], "segments": [{"speaker": "Anna", "text": "Hello, and welcome!", "t": 0.0}, {"speaker": "Anna", "text": "It's really nice to have you with us today.", "t": 2.04}, {"speaker": "Tom", "text": "Hello everyone!", "t": 5.52}, {"speaker": "Anna", "text": "This episode is part of the Biergerpakt.", "t": 7.82}, {"speaker": "Anna", "text": "That's a programme of living together in Luxembourg.", "t": 10.46}, {"speaker": "Anna", "text": "The idea is simple...", "t": 13.82}, {"speaker": "Anna", "text": "we want to help residents, and also cross-border workers, to discover Luxembourg — or re-discover it — and to meet new people.", "t": 15.26}, {"speaker": "Tom", "text": "Exactly.", "t": 23.24}, {"speaker": "Tom", "text": "And today we talk about a beautiful way to do just that.", "t": 24.92}, {"speaker": "Tom", "text": "To meet people, and to give something back.", "t": 28.42}, {"speaker": "Tom", "text": "We're talking about volunteering.", "t": 32.02}, {"speaker": "Tom", "text": "In French, \"le bénévolat\".", "t": 34.58}, {"speaker": "Anna", "text": "Volunteering.", "t": 38.04}, {"speaker": "Anna", "text": "Okay, Tom...", "t": 39.62}, {"speaker": "Anna", "text": "let's start simply.", "t": 40.66}, {"speaker": "Anna", "text": "What is it, really?", "t": 42.08}, {"speaker": "Tom", "text": "So...", "t": 44.4}, {"speaker": "Tom", "text": "volunteering is giving the time you want — a little, a lot, or passionately — to support a cause and help others.", "t": 44.64}, {"speaker": "Tom", "text": "The official definition is: a volunteer is someone who, of their own free will, and without being paid, does something in the service of others, or of the community.", "t": 52.08}, {"speaker": "Anna", "text": "Of their own free will, and without being paid.", "t": 62.22}, {"speaker": "Anna", "text": "So it's a gift.", "t": 65.38}, {"speaker": "Anna", "text": "A gift of time.", "t": 66.86}, {"speaker": "Tom", "text": "Exactly.", "t": 68.92}, {"speaker": "Tom", "text": "And here's the key part — \"the time you want\".", "t": 70.34}, {"speaker": "Tom", "text": "You don't give your whole life.", "t": 73.62}, {"speaker": "Tom", "text": "You give what you can.", "t": 75.92}, {"speaker": "Tom", "text": "And it's also about having fun, meeting people who share your values, and doing something you enjoy.", "t": 77.9}, {"speaker": "Anna", "text": "I like that.", "t": 84.3}, {"speaker": "Anna", "text": "It's not only duty.", "t": 86.26}, {"speaker": "Anna", "text": "It's also pleasure.", "t": 87.78}, {"speaker": "Anna", "text": "So tell me, Tom — why is volunteering so important?", "t": 89.46}, {"speaker": "Tom", "text": "Well...", "t": 93.94}, {"speaker": "Tom", "text": "volunteering plays a key role in our society.", "t": 94.76}, {"speaker": "Tom", "text": "It holds people together.", "t": 98.0}, {"speaker": "Tom", "text": "It's built on values — solidarity, citizenship, respect.", "t": 100.22}, {"speaker": "Tom", "text": "When people give their time freely, the society becomes more connected.", "t": 105.14}, {"speaker": "Tom", "text": "More inclusive.", "t": 109.86}, {"speaker": "Tom", "text": "Nobody is left alone in the corner.", "t": 110.7}, {"speaker": "Anna", "text": "So it's like...", "t": 115.3}, {"speaker": "Anna", "text": "the glue between people.", "t": 115.98}, {"speaker": "Tom", "text": "That's a good way to say it.", "t": 118.64}, {"speaker": "Tom", "text": "The glue.", "t": 120.76}, {"speaker": "Tom", "text": "And here's a number that surprised me.", "t": 122.22}, {"speaker": "Tom", "text": "In Luxembourg, in 2022, thirty-five percent of the population did some volunteering.", "t": 124.92}, {"speaker": "Anna", "text": "Thirty-five percent?", "t": 129.31}, {"speaker": "Anna", "text": "More than one person in three?", "t": 133.7}, {"speaker": "Tom", "text": "More than one in three.", "t": 136.46}, {"speaker": "Tom", "text": "And that puts Luxembourg fourth in all of Europe.", "t": 137.96}, {"speaker": "Tom", "text": "There's even a Volunteering Day every year, on the fifth of December.", "t": 142.12}, {"speaker": "Anna", "text": "So it's really part of the culture here.", "t": 147.34}, {"speaker": "Tom", "text": "It really is.", "t": 150.34}, {"speaker": "Tom", "text": "And there's something nice — when you volunteer, you also gain for yourself.", "t": 152.14}, {"speaker": "Tom", "text": "You learn new skills, you get more confident, more independent.", "t": 157.12}, {"speaker": "Tom", "text": "You learn to work in a team.", "t": 161.54}, {"speaker": "Tom", "text": "So you give your time, but you also grow.", "t": 164.0}, {"speaker": "Anna", "text": "Beautiful.", "t": 167.5}, {"speaker": "Anna", "text": "Okay — so how is volunteering organised here in Luxembourg?", "t": 168.92}, {"speaker": "Tom", "text": "The central place to know is the Agence du Bénévolat.", "t": 173.72}, {"speaker": "Tom", "text": "The Volunteering Agency.", "t": 177.28}, {"speaker": "Tom", "text": "Since 2002, their job is to promote and develop volunteering in Luxembourg.", "t": 179.68}, {"speaker": "Tom", "text": "And the most useful thing for a listener is their website — benevolat dot l-u.", "t": 185.28}, {"speaker": "Anna", "text": "benevolat.lu.", "t": 188.76}, {"speaker": "Anna", "text": "And what do I find there?", "t": 192.24}, {"speaker": "Tom", "text": "It's a meeting point.", "t": 194.7}, {"speaker": "Tom", "text": "On one side, the associations looking for help.", "t": 196.78}, {"speaker": "Tom", "text": "On the other side, people like you and me who want to give some time.", "t": 200.58}, {"speaker": "Tom", "text": "The platform brings the two together.", "t": 204.64}, {"speaker": "Tom", "text": "They even added a smart matching system — it looks at your interests and skills, and suggests missions that fit you.", "t": 207.24}, {"speaker": "Anna", "text": "Oh — like when a website suggests things, but for good deeds.", "t": 214.92}, {"speaker": "Tom", "text": "Exactly.", "t": 219.58}, {"speaker": "Tom", "text": "Matching, but for kindness.", "t": 221.26}, {"speaker": "Anna", "text": "And is the choice big?", "t": 224.34}, {"speaker": "Tom", "text": "Very big.", "t": 226.68}, {"speaker": "Tom", "text": "Health.", "t": 229.14}, {"speaker": "Tom", "text": "Humanitarian help.", "t": 229.76}, {"speaker": "Tom", "text": "The environment.", "t": 231.78}, {"speaker": "Tom", "text": "Living together — solidarity and inclusion.", "t": 233.86}, {"speaker": "Tom", "text": "Culture.", "t": 236.68}, {"speaker": "Tom", "text": "Education.", "t": 238.7}, {"speaker": "Tom", "text": "Social and relational work.", "t": 240.54}, {"speaker": "Tom", "text": "Leisure.", "t": 242.6}, {"speaker": "Tom", "text": "Sports.", "t": 244.28}, {"speaker": "Tom", "text": "Animals.", "t": 244.57}, {"speaker": "Tom", "text": "Emergency relief.", "t": 244.87}, {"speaker": "Tom", "text": "For example, behind every sports club in Luxembourg, there are volunteers who keep it running.", "t": 245.16}, {"speaker": "Tom", "text": "And in some hospitals, volunteers are simply there, close to the patients.", "t": 245.46}, {"speaker": "Tom", "text": "To talk.", "t": 245.75}, {"speaker": "Tom", "text": "To keep company.", "t": 246.05}, {"speaker": "Anna", "text": "That's lovely.", "t": 246.34}, {"speaker": "Anna", "text": "Just being there for someone.", "t": 247.54}, {"speaker": "Tom", "text": "And it's everywhere in the country.", "t": 250.16}, {"speaker": "Tom", "text": "The platform covers all regions — from Luxembourg City, to Esch, to Diekirch, to Wiltz.", "t": 252.42}, {"speaker": "Tom", "text": "There's even a map, so you can find something close to home.", "t": 259.08}, {"speaker": "Anna", "text": "Okay Tom — this is the part I really want to underline.", "t": 264.12}, {"speaker": "Anna", "text": "Because some people hear \"volunteering\" and they get scared.", "t": 267.28}, {"speaker": "Anna", "text": "They think, \"I don't have time.", "t": 270.76}, {"speaker": "Anna", "text": "I can't commit for years.\"", "t": 273.06}, {"speaker": "Tom", "text": "Yes — and this is so important.", "t": 275.62}, {"speaker": "Tom", "text": "So let me be very clear.", "t": 278.56}, {"speaker": "Tom", "text": "You do NOT need to commit for a long time.", "t": 280.86}, {"speaker": "Anna", "text": "Say that again, louder, for the people in the back!", "t": 284.5}, {"speaker": "Tom", "text": "You do not need a long commitment!", "t": 288.48}, {"speaker": "Tom", "text": "Remember the definition — you give the time you want.", "t": 290.86}, {"speaker": "Tom", "text": "A little, a lot, or passionately.", "t": 294.64}, {"speaker": "Tom", "text": "It's your choice.", "t": 297.8}, {"speaker": "Anna", "text": "So there are short missions?", "t": 300.28}, {"speaker": "Anna", "text": "One-time things?", "t": 302.08}, {"speaker": "Tom", "text": "Yes — lots of them.", "t": 304.16}, {"speaker": "Tom", "text": "On benevolat.lu, many missions are just for a single event, or a single day.", "t": 306.32}, {"speaker": "Tom", "text": "Real examples on the site right now: helping at a gymnastics gala for one weekend.", "t": 312.08}, {"speaker": "Tom", "text": "Being a marshal for one day at a cycling race.", "t": 317.44}, {"speaker": "Tom", "text": "Manning the barbecue at a summer party.", "t": 321.46}, {"speaker": "Tom", "text": "Making Christmas decorations.", "t": 324.56}, {"speaker": "Tom", "text": "Transporting an animal from a drop-off point.", "t": 327.12}, {"speaker": "Anna", "text": "So small, concrete things.", "t": 330.68}, {"speaker": "Anna", "text": "A few hours.", "t": 333.28}, {"speaker": "Anna", "text": "A day.", "t": 334.58}, {"speaker": "Anna", "text": "A weekend.", "t": 335.6}, {"speaker": "Tom", "text": "Exactly.", "t": 337.24}, {"speaker": "Tom", "text": "You can help for one afternoon, and that's already wonderful.", "t": 338.92}, {"speaker": "Tom", "text": "You're not signing a contract for ten years.", "t": 342.7}, {"speaker": "Tom", "text": "You give one moment of your time, and it really helps.", "t": 346.28}, {"speaker": "Anna", "text": "That changes everything.", "t": 350.54}, {"speaker": "Anna", "text": "So anyone can do it — even with a busy life.", "t": 352.56}, {"speaker": "Tom", "text": "Anyone.", "t": 356.12}, {"speaker": "Tom", "text": "A student, a parent, someone working full-time, a retired person.", "t": 357.86}, {"speaker": "Tom", "text": "You just choose a mission that fits your free time.", "t": 363.14}, {"speaker": "Anna", "text": "Okay.", "t": 367.26}, {"speaker": "Anna", "text": "I'm convinced.", "t": 367.86}, {"speaker": "Anna", "text": "How do I actually start?", "t": 369.52}, {"speaker": "Anna", "text": "Step by step.", "t": 371.72}, {"speaker": "Tom", "text": "The Agence suggests a simple method.", "t": 373.6}, {"speaker": "Tom", "text": "Step one — first, think about what you like.", "t": 376.48}, {"speaker": "Tom", "text": "Make a little list.", "t": 380.12}, {"speaker": "Tom", "text": "What cause touches you?", "t": 381.94}, {"speaker": "Tom", "text": "Animals, helping children with school, the environment?", "t": 384.4}, {"speaker": "Tom", "text": "What type of activity — welcoming people, something manual or creative?", "t": 387.9}, {"speaker": "Tom", "text": "Which group would you like to help — children, older people, people with a disability?", "t": 393.28}, {"speaker": "Tom", "text": "And finally, where, and how much time you want to give.", "t": 398.68}, {"speaker": "Anna", "text": "Ah, smart.", "t": 403.24}, {"speaker": "Anna", "text": "So I first understand what suits me.", "t": 404.94}, {"speaker": "Tom", "text": "Exactly.", "t": 408.28}, {"speaker": "Tom", "text": "Because a happy volunteer is one who does something they enjoy.", "t": 409.72}, {"speaker": "Tom", "text": "Step two — you go to benevolat.lu and register on the portal.", "t": 412.98}, {"speaker": "Tom", "text": "It's free.", "t": 418.62}, {"speaker": "Tom", "text": "Then you look through the directory of missions and associations, you filter by region or field, and when you find one you like, you offer your help directly.", "t": 420.22}, {"speaker": "Tom", "text": "The association then contacts you.", "t": 429.12}, {"speaker": "Anna", "text": "So three movements.", "t": 432.56}, {"speaker": "Anna", "text": "Think about what I like.", "t": 434.42}, {"speaker": "Anna", "text": "Register on benevolat.lu.", "t": 436.84}, {"speaker": "Anna", "text": "Offer my help.", "t": 439.08}, {"speaker": "Tom", "text": "That's it.", "t": 441.48}, {"speaker": "Tom", "text": "And if you prefer to talk to a human, you can contact the Agence directly — they're on Avenue Guillaume in Luxembourg City, phone two-six, one-two, one-zero.", "t": 442.46}, {"speaker": "Anna", "text": "And if I'm young — is there something special?", "t": 453.14}, {"speaker": "Tom", "text": "Yes, and don't confuse the two.", "t": 456.52}, {"speaker": "Tom", "text": "For people under thirty, there's also \"voluntary service\" — in French, \"service volontaire\".", "t": 459.3}, {"speaker": "Tom", "text": "That's a bigger commitment — full-time, on one project, usually three to twelve months, in Luxembourg or abroad.", "t": 465.02}, {"speaker": "Tom", "text": "It's run by the National Youth Service, the website volontaires.lu.", "t": 472.94}, {"speaker": "Tom", "text": "So — normal volunteering is flexible and for everybody, at any age.", "t": 478.12}, {"speaker": "Tom", "text": "The voluntary service is the full-time programme for the under-thirties.", "t": 483.12}, {"speaker": "Anna", "text": "Useful difference.", "t": 487.54}, {"speaker": "Anna", "text": "One last thing — does volunteering count for anything officially?", "t": 489.74}, {"speaker": "Tom", "text": "It can.", "t": 494.24}, {"speaker": "Tom", "text": "The skills you gain can be officially recognised.", "t": 495.68}, {"speaker": "Tom", "text": "The association can give you a certificate of what you did.", "t": 499.14}, {"speaker": "Tom", "text": "And there's even a system called Validation of Acquired Experience, through the Ministry of Education.", "t": 502.8}, {"speaker": "Tom", "text": "So volunteering can help your career later, too.", "t": 508.94}, {"speaker": "Anna", "text": "So it's good for the heart...", "t": 513.12}, {"speaker": "Anna", "text": "and good for the CV.", "t": 514.46}, {"speaker": "Tom", "text": "Both.", "t": 515.86}, {"speaker": "Tom", "text": "And every year the Agence gives a prize — the Prix du Mérite du Bénévolat — to honour volunteers.", "t": 518.0}, {"speaker": "Anna", "text": "Lovely.", "t": 524.44}, {"speaker": "Anna", "text": "Okay Tom, short summary?", "t": 525.66}, {"speaker": "Tom", "text": "Volunteering is giving the time you want, freely, to help others.", "t": 529.14}, {"speaker": "Tom", "text": "It matters because it holds our society together — and in Luxembourg, more than one person in three does it.", "t": 533.12}, {"speaker": "Tom", "text": "The central place is the Agence du Bénévolat, and their website benevolat.lu, where associations and volunteers meet, in every region.", "t": 539.02}, {"speaker": "Anna", "text": "And the most important message of today?", "t": 548.9}, {"speaker": "Tom", "text": "You do not need a long commitment.", "t": 552.24}, {"speaker": "Tom", "text": "There are short missions — one afternoon, one day, one event.", "t": 554.82}, {"speaker": "Tom", "text": "To start: think about what you enjoy, register on benevolat.lu, and offer your help.", "t": 559.62}, {"speaker": "Anna", "text": "So...", "t": 566.52}, {"speaker": "Anna", "text": "don't be afraid to try.", "t": 567.02}, {"speaker": "Anna", "text": "Even a small action makes a difference — and it's a wonderful way to meet people and feel part of Luxembourg.", "t": 568.9}, {"speaker": "Tom", "text": "Really.", "t": 575.8}, {"speaker": "Tom", "text": "Start small.", "t": 577.1}, {"speaker": "Tom", "text": "One afternoon.", "t": 578.84}, {"speaker": "Tom", "text": "You'll see.", "t": 580.66}, {"speaker": "Anna", "text": "That was our episode about volunteering in Luxembourg, part of the Biergerpakt — living together, discovering the country, and meeting new people.", "t": 582.88}, {"speaker": "Anna", "text": "Thank you so much for listening.", "t": 591.38}, {"speaker": "Tom", "text": "Thank you, everyone.", "t": 593.97}, {"speaker": "Tom", "text": "Take care...", "t": 596.36}, {"speaker": "Tom", "text": "and see you next time!", "t": 597.02}, {"speaker": "Anna", "text": "Bye bye!", "t": 599.94}], "questions": [{"text": "How is a volunteer defined in the episode?", "options": ["A paid part-time worker for a charity", "Someone who, of their own free will and without being paid, does something in the service of others or of the community", "A government employee", "Someone required to help by a court order"], "correct": 1, "explanation": "A volunteer gives the time they want – a little, a lot, or passionately – of their own free will and without being paid, in the service of others or of the community."}, {"text": "In 2022, roughly what share of Luxembourg’s population did some volunteering?", "options": ["About 5%", "About 70%", "About 35% – more than one person in three, placing Luxembourg fourth in Europe", "About 10%"], "correct": 2, "explanation": "In 2022 about 35% of the population volunteered – more than one in three – which put Luxembourg fourth in all of Europe. There is even a Volunteering Day every 5 December."}, {"text": "What is the central organisation and website for volunteering in Luxembourg?", "options": ["The commune’s town hall only", "The ADEM, on adem.lu", "The Agence du Bénévolat, with its website benevolat.lu", "The Ministry of Finance"], "correct": 2, "explanation": "The Agence du Bénévolat promotes volunteering since 2002. Its website benevolat.lu is a meeting point where associations looking for help and people who want to give time find each other."}, {"text": "Do you need a long-term commitment to volunteer?", "options": ["Only full weekends for a whole year", "Yes, at least one year", "Yes, at least three months", "No – you give the time you want, and many missions are one-time or short (an afternoon, a day, an event)"], "correct": 3, "explanation": "You do not need a long commitment. Many missions on benevolat.lu are for a single event or a single day – helping at a gala, marshalling a race, manning a barbecue – so anyone with a busy life can take part."}, {"text": "What is “voluntary service” (service volontaire), and who is it for?", "options": ["A compulsory programme for all new residents", "A bigger, full-time commitment (usually 3–12 months) for people under 30, run by the National Youth Service", "A paid civil-service job for retirees", "Exactly the same as normal volunteering"], "correct": 1, "explanation": "Voluntary service is a larger, full-time commitment of about 3–12 months for people under 30 (via the National Youth Service, volontaires.lu) – different from ordinary volunteering, which is flexible and open to everyone at any age."}]}, {"id": 5, "key": "lualert", "number": "Episode 5", "audio": "podcast_lualert.mp3", "title": "LU-Alert – How Luxembourg Warns You in an Emergency", "description": "Luxembourg's national warning system: what LU-Alert is, how alerts reach your phone (Cell Broadcast, location-based SMS, the app), the alert levels and categories, the languages, and how to tell a real alert from a scam.", "duration": 506.43, "topics": ["What “LU-Alert” means", "Cell Broadcast & LB-SMS", "No sign-up needed", "The free mobile app", "Languages: DE / EN / FR", "Alert levels & colours", "The 12 alert categories", "Spotting phishing"], "segments": [{"speaker": "Anna", "text": "Hello, and welcome!", "t": 0.0}, {"speaker": "Anna", "text": "It's really nice to have you with us today.", "t": 1.48}, {"speaker": "Tom", "text": "Hello everyone!", "t": 4.14}, {"speaker": "Anna", "text": "This episode is part of the Biergerpakt.", "t": 5.19}, {"speaker": "Anna", "text": "That's a programme of living together in Luxembourg.", "t": 7.88}, {"speaker": "Anna", "text": "The idea is simple...", "t": 11.22}, {"speaker": "Anna", "text": "we want to help residents, and also cross-border workers, to discover Luxembourg — or re-discover it — and to meet new people.", "t": 12.75}, {"speaker": "Tom", "text": "Exactly.", "t": 20.34}, {"speaker": "Tom", "text": "And today we talk about something that protects everybody.", "t": 21.07}, {"speaker": "Tom", "text": "It's the system that warns the population when there is an emergency.", "t": 23.58}, {"speaker": "Tom", "text": "It's called LU-Alert.", "t": 26.71}, {"speaker": "Anna", "text": "LU-Alert.", "t": 28.09}, {"speaker": "Anna", "text": "Okay, Tom, let's start at the very beginning.", "t": 29.15}, {"speaker": "Anna", "text": "What does the name mean?", "t": 32.47}, {"speaker": "Tom", "text": "So, the name has two parts.", "t": 34.22}, {"speaker": "Tom", "text": "\"LU\" is the international two-letter code for Luxembourg.", "t": 35.92}, {"speaker": "Tom", "text": "And \"Alert\" is simply the English word for \"alerte\".", "t": 38.76}, {"speaker": "Tom", "text": "So, LU-Alert...", "t": 41.08}, {"speaker": "Tom", "text": "the alert for Luxembourg.", "t": 42.25}, {"speaker": "Anna", "text": "Simple and clear.", "t": 43.6}, {"speaker": "Anna", "text": "And what exactly is it?", "t": 44.96}, {"speaker": "Tom", "text": "LU-Alert is the national warning and information system for the population.", "t": 46.88}, {"speaker": "Tom", "text": "It was deployed in autumn 2024.", "t": 50.82}, {"speaker": "Tom", "text": "It's the modern replacement for the older warning system.", "t": 53.14}, {"speaker": "Anna", "text": "And what is it for, really?", "t": 55.62}, {"speaker": "Tom", "text": "The goal is to warn and inform people who could be affected by a dangerous event.", "t": 57.76}, {"speaker": "Tom", "text": "So you can prepare, and take the right precautions to protect yourself and your property.", "t": 61.68}, {"speaker": "Tom", "text": "And it's not only during the emergency.", "t": 65.49}, {"speaker": "Tom", "text": "It's also before — to build what they call resilience and prevention.", "t": 67.49}, {"speaker": "Anna", "text": "So it helps me act at the right moment.", "t": 70.78}, {"speaker": "Anna", "text": "Okay, the big question for most people...", "t": 73.34}, {"speaker": "Anna", "text": "how does the warning actually reach me?", "t": 76.0}, {"speaker": "Anna", "text": "On my phone?", "t": 78.38}, {"speaker": "Tom", "text": "Yes, mostly on your phone, and in several ways.", "t": 79.59}, {"speaker": "Tom", "text": "LU-Alert is what we call \"multi-channel\".", "t": 82.14}, {"speaker": "Tom", "text": "That means it uses many different channels at the same time, to reach as many people as possible.", "t": 84.19}, {"speaker": "Anna", "text": "Many channels.", "t": 88.7}, {"speaker": "Anna", "text": "Can you list them?", "t": 89.94}, {"speaker": "Tom", "text": "Of course.", "t": 91.43}, {"speaker": "Tom", "text": "First, two ways that arrive directly on your mobile phone.", "t": 92.15}, {"speaker": "Tom", "text": "One is Cell Broadcast.", "t": 95.04}, {"speaker": "Tom", "text": "The other is location-based SMS.", "t": 96.52}, {"speaker": "Anna", "text": "Let's take them one by one.", "t": 98.87}, {"speaker": "Anna", "text": "What is Cell Broadcast?", "t": 100.84}, {"speaker": "Tom", "text": "Cell Broadcast sends a message to every compatible phone inside a chosen area.", "t": 102.68}, {"speaker": "Tom", "text": "It uses a special, dedicated network.", "t": 107.0}, {"speaker": "Tom", "text": "So it still works well even when the normal network is very busy.", "t": 109.08}, {"speaker": "Anna", "text": "And location-based SMS?", "t": 112.5}, {"speaker": "Tom", "text": "That's a text message — an SMS — sent to the phones located in the targeted area.", "t": 114.66}, {"speaker": "Tom", "text": "It works in a similar way, but it travels over the normal mobile network.", "t": 119.0}, {"speaker": "Anna", "text": "Okay.", "t": 122.66}, {"speaker": "Anna", "text": "And here's the question everybody asks.", "t": 123.52}, {"speaker": "Anna", "text": "Do I need to sign up, or register, to get these?", "t": 126.2}, {"speaker": "Tom", "text": "No.", "t": 129.69}, {"speaker": "Tom", "text": "And this is really important.", "t": 130.14}, {"speaker": "Tom", "text": "For Cell Broadcast and for location-based SMS, you do not need to sign up.", "t": 131.58}, {"speaker": "Tom", "text": "You don't give your number to anybody.", "t": 135.5}, {"speaker": "Tom", "text": "If your phone is in the area when the authorities send a message, your phone is targeted automatically.", "t": 137.0}, {"speaker": "Anna", "text": "So I don't have to do anything, and I can't really opt out either.", "t": 141.86}, {"speaker": "Tom", "text": "Correct.", "t": 146.14}, {"speaker": "Tom", "text": "That's by design — so that everybody in danger gets warned.", "t": 146.63}, {"speaker": "Anna", "text": "Good.", "t": 149.78}, {"speaker": "Anna", "text": "You also mentioned other channels?", "t": 150.53}, {"speaker": "Tom", "text": "Yes.", "t": 152.78}, {"speaker": "Tom", "text": "There is the LU-Alert mobile application, that you download for free.", "t": 153.13}, {"speaker": "Tom", "text": "There are the official websites, like lu-alert dot l-u.", "t": 156.36}, {"speaker": "Tom", "text": "There is the press — radio, television, their websites and apps.", "t": 158.91}, {"speaker": "Tom", "text": "There is social media.", "t": 162.33}, {"speaker": "Tom", "text": "And finally, sirens.", "t": 163.45}, {"speaker": "Anna", "text": "Sirens?", "t": 164.96}, {"speaker": "Anna", "text": "Like the old air-raid sirens?", "t": 165.94}, {"speaker": "Tom", "text": "Yes, but today the sirens are used only in one specific case — a nuclear alert.", "t": 168.15}, {"speaker": "Tom", "text": "For everything else, it's the phone and the other channels.", "t": 172.53}, {"speaker": "Anna", "text": "Got it.", "t": 175.11}, {"speaker": "Anna", "text": "And the mobile app — what does it add, if I already get the SMS?", "t": 175.96}, {"speaker": "Tom", "text": "The app lets you follow all the alerts and information in one place, issued by the public authorities.", "t": 180.27}, {"speaker": "Tom", "text": "You download it for free, from the Apple App Store or the Google Play Store.", "t": 184.81}, {"speaker": "Tom", "text": "It's a good idea to install it.", "t": 188.47}, {"speaker": "Anna", "text": "Now, a practical worry.", "t": 190.26}, {"speaker": "Anna", "text": "Many of us don't speak Luxembourgish.", "t": 192.11}, {"speaker": "Anna", "text": "In what language do these messages arrive?", "t": 194.66}, {"speaker": "Tom", "text": "Good question.", "t": 197.51}, {"speaker": "Tom", "text": "The messages are sent in three languages — German, English and French.", "t": 198.27}, {"speaker": "Tom", "text": "In the app, you receive the language you chose in the settings.", "t": 201.71}, {"speaker": "Tom", "text": "By location-based SMS, you get all three languages in one message.", "t": 204.33}, {"speaker": "Tom", "text": "So, English speakers are covered.", "t": 207.97}, {"speaker": "Anna", "text": "That's reassuring.", "t": 209.79}, {"speaker": "Anna", "text": "Okay, so a message arrives.", "t": 211.16}, {"speaker": "Anna", "text": "What's inside it?", "t": 213.34}, {"speaker": "Tom", "text": "Normally, three things.", "t": 214.67}, {"speaker": "Tom", "text": "First, what has happened, or what is likely to happen.", "t": 216.05}, {"speaker": "Tom", "text": "Second, a recommendation — how you should behave, or what you should do.", "t": 218.69}, {"speaker": "Tom", "text": "And third, a website where you can find more information.", "t": 221.82}, {"speaker": "Anna", "text": "And if the message is very short?", "t": 224.69}, {"speaker": "Tom", "text": "That can happen, especially with SMS, because there is a character limit.", "t": 226.93}, {"speaker": "Tom", "text": "So if the message is short, the advice is always the same — go to the website, lu-alert dot l-u, to read the full details of the alert.", "t": 230.2}, {"speaker": "Anna", "text": "lu-alert.lu for the full story.", "t": 234.95}, {"speaker": "Anna", "text": "Now, the messages also have levels, right?", "t": 237.34}, {"speaker": "Anna", "text": "To show how serious it is?", "t": 240.27}, {"speaker": "Tom", "text": "Yes.", "t": 242.28}, {"speaker": "Tom", "text": "LU-Alert uses different alert levels.", "t": 242.65}, {"speaker": "Tom", "text": "Let me go through them.", "t": 244.65}, {"speaker": "Tom", "text": "The strongest is \"D\", for imminent danger — that means take action immediately.", "t": 245.64}, {"speaker": "Tom", "text": "Then there are three awareness levels, like the weather colours.", "t": 249.44}, {"speaker": "Tom", "text": "Red is N1 — utmost vigilance, the highest.", "t": 252.11}, {"speaker": "Tom", "text": "Orange is N2 — be careful, medium risk.", "t": 254.67}, {"speaker": "Tom", "text": "Yellow is N3 — be aware, low risk.", "t": 257.25}, {"speaker": "Anna", "text": "So red, orange, yellow — like a traffic light, almost.", "t": 259.88}, {"speaker": "Tom", "text": "Exactly, that's an easy way to remember it.", "t": 263.81}, {"speaker": "Tom", "text": "And there are three more.", "t": 266.13}, {"speaker": "Tom", "text": "\"A\" is for a missing person or a kidnapping alert.", "t": 267.18}, {"speaker": "Tom", "text": "\"I\" is just information — no danger.", "t": 269.96}, {"speaker": "Tom", "text": "And \"T\" is a test message.", "t": 272.05}, {"speaker": "Anna", "text": "Ah, the test.", "t": 273.82}, {"speaker": "Anna", "text": "So if I get a message that says it's a test...", "t": 275.21}, {"speaker": "Tom", "text": "...then you don't need to do anything.", "t": 278.22}, {"speaker": "Tom", "text": "The message will say clearly that it is a test.", "t": 279.67}, {"speaker": "Tom", "text": "Luxembourg runs national tests — for example, there was one in February 2026.", "t": 281.82}, {"speaker": "Tom", "text": "It's normal, don't worry.", "t": 286.85}, {"speaker": "Anna", "text": "Very good to know.", "t": 288.34}, {"speaker": "Anna", "text": "So nobody panics on a test day.", "t": 289.78}, {"speaker": "Anna", "text": "Now — what kind of events can trigger an alert?", "t": 292.41}, {"speaker": "Tom", "text": "Quite a wide range.", "t": 295.68}, {"speaker": "Tom", "text": "The system has twelve categories of events.", "t": 296.76}, {"speaker": "Tom", "text": "Things like weather — storms, heavy rain, snow, cold, heat.", "t": 299.16}, {"speaker": "Tom", "text": "The environment — for example floods, or air pollution.", "t": 302.51}, {"speaker": "Tom", "text": "Health — like a food recall or an allergen warning.", "t": 305.4}, {"speaker": "Tom", "text": "And then fire, rescue, security, safety, transport problems, failing infrastructure, and a few more.", "t": 307.85}, {"speaker": "Anna", "text": "So from a big storm, to a flood, to a food recall.", "t": 313.92}, {"speaker": "Tom", "text": "Exactly.", "t": 317.52}, {"speaker": "Tom", "text": "A wide range, all in one system.", "t": 318.29}, {"speaker": "Tom", "text": "And these categories follow an international standard, so they fit with other countries too.", "t": 320.32}, {"speaker": "Anna", "text": "And who actually sends these messages?", "t": 324.78}, {"speaker": "Anna", "text": "Who decides?", "t": 327.38}, {"speaker": "Tom", "text": "Only public authorities.", "t": 328.73}, {"speaker": "Tom", "text": "Several of them are connected to the system.", "t": 330.04}, {"speaker": "Tom", "text": "For example — the Police, the Fire and Rescue Corps, which is the CGDIS, the weather service MeteoLux, the water management agency, the food administration, and the High Commission for National Protection.", "t": 332.06}, {"speaker": "Anna", "text": "So it's always an official source.", "t": 342.46}, {"speaker": "Anna", "text": "Never a private company.", "t": 344.74}, {"speaker": "Tom", "text": "Never.", "t": 346.58}, {"speaker": "Tom", "text": "And one more thing — there is no advertising on LU-Alert.", "t": 347.1}, {"speaker": "Tom", "text": "It is used only by public authorities, only for warning and information.", "t": 349.9}, {"speaker": "Tom", "text": "Never for ads.", "t": 353.73}, {"speaker": "Anna", "text": "That's a perfect link to my next worry.", "t": 354.9}, {"speaker": "Anna", "text": "Scams.", "t": 357.39}, {"speaker": "Anna", "text": "How do I know a message is real, and not phishing?", "t": 358.36}, {"speaker": "Tom", "text": "Very important topic.", "t": 361.62}, {"speaker": "Tom", "text": "Like any message, an alert could be imitated by criminals.", "t": 363.01}, {"speaker": "Tom", "text": "So, a few simple checks.", "t": 366.06}, {"speaker": "Tom", "text": "First — the public authorities will never ask you for personal data.", "t": 367.58}, {"speaker": "Tom", "text": "Never.", "t": 370.69}, {"speaker": "Anna", "text": "Never share personal data.", "t": 371.38}, {"speaker": "Anna", "text": "Okay.", "t": 373.18}, {"speaker": "Tom", "text": "Second — normally, the message will not contain a clickable link.", "t": 374.14}, {"speaker": "Tom", "text": "If somehow there is a link, be careful, and check that it really points to an official government website.", "t": 377.3}, {"speaker": "Tom", "text": "And third, the easiest check of all — go to lu-alert dot l-u and see if the same alert is listed there.", "t": 381.99}, {"speaker": "Tom", "text": "If it's real, it will be on the website.", "t": 385.94}, {"speaker": "Anna", "text": "So when in doubt, check the website.", "t": 388.21}, {"speaker": "Anna", "text": "Don't click, don't share, just verify.", "t": 390.62}, {"speaker": "Tom", "text": "That's the golden rule.", "t": 393.64}, {"speaker": "Anna", "text": "Now, two questions about people who might be left out.", "t": 394.83}, {"speaker": "Anna", "text": "First — what if I don't have a smartphone?", "t": 398.39}, {"speaker": "Tom", "text": "Then you won't get the app messages, or Cell Broadcast.", "t": 401.2}, {"speaker": "Tom", "text": "But you can still receive a location-based SMS on a normal phone.", "t": 403.86}, {"speaker": "Tom", "text": "And you always have the other channels — the website, other government websites, the radio and television.", "t": 407.47}, {"speaker": "Anna", "text": "And someone with a visual impairment?", "t": 412.41}, {"speaker": "Tom", "text": "Most phones have accessibility settings.", "t": 414.77}, {"speaker": "Tom", "text": "You can let the phone read the message out loud, or make the text bigger.", "t": 416.85}, {"speaker": "Tom", "text": "So the message can be heard, not only seen.", "t": 419.95}, {"speaker": "Anna", "text": "That's thoughtful.", "t": 422.32}, {"speaker": "Anna", "text": "Okay, Tom — let's make it really practical.", "t": 423.43}, {"speaker": "Anna", "text": "If I'm listening now, what should I do today, to be ready?", "t": 426.54}, {"speaker": "Tom", "text": "Three simple things.", "t": 430.18}, {"speaker": "Tom", "text": "One — download the LU-Alert app, from your app store, and choose your language.", "t": 431.4}, {"speaker": "Tom", "text": "Two — check that your phone can receive these alerts; you can look in your phone settings, under emergency or government alerts.", "t": 435.44}, {"speaker": "Tom", "text": "And three — remember the website, lu-alert dot l-u, and remember the golden rule: verify there, never share personal data.", "t": 441.34}, {"speaker": "Anna", "text": "Download the app, check your settings, remember the website.", "t": 444.97}, {"speaker": "Anna", "text": "Easy.", "t": 448.35}, {"speaker": "Anna", "text": "Okay, short summary to finish?", "t": 449.06}, {"speaker": "Tom", "text": "Sure.", "t": 451.49}, {"speaker": "Tom", "text": "LU-Alert is Luxembourg's national warning and information system, launched in autumn 2024.", "t": 451.78}, {"speaker": "Tom", "text": "It reaches you on your phone — by Cell Broadcast and location-based SMS, with no sign-up needed — and also through the app, websites, the media and, for nuclear alerts, sirens.", "t": 457.33}, {"speaker": "Tom", "text": "Messages come in German, English and French, with a level from yellow up to imminent danger, and they tell you what happened and what to do.", "t": 466.67}, {"speaker": "Anna", "text": "And the safety message?", "t": 472.9}, {"speaker": "Tom", "text": "The authorities never ask for personal data, and there are no ads.", "t": 474.61}, {"speaker": "Tom", "text": "If you are not sure, check lu-alert dot l-u.", "t": 477.81}, {"speaker": "Anna", "text": "Beautiful.", "t": 480.36}, {"speaker": "Anna", "text": "So...", "t": 481.24}, {"speaker": "Anna", "text": "an emergency is rare, but being ready costs you nothing.", "t": 481.95}, {"speaker": "Anna", "text": "Download the app today, and you're prepared.", "t": 485.6}, {"speaker": "Tom", "text": "Really.", "t": 488.47}, {"speaker": "Tom", "text": "A few minutes now...", "t": 488.94}, {"speaker": "Tom", "text": "real peace of mind later.", "t": 489.98}, {"speaker": "Anna", "text": "That was our episode about LU-Alert, part of the Biergerpakt — living together in Luxembourg, discovering the country, and staying safe together.", "t": 491.73}, {"speaker": "Anna", "text": "Thank you so much for listening.", "t": 500.11}, {"speaker": "Tom", "text": "Thank you, everyone.", "t": 502.18}, {"speaker": "Tom", "text": "Take care...", "t": 503.54}, {"speaker": "Tom", "text": "and see you next time!", "t": 504.32}, {"speaker": "Anna", "text": "Bye bye!", "t": 505.55}], "questions": [{"text": "What is LU-Alert?", "options": ["A private weather app you subscribe to", "A social media account run by the police", "Luxembourg’s national public warning and information system, launched in autumn 2024", "An insurance scheme for natural disasters"], "correct": 2, "explanation": "“LU-Alert” combines “LU” (the country code for Luxembourg) and “Alert”. It is the national warning and information system for the population, deployed in autumn 2024 to warn people about dangerous events."}, {"text": "Do you need to sign up to receive alerts by Cell Broadcast or location-based SMS?", "options": ["No – there is no registration; any phone in the targeted area is reached automatically", "Yes, you must register your number on lu-alert.lu", "Yes, but only cross-border workers need to register", "No, but only if you pay a small annual fee"], "correct": 0, "explanation": "For Cell Broadcast and location-based SMS you do not sign up – and cannot really opt out. If your phone is in the area when the authorities send a message, it is targeted automatically. (For the mobile app, you simply download it.)"}, {"text": "In which languages are LU-Alert messages sent?", "options": ["Only Luxembourgish", "Only French", "English and Luxembourgish", "German, English and French"], "correct": 3, "explanation": "Warning and information messages are issued in German, English and French, so English speakers are covered."}, {"text": "When are sirens used in the LU-Alert system?", "options": ["For every weather warning", "Only in the event of a nuclear alert", "Every day at noon as a test", "Whenever the mobile network is down"], "correct": 1, "explanation": "Today the sirens are used only for a nuclear alert. All other warnings reach you through phones (Cell Broadcast and SMS), the app, websites and the media."}, {"text": "How can you check that an alert message is genuine and not phishing?", "options": ["Reply to the SMS with your details to confirm your identity", "Click the link in the message to verify it", "Remember that the authorities never ask for personal data, and check whether the alert is listed on lu-alert.lu", "Call the number shown and give your bank details"], "correct": 2, "explanation": "Public authorities never ask for personal data, and messages normally contain no clickable link. If you are unsure, verify the alert on lu-alert.lu – and never share personal data."}]}, {"id": 6, "key": "luxtrust", "number": "Episode 6", "audio": "podcast_luxtrust.mp3", "title": "LuxTrust – Your Digital Identity in Luxembourg", "description": "Your secure digital identity for life online in Luxembourg: what LuxTrust is, what individuals use it for, the different products, and how to order, get identified and activate it. (Briefly: businesses use it too.)", "duration": 537.76, "topics": ["What a digital identity is", "Online banking login", "MyGuichet & public services", "Legally-valid e-signature", "Confirming online payments", "App, Scan & SmartCard", "Ordering & video ID", "Activation & staying safe"], "segments": [{"speaker": "Anna", "text": "Hello, and welcome!", "t": 0.0}, {"speaker": "Anna", "text": "It's really nice to have you with us today.", "t": 1.49}, {"speaker": "Tom", "text": "Hello everyone!", "t": 4.14}, {"speaker": "Anna", "text": "This episode is part of the Biergerpakt.", "t": 5.3}, {"speaker": "Anna", "text": "That's a programme of living together in Luxembourg.", "t": 8.0}, {"speaker": "Anna", "text": "The idea is simple...", "t": 11.22}, {"speaker": "Anna", "text": "we want to help residents, and also cross-border workers, to discover Luxembourg — or re-discover it — and to meet new people.", "t": 12.71}, {"speaker": "Tom", "text": "Exactly.", "t": 20.27}, {"speaker": "Tom", "text": "And today we talk about something you will need almost everywhere in Luxembourg, online.", "t": 21.04}, {"speaker": "Tom", "text": "It's called LuxTrust.", "t": 24.97}, {"speaker": "Anna", "text": "LuxTrust.", "t": 26.39}, {"speaker": "Anna", "text": "We have mentioned it before, in the episode about MyGuichet.", "t": 27.55}, {"speaker": "Anna", "text": "But today, the full story.", "t": 31.28}, {"speaker": "Anna", "text": "Tom, let's start simply.", "t": 33.2}, {"speaker": "Anna", "text": "What is LuxTrust?", "t": 35.27}, {"speaker": "Tom", "text": "So, LuxTrust gives you one thing — a digital identity.", "t": 37.06}, {"speaker": "Tom", "text": "A single, secure digital identity that lets you prove who you really are, online.", "t": 40.06}, {"speaker": "Anna", "text": "A digital identity.", "t": 44.24}, {"speaker": "Anna", "text": "Can you explain that a bit more?", "t": 45.88}, {"speaker": "Tom", "text": "Of course.", "t": 48.06}, {"speaker": "Tom", "text": "Think of it as the digital version of your ID card or your passport.", "t": 48.77}, {"speaker": "Tom", "text": "In real life, you show your ID card to prove who you are.", "t": 51.99}, {"speaker": "Tom", "text": "But online, nobody can see you.", "t": 54.78}, {"speaker": "Tom", "text": "So you need something that proves your identity in a secure way.", "t": 56.75}, {"speaker": "Tom", "text": "That's the digital identity.", "t": 59.68}, {"speaker": "Anna", "text": "Ah.", "t": 61.25}, {"speaker": "Anna", "text": "So it's like an ID card, but for the internet.", "t": 61.89}, {"speaker": "Tom", "text": "Exactly.", "t": 65.06}, {"speaker": "Tom", "text": "And LuxTrust is the company that provides it.", "t": 65.81}, {"speaker": "Tom", "text": "They are what we call a \"Certificate Authority\" and a \"trust service provider\".", "t": 67.86}, {"speaker": "Tom", "text": "They are certified by the European Union, and they have been doing this for about twenty years.", "t": 70.95}, {"speaker": "Anna", "text": "Twenty years.", "t": 75.28}, {"speaker": "Anna", "text": "So it's well established.", "t": 76.42}, {"speaker": "Anna", "text": "And is my data safe with them?", "t": 78.32}, {"speaker": "Tom", "text": "Yes.", "t": 80.38}, {"speaker": "Tom", "text": "Your data is encrypted, and stored in data centres here, in Luxembourg.", "t": 80.76}, {"speaker": "Tom", "text": "Security is really the whole point of the company.", "t": 84.44}, {"speaker": "Anna", "text": "Good.", "t": 86.91}, {"speaker": "Anna", "text": "Now the most important question for most people.", "t": 87.63}, {"speaker": "Anna", "text": "What can I actually do with my LuxTrust identity?", "t": 90.65}, {"speaker": "Tom", "text": "A lot of everyday things.", "t": 94.01}, {"speaker": "Tom", "text": "Let me give the four main uses.", "t": 95.42}, {"speaker": "Tom", "text": "The first, and the most common — your bank.", "t": 97.0}, {"speaker": "Tom", "text": "With LuxTrust, you log in to your online banking securely, and you confirm your transactions.", "t": 99.04}, {"speaker": "Tom", "text": "A payment, a transfer...", "t": 103.5}, {"speaker": "Tom", "text": "you validate it with LuxTrust.", "t": 104.84}, {"speaker": "Anna", "text": "So most people in Luxembourg first meet LuxTrust through their bank.", "t": 106.61}, {"speaker": "Tom", "text": "Exactly.", "t": 110.91}, {"speaker": "Tom", "text": "The second use — public services.", "t": 111.59}, {"speaker": "Tom", "text": "With LuxTrust, you log in to MyGuichet.lu.", "t": 113.4}, {"speaker": "Tom", "text": "So you can do your administrative procedures, and, for example, complete and sign your tax declaration online.", "t": 115.66}, {"speaker": "Anna", "text": "That's the link with our MyGuichet episode.", "t": 121.42}, {"speaker": "Anna", "text": "Okay, the third?", "t": 124.11}, {"speaker": "Tom", "text": "The third is a beautiful one — the electronic signature.", "t": 125.67}, {"speaker": "Tom", "text": "With LuxTrust, you can sign a document electronically.", "t": 128.64}, {"speaker": "Tom", "text": "And — this is the key point — that electronic signature has the same legal value as a handwritten signature.", "t": 131.32}, {"speaker": "Anna", "text": "Wait, really?", "t": 136.7}, {"speaker": "Anna", "text": "The same legal value as signing with a pen?", "t": 137.9}, {"speaker": "Tom", "text": "The same.", "t": 140.73}, {"speaker": "Tom", "text": "So you can close a contract, or sign an official document, from your home, without printing anything.", "t": 141.38}, {"speaker": "Anna", "text": "That's powerful.", "t": 146.39}, {"speaker": "Anna", "text": "And the fourth use?", "t": 147.49}, {"speaker": "Tom", "text": "The fourth — your online purchases.", "t": 148.98}, {"speaker": "Tom", "text": "When you shop online, LuxTrust can be used, together with the system called 3D Secure, to confirm that it's really you paying.", "t": 150.81}, {"speaker": "Tom", "text": "So your card payments are more secure.", "t": 156.83}, {"speaker": "Anna", "text": "So, to sum up — banking, public services, electronic signature, and online payments.", "t": 158.99}, {"speaker": "Tom", "text": "That's it.", "t": 164.52}, {"speaker": "Tom", "text": "One identity, for all of these.", "t": 165.07}, {"speaker": "Anna", "text": "And quickly — is it only for individuals like us?", "t": 167.03}, {"speaker": "Anna", "text": "Or also for companies?", "t": 170.35}, {"speaker": "Tom", "text": "Mostly we talk about individuals today.", "t": 172.22}, {"speaker": "Tom", "text": "But yes, businesses use LuxTrust too — to identify their customers, to sign and seal documents, and to secure their processes.", "t": 174.18}, {"speaker": "Tom", "text": "But for you, as a resident or cross-border worker, the personal uses are what matter most.", "t": 180.84}, {"speaker": "Anna", "text": "Perfect.", "t": 185.44}, {"speaker": "Anna", "text": "Now, the practical part.", "t": 186.26}, {"speaker": "Anna", "text": "How does it actually work, when I use it?", "t": 188.15}, {"speaker": "Tom", "text": "Let's take the example of logging in to your bank.", "t": 191.01}, {"speaker": "Tom", "text": "Step one — you connect to your bank's website or app.", "t": 193.39}, {"speaker": "Tom", "text": "Step two — you choose your LuxTrust device.", "t": 195.99}, {"speaker": "Tom", "text": "Step three — you enter your User ID and your password.", "t": 198.34}, {"speaker": "Tom", "text": "Or, if you have a card-based device, your PIN code.", "t": 201.12}, {"speaker": "Tom", "text": "And step four — you generate a one-time password, an OTP — a code that works only once — and that gives you access.", "t": 203.93}, {"speaker": "Anna", "text": "A one-time password.", "t": 210.05}, {"speaker": "Anna", "text": "So a new code each time.", "t": 211.64}, {"speaker": "Tom", "text": "Each time.", "t": 213.74}, {"speaker": "Tom", "text": "That's what makes it secure.", "t": 214.34}, {"speaker": "Tom", "text": "With the LuxTrust app, this all happens in a few taps on your phone.", "t": 215.63}, {"speaker": "Anna", "text": "Speaking of which — what are the different LuxTrust products?", "t": 218.82}, {"speaker": "Anna", "text": "Because I think there's a choice.", "t": 222.34}, {"speaker": "Tom", "text": "There is.", "t": 224.42}, {"speaker": "Tom", "text": "For an individual, there are three main products.", "t": 225.03}, {"speaker": "Tom", "text": "The first, and today the most popular — the LuxTrust Mobile app.", "t": 227.52}, {"speaker": "Tom", "text": "It's a one-hundred-percent mobile solution.", "t": 230.69}, {"speaker": "Tom", "text": "Everything happens on your smartphone.", "t": 232.85}, {"speaker": "Anna", "text": "So no extra device to carry.", "t": 234.67}, {"speaker": "Anna", "text": "Just my phone.", "t": 236.98}, {"speaker": "Tom", "text": "Just your phone.", "t": 238.48}, {"speaker": "Tom", "text": "The second product is the Scan — a small physical device, with a little screen and a camera, that generates your codes.", "t": 239.29}, {"speaker": "Tom", "text": "And the third is the SmartCard — a chip card, like a bank card.", "t": 244.96}, {"speaker": "Tom", "text": "But to use the SmartCard, you need a card reader and some software on your computer.", "t": 248.2}, {"speaker": "Anna", "text": "And which one should most people choose?", "t": 252.38}, {"speaker": "Tom", "text": "For most people today, the app is the easiest.", "t": 255.01}, {"speaker": "Tom", "text": "And here's an important note — the old LuxTrust Token, the little device many people had on their keychain, was stopped at the end of 2024.", "t": 257.44}, {"speaker": "Tom", "text": "So if you still have an old Token, it's time to switch to the app.", "t": 265.03}, {"speaker": "Anna", "text": "Good to know.", "t": 268.1}, {"speaker": "Anna", "text": "And — roughly — what does it cost?", "t": 269.09}, {"speaker": "Tom", "text": "It's a paid service, valid for three years.", "t": 271.54}, {"speaker": "Tom", "text": "As a rough idea, the app starts at around fifty euros for three years, and the physical devices cost a bit more.", "t": 273.87}, {"speaker": "Tom", "text": "But please check the exact prices on luxtrust.com, because they can change.", "t": 279.33}, {"speaker": "Anna", "text": "Always check the website for the exact price.", "t": 283.19}, {"speaker": "Anna", "text": "Okay, Tom — now the big practical question.", "t": 286.15}, {"speaker": "Anna", "text": "I'm new here, I have nothing yet.", "t": 289.27}, {"speaker": "Anna", "text": "How do I get a LuxTrust identity?", "t": 291.59}, {"speaker": "Anna", "text": "Step by step.", "t": 294.11}, {"speaker": "Tom", "text": "Five steps.", "t": 295.51}, {"speaker": "Tom", "text": "Step one — choose the right product for you, for example the app.", "t": 296.45}, {"speaker": "Tom", "text": "Step two — place your order.", "t": 299.36}, {"speaker": "Tom", "text": "You can order online, on the LuxTrust website, or through your bank.", "t": 300.93}, {"speaker": "Anna", "text": "Ah, so my bank can set it up for me.", "t": 304.47}, {"speaker": "Tom", "text": "Very often, yes — many people get their LuxTrust through their bank.", "t": 307.34}, {"speaker": "Tom", "text": "Step three, and this one is important — you must get identified.", "t": 310.73}, {"speaker": "Tom", "text": "Because they are creating proof of your identity, they must check who you are.", "t": 314.06}, {"speaker": "Tom", "text": "You can do this face-to-face, with one of their agents.", "t": 317.42}, {"speaker": "Tom", "text": "Or remotely, by a video identification.", "t": 319.77}, {"speaker": "Anna", "text": "So, a bit like opening a bank account.", "t": 322.23}, {"speaker": "Anna", "text": "They verify it's really me.", "t": 325.16}, {"speaker": "Tom", "text": "Exactly.", "t": 327.19}, {"speaker": "Tom", "text": "Step four — you receive your LuxTrust codes, and your device if you ordered one.", "t": 327.93}, {"speaker": "Tom", "text": "And step five — you activate your identity.", "t": 331.7}, {"speaker": "Tom", "text": "After that, your digital identity is valid for three years.", "t": 333.87}, {"speaker": "Anna", "text": "Let's stay on that last step — activation.", "t": 336.98}, {"speaker": "Anna", "text": "What do I need to have ready?", "t": 339.94}, {"speaker": "Tom", "text": "Good question.", "t": 341.92}, {"speaker": "Tom", "text": "Before you start, have these things at hand.", "t": 342.64}, {"speaker": "Tom", "text": "Your User ID — you receive it by letter, or by SMS.", "t": 344.61}, {"speaker": "Tom", "text": "Your initial password — also by letter or SMS.", "t": 347.9}, {"speaker": "Tom", "text": "Your device, if you have one.", "t": 350.8}, {"speaker": "Tom", "text": "And your activation code.", "t": 352.38}, {"speaker": "Anna", "text": "The activation code — where does that come from?", "t": 353.77}, {"speaker": "Tom", "text": "You actually chose it yourself, when you ordered.", "t": 357.03}, {"speaker": "Tom", "text": "They usually advise you to use the last five characters of your ID card or passport number.", "t": 359.14}, {"speaker": "Tom", "text": "And you also find it in the order confirmation, sent to you by email.", "t": 364.11}, {"speaker": "Anna", "text": "Okay.", "t": 367.48}, {"speaker": "Anna", "text": "And how does the activation itself go?", "t": 368.35}, {"speaker": "Tom", "text": "It depends on the product.", "t": 371.01}, {"speaker": "Tom", "text": "For the Mobile app, you activate it directly on your smartphone, following the guide.", "t": 372.16}, {"speaker": "Tom", "text": "For the Scan, it takes about six minutes — you follow the steps, scan some QR codes, and set a new, strong password.", "t": 375.9}, {"speaker": "Tom", "text": "For the SmartCard, it's a bit longer, around twenty minutes, because you first install the software, called the middleware, on your computer.", "t": 382.06}, {"speaker": "Anna", "text": "And once I finish activating — can I use it immediately?", "t": 388.84}, {"speaker": "Tom", "text": "Almost.", "t": 392.5}, {"speaker": "Tom", "text": "One small thing to remember — after activation, the certificate becomes usable after about four hours.", "t": 393.17}, {"speaker": "Tom", "text": "So don't activate it five minutes before you need it.", "t": 398.22}, {"speaker": "Tom", "text": "Do it a little in advance.", "t": 400.62}, {"speaker": "Anna", "text": "Very practical tip.", "t": 402.18}, {"speaker": "Anna", "text": "Activate it the evening before, not at the last minute.", "t": 403.9}, {"speaker": "Tom", "text": "Exactly.", "t": 407.41}, {"speaker": "Anna", "text": "Now, Tom — this is digital identity, it's sensitive.", "t": 408.27}, {"speaker": "Anna", "text": "Let's talk about safety.", "t": 412.22}, {"speaker": "Anna", "text": "About scams.", "t": 414.07}, {"speaker": "Tom", "text": "Yes, this is really important.", "t": 415.47}, {"speaker": "Tom", "text": "There are phishing attempts — fake messages, fake phone calls, that pretend to be LuxTrust.", "t": 417.19}, {"speaker": "Tom", "text": "So remember a few rules.", "t": 421.51}, {"speaker": "Tom", "text": "LuxTrust will never ask you for your codes or your credentials.", "t": 423.2}, {"speaker": "Tom", "text": "Never.", "t": 426.1}, {"speaker": "Anna", "text": "Never give the codes.", "t": 426.8}, {"speaker": "Anna", "text": "Even if it looks official?", "t": 428.5}, {"speaker": "Tom", "text": "Even then.", "t": 430.43}, {"speaker": "Tom", "text": "And more — LuxTrust will never call you to ask for sensitive information.", "t": 431.13}, {"speaker": "Tom", "text": "They will never ask for access to your computer or your phone.", "t": 434.56}, {"speaker": "Tom", "text": "And they will never come to your home.", "t": 437.16}, {"speaker": "Anna", "text": "So if someone does any of that, it's a scam.", "t": 438.79}, {"speaker": "Tom", "text": "It's a scam.", "t": 442.29}, {"speaker": "Tom", "text": "Your digital identity is yours, and only yours.", "t": 443.08}, {"speaker": "Tom", "text": "Just like you don't give your bank card and your PIN to a colleague, you never share your LuxTrust credentials.", "t": 445.8}, {"speaker": "Tom", "text": "If you are in doubt, contact LuxTrust directly, with the number on their official website.", "t": 450.79}, {"speaker": "Anna", "text": "That's the golden rule again — when in doubt, don't share, and check directly.", "t": 455.12}, {"speaker": "Anna", "text": "Okay, Tom, let's make it really practical for someone listening.", "t": 459.72}, {"speaker": "Anna", "text": "What should I do?", "t": 463.74}, {"speaker": "Tom", "text": "If you live or work in Luxembourg and you don't have it yet — get a LuxTrust identity.", "t": 465.15}, {"speaker": "Tom", "text": "The easiest way: ask your bank, or go to luxtrust.com, choose the app, order it, get identified, and activate it.", "t": 469.23}, {"speaker": "Tom", "text": "Then you can use it for your bank, for MyGuichet, for signing documents, and for your online payments.", "t": 472.93}, {"speaker": "Anna", "text": "One identity, for your whole digital life here.", "t": 477.52}, {"speaker": "Anna", "text": "Short summary to finish?", "t": 480.32}, {"speaker": "Tom", "text": "Sure.", "t": 482.13}, {"speaker": "Tom", "text": "LuxTrust is your secure digital identity in Luxembourg — like an ID card for the internet, from a European-certified provider.", "t": 482.5}, {"speaker": "Tom", "text": "You use it for online banking, for public services like MyGuichet, for legally-valid electronic signatures, and for online payments.", "t": 488.93}, {"speaker": "Tom", "text": "You get it through your bank or on luxtrust.com, you prove your identity in person or by video, and you activate it — most easily with the Mobile app.", "t": 495.49}, {"speaker": "Anna", "text": "And the safety message?", "t": 500.02}, {"speaker": "Tom", "text": "LuxTrust never asks for your codes, never calls for sensitive data, never asks to access your devices.", "t": 501.68}, {"speaker": "Tom", "text": "Keep your credentials to yourself.", "t": 506.91}, {"speaker": "Tom", "text": "When in doubt, check the official website.", "t": 508.48}, {"speaker": "Anna", "text": "Beautiful.", "t": 510.58}, {"speaker": "Anna", "text": "So...", "t": 511.55}, {"speaker": "Anna", "text": "your digital identity is the key to daily life online in Luxembourg.", "t": 512.27}, {"speaker": "Anna", "text": "Set it up once, and so much becomes easier.", "t": 516.69}, {"speaker": "Tom", "text": "Really.", "t": 519.88}, {"speaker": "Tom", "text": "A little effort to set it up...", "t": 520.35}, {"speaker": "Tom", "text": "and then everything, from your sofa.", "t": 521.68}, {"speaker": "Anna", "text": "That was our episode about LuxTrust, part of the Biergerpakt — living together in Luxembourg, discovering the country, and meeting new people.", "t": 523.56}, {"speaker": "Anna", "text": "Thank you so much for listening.", "t": 531.66}, {"speaker": "Tom", "text": "Thank you, everyone.", "t": 533.66}, {"speaker": "Tom", "text": "Take care...", "t": 534.95}, {"speaker": "Tom", "text": "and see you next time!", "t": 535.74}, {"speaker": "Anna", "text": "Bye bye!", "t": 536.93}], "questions": [{"text": "What is LuxTrust?", "options": ["A mobile bank account", "A secure digital identity that proves who you are online – like an ID card for the internet", "An antivirus program for your phone", "A government tax website"], "correct": 1, "explanation": "LuxTrust gives you a single, secure digital identity – the online equivalent of your ID card or passport – provided by a European-certified Certificate Authority and trust service provider."}, {"text": "As an individual in Luxembourg, what can you do with LuxTrust?", "options": ["Only log in to social media", "Only file your taxes, nothing else", "Nothing until you start a company", "Log in to online banking, access MyGuichet, sign documents electronically and confirm online payments"], "correct": 3, "explanation": "The four main personal uses are secure online banking, access to public services such as MyGuichet.lu, legally-valid electronic signatures, and confirming online card payments (with 3D Secure)."}, {"text": "What legal value does a LuxTrust electronic signature have?", "options": ["The same legal value as a handwritten signature", "No legal value – it is only for convenience", "It is valid only for emails", "It is valid only inside your bank"], "correct": 0, "explanation": "A LuxTrust electronic signature has the same legal value as a handwritten signature, so you can sign official documents from home without printing anything."}, {"text": "When you obtain a LuxTrust identity, how is your identity verified?", "options": ["It is never verified", "Only by sending a photo by email", "You must be identified – in person with an agent, or remotely by video identification", "Only by answering security questions online"], "correct": 2, "explanation": "Because LuxTrust creates proof of your identity, you must be identified – face-to-face with an agent or remotely by video identification. You order online or through your bank, then activate it; the identity is valid for 3 years."}, {"text": "Which statement about LuxTrust and security is correct?", "options": ["LuxTrust may call you to ask for your password", "You can safely share your codes with your bank adviser", "LuxTrust staff may visit your home to help you", "LuxTrust will never ask for your codes or credentials, never ask to access your device, and never visit your home"], "correct": 3, "explanation": "LuxTrust never asks for your codes or credentials, never requests access to your computer or phone, and never visits your home. Keep your credentials to yourself and, if in doubt, check the official website."}]}, {"id": 7, "key": "maison_orientation", "number": "Episode 7", "audio": "podcast_maison_orientation.mp3", "title": "The Maison de l'Orientation – One Place to Help You Choose Your Path", "description": "The State “house of guidance” in Luxembourg City: how it brings many school- and career-guidance services under one roof, the free anonymous advice space, the interests-test coaching, how to book via MyGuichet, and the help it offers adults and newcomers.", "duration": 590.6, "topics": ["A house of guidance", "One place, many services", "Free, anonymous advice", "Ages 14–22 (and adults)", "Booking via MyGuichet", "Interests test & coaching", "Studies, work & apprenticeship", "Recognising diplomas & experience"], "segments": [{"speaker": "Anna", "text": "Hello, and welcome!", "t": 0.0}, {"speaker": "Anna", "text": "It's really nice to have you with us today.", "t": 1.56}, {"speaker": "Tom", "text": "Hello everyone!", "t": 4.26}, {"speaker": "Anna", "text": "This episode is part of the Biergerpakt.", "t": 5.4}, {"speaker": "Anna", "text": "That's a programme of living together in Luxembourg.", "t": 8.03}, {"speaker": "Anna", "text": "The idea is simple...", "t": 11.35}, {"speaker": "Anna", "text": "we want to help residents, and also cross-border workers, to discover Luxembourg — or re-discover it — and to meet new people.", "t": 12.88}, {"speaker": "Tom", "text": "Exactly.", "t": 20.36}, {"speaker": "Tom", "text": "And today we talk about a place that helps you with one of life's big questions — what should I study, or what work should I do?", "t": 21.11}, {"speaker": "Tom", "text": "It's called the Maison de l'Orientation.", "t": 26.3}, {"speaker": "Anna", "text": "The Maison de l'Orientation.", "t": 28.31}, {"speaker": "Anna", "text": "Let's translate that first, Tom.", "t": 30.31}, {"speaker": "Anna", "text": "What does the name mean?", "t": 32.69}, {"speaker": "Tom", "text": "So, \"Maison\" means \"house\".", "t": 34.38}, {"speaker": "Tom", "text": "And \"Orientation\" here means guidance — finding your direction, in school and in work.", "t": 36.04}, {"speaker": "Tom", "text": "So you could call it \"the House of Guidance\".", "t": 39.98}, {"speaker": "Tom", "text": "A house where you go to get help choosing your path.", "t": 41.81}, {"speaker": "Anna", "text": "I like that.", "t": 44.05}, {"speaker": "Anna", "text": "A house of guidance.", "t": 45.24}, {"speaker": "Anna", "text": "So what exactly is it?", "t": 46.72}, {"speaker": "Tom", "text": "It's a State administration — an official public service.", "t": 48.73}, {"speaker": "Tom", "text": "And its special idea is this: it brings together, in one single place, many public services that all work on school and career guidance.", "t": 51.43}, {"speaker": "Anna", "text": "Ah, so instead of running around to ten different offices...", "t": 58.45}, {"speaker": "Tom", "text": "...you go to one address, and you find them all under one roof.", "t": 62.17}, {"speaker": "Tom", "text": "That's really the whole point.", "t": 64.86}, {"speaker": "Tom", "text": "One place, many experts.", "t": 66.19}, {"speaker": "Anna", "text": "And who is it for?", "t": 67.95}, {"speaker": "Anna", "text": "Only students?", "t": 69.35}, {"speaker": "Tom", "text": "Not only.", "t": 70.71}, {"speaker": "Tom", "text": "It's for any citizen who is looking for advice about their school path or their career.", "t": 71.32}, {"speaker": "Tom", "text": "The goal is to help you identify your abilities, your skills and your interests — and then make good, informed decisions about your studies, your training, and your work plans.", "t": 75.34}, {"speaker": "Anna", "text": "So it's about understanding yourself first, and then choosing.", "t": 83.81}, {"speaker": "Tom", "text": "Exactly.", "t": 87.64}, {"speaker": "Tom", "text": "Know what you're good at, know what you like, and then choose with confidence.", "t": 88.42}, {"speaker": "Anna", "text": "Okay.", "t": 91.53}, {"speaker": "Anna", "text": "Let's get practical.", "t": 92.41}, {"speaker": "Anna", "text": "If I just walk in, what do I find?", "t": 93.91}, {"speaker": "Tom", "text": "The heart of it is the \"Espace Orientation\" — the guidance space.", "t": 96.84}, {"speaker": "Tom", "text": "It's a welcome area where you can come with your questions about school or vocational training.", "t": 100.09}, {"speaker": "Anna", "text": "And is there an age for this part?", "t": 104.31}, {"speaker": "Tom", "text": "The guidance space especially welcomes people aged 14 to 22.", "t": 106.57}, {"speaker": "Tom", "text": "So — teenagers and young adults.", "t": 110.36}, {"speaker": "Tom", "text": "But, as we'll see, the house also has services for adults.", "t": 112.41}, {"speaker": "Anna", "text": "Good.", "t": 115.64}, {"speaker": "Anna", "text": "And do I need an appointment to use this guidance space?", "t": 116.42}, {"speaker": "Tom", "text": "No, you don't have to.", "t": 119.93}, {"speaker": "Tom", "text": "And this is a lovely part — you can simply walk in, without an appointment, and get advice that is free, and anonymous.", "t": 121.12}, {"speaker": "Anna", "text": "Free and anonymous.", "t": 126.65}, {"speaker": "Anna", "text": "So nobody writes down my name, and it costs nothing.", "t": 128.31}, {"speaker": "Tom", "text": "Nothing at all.", "t": 131.95}, {"speaker": "Tom", "text": "The only thing — if you walk in without an appointment, you might have to wait a little, because the people with appointments are seen first.", "t": 132.7}, {"speaker": "Anna", "text": "That makes sense.", "t": 138.64}, {"speaker": "Anna", "text": "So I can book, to skip the wait?", "t": 140.07}, {"speaker": "Tom", "text": "Yes.", "t": 142.37}, {"speaker": "Tom", "text": "You can book an appointment, and it's done online — through MyGuichet.lu.", "t": 142.73}, {"speaker": "Anna", "text": "MyGuichet again!", "t": 146.2}, {"speaker": "Anna", "text": "We did a whole episode on that.", "t": 147.62}, {"speaker": "Tom", "text": "Yes, it keeps coming back, because it's the door to so many services.", "t": 150.18}, {"speaker": "Tom", "text": "On MyGuichet, you choose the format that suits you — an appointment online, by video, or an appointment in person, at the Maison de l'Orientation.", "t": 153.55}, {"speaker": "Tom", "text": "And you can book with or without a login.", "t": 160.84}, {"speaker": "Anna", "text": "Very flexible.", "t": 162.83}, {"speaker": "Anna", "text": "And where is the house, exactly?", "t": 164.17}, {"speaker": "Tom", "text": "It's in Luxembourg City — 29, rue Aldringen.", "t": 166.45}, {"speaker": "Tom", "text": "The guidance space is open Monday to Friday, from 8 in the morning to 5 in the afternoon.", "t": 169.14}, {"speaker": "Tom", "text": "And there's a free phone line — 8002, 8181 — and an email, info at m-o dot l-u.", "t": 173.39}, {"speaker": "Anna", "text": "Good.", "t": 178.18}, {"speaker": "Anna", "text": "Now, you said they give advice.", "t": 178.95}, {"speaker": "Anna", "text": "On what topics, concretely?", "t": 181.27}, {"speaker": "Tom", "text": "Two big families of topics.", "t": 183.47}, {"speaker": "Tom", "text": "The first is your school path.", "t": 185.06}, {"speaker": "Tom", "text": "So — guidance about secondary school, what the different lycées offer, the choice of sections, or how to get back into a lycée.", "t": 186.47}, {"speaker": "Tom", "text": "The second is training and trades.", "t": 192.47}, {"speaker": "Tom", "text": "So — information about jobs and professions, about first work experiences, about courses, and about the apprenticeship.", "t": 194.29}, {"speaker": "Anna", "text": "So from \"which school section should I choose\" to \"how do I start an apprenticeship\".", "t": 200.92}, {"speaker": "Tom", "text": "Exactly.", "t": 205.73}, {"speaker": "Tom", "text": "The whole journey from school into the world of work.", "t": 206.47}, {"speaker": "Anna", "text": "Now you mentioned a special session — coaching?", "t": 208.82}, {"speaker": "Tom", "text": "Yes.", "t": 211.66}, {"speaker": "Tom", "text": "They offer a guidance coaching session, together with an interests test.", "t": 212.02}, {"speaker": "Tom", "text": "The test helps you discover what really motivates you, what kind of activities suit you.", "t": 215.39}, {"speaker": "Tom", "text": "This one is for students, it's voluntary, and for this you do need an appointment.", "t": 219.17}, {"speaker": "Anna", "text": "An interests test — that sounds genuinely useful when you have no idea what to do.", "t": 222.69}, {"speaker": "Tom", "text": "It really helps.", "t": 228.06}, {"speaker": "Tom", "text": "Many young people don't know where to start, and a test like this gives a first direction to explore.", "t": 229.02}, {"speaker": "Anna", "text": "Okay, Tom.", "t": 233.69}, {"speaker": "Anna", "text": "You said many services are under one roof.", "t": 235.02}, {"speaker": "Anna", "text": "Can you tell us who they are?", "t": 237.81}, {"speaker": "Tom", "text": "Yes, and this is the strength of the house.", "t": 239.7}, {"speaker": "Tom", "text": "Several public services sit there, and you can make an appointment with them all year — even during the school holidays — Monday to Friday.", "t": 241.62}, {"speaker": "Tom", "text": "Let me name the main ones.", "t": 248.14}, {"speaker": "Anna", "text": "Please.", "t": 249.46}, {"speaker": "Tom", "text": "First, the CePAS — the psycho-social and school support centre.", "t": 250.38}, {"speaker": "Tom", "text": "They help pupils with personal, social or school difficulties.", "t": 253.98}, {"speaker": "Tom", "text": "Second, the SIA — the service for the integration and reception of pupils in school.", "t": 257.08}, {"speaker": "Tom", "text": "This one is very important for newcomers: it helps foreign pupils find their place in the Luxembourg school system.", "t": 261.12}, {"speaker": "Anna", "text": "That's directly useful for families arriving from abroad.", "t": 266.87}, {"speaker": "Tom", "text": "Very much.", "t": 270.55}, {"speaker": "Tom", "text": "Then, third — the ADEM career guidance service, and apprenticeship placement.", "t": 271.37}, {"speaker": "Tom", "text": "ADEM is the employment agency, and here they help with vocational orientation and finding an apprenticeship.", "t": 275.44}, {"speaker": "Tom", "text": "Fourth — the ATVA, the agency for the transition to an autonomous life.", "t": 280.75}, {"speaker": "Tom", "text": "They support young people with specific needs, to move towards independence.", "t": 284.48}, {"speaker": "Anna", "text": "So there's something even for people who need extra support.", "t": 288.08}, {"speaker": "Tom", "text": "Yes.", "t": 291.75}, {"speaker": "Tom", "text": "And then, fifth — Euroguidance.", "t": 292.14}, {"speaker": "Tom", "text": "This is a European network, for those who dream of studying or working abroad.", "t": 294.01}, {"speaker": "Tom", "text": "And finally — adult guidance.", "t": 298.02}, {"speaker": "Tom", "text": "Because, as I promised, it's not only for the young.", "t": 299.72}, {"speaker": "Anna", "text": "Let's stay on that — adults.", "t": 302.51}, {"speaker": "Anna", "text": "Because many of our listeners are grown-ups, maybe thinking of changing job.", "t": 304.59}, {"speaker": "Tom", "text": "Right.", "t": 309.2}, {"speaker": "Tom", "text": "So the Maison de l'Orientation also helps with changing your professional path.", "t": 309.73}, {"speaker": "Tom", "text": "If you want to re-orient, or get back into work, they can guide you.", "t": 313.13}, {"speaker": "Tom", "text": "If you want to go back to studying, or follow a training, they help.", "t": 316.37}, {"speaker": "Tom", "text": "And if you arrived from another country, they help you with two key things — getting your diplomas recognised, and validating the experience you already have.", "t": 319.43}, {"speaker": "Anna", "text": "That last point is so important for newcomers.", "t": 326.66}, {"speaker": "Anna", "text": "You might have years of experience from your home country.", "t": 329.65}, {"speaker": "Tom", "text": "Exactly.", "t": 333.06}, {"speaker": "Tom", "text": "And there's an official process to turn that experience into a recognised qualification here.", "t": 333.76}, {"speaker": "Tom", "text": "The house can point you to it.", "t": 337.9}, {"speaker": "Anna", "text": "Beautiful.", "t": 339.36}, {"speaker": "Anna", "text": "So really, it covers the whole of life — a teenager choosing a school section, a young adult looking for an apprenticeship, and an adult changing career or arriving from abroad.", "t": 340.26}, {"speaker": "Tom", "text": "That's the idea.", "t": 350.1}, {"speaker": "Tom", "text": "Guidance, for every stage.", "t": 350.99}, {"speaker": "Anna", "text": "Now, Tom — there's also a website, isn't there?", "t": 352.76}, {"speaker": "Anna", "text": "For people who want to look first, from home.", "t": 355.93}, {"speaker": "Tom", "text": "Yes, and it's a real resource on its own.", "t": 359.02}, {"speaker": "Tom", "text": "The website is maison-orientation, all one word, dot public dot l-u.", "t": 361.16}, {"speaker": "Tom", "text": "And it's organised around a few big themes.", "t": 363.85}, {"speaker": "Tom", "text": "Let me walk through them.", "t": 365.79}, {"speaker": "Anna", "text": "Please do.", "t": 366.99}, {"speaker": "Tom", "text": "The first theme is \"My studies\".", "t": 368.09}, {"speaker": "Tom", "text": "There you find information about basic and secondary school, and a very practical thing — the calendar of open days of the lycées and the universities.", "t": 369.72}, {"speaker": "Anna", "text": "Ah, the open days — when you can visit a school and see it for yourself.", "t": 376.74}, {"speaker": "Tom", "text": "Exactly.", "t": 381.48}, {"speaker": "Tom", "text": "You go, you look around, you ask questions, you get a feeling for the place.", "t": 382.25}, {"speaker": "Tom", "text": "And there's also a part called \"What to do after the bac?\" — the bac being the end-of-secondary diploma.", "t": 385.75}, {"speaker": "Tom", "text": "So, what comes next — university, a higher technical diploma, and so on.", "t": 390.09}, {"speaker": "Anna", "text": "Useful.", "t": 394.39}, {"speaker": "Anna", "text": "What's the second theme?", "t": 395.24}, {"speaker": "Tom", "text": "The second is \"The world of work\".", "t": 396.87}, {"speaker": "Tom", "text": "This is about discovering jobs and professions, and your first steps into working life.", "t": 398.4}, {"speaker": "Tom", "text": "There's a special part for young people — about internships, holiday jobs, student jobs, even things like a gap year or \"work and travel\".", "t": 402.58}, {"speaker": "Anna", "text": "Oh, so for a teenager who wants a summer job, or a first experience...", "t": 409.9}, {"speaker": "Tom", "text": "...there's information made just for them.", "t": 414.54}, {"speaker": "Tom", "text": "They even have a series of brochures, called BOOST, with exactly this kind of advice.", "t": 416.11}, {"speaker": "Tom", "text": "And this theme also covers the apprenticeship, and the path \"towards employment\" — so, looking for a job.", "t": 420.21}, {"speaker": "Anna", "text": "Good.", "t": 425.44}, {"speaker": "Anna", "text": "And the third theme?", "t": 426.16}, {"speaker": "Tom", "text": "The third is \"Changing your professional path\".", "t": 427.55}, {"speaker": "Tom", "text": "This is the one for adults we spoke about — help to re-orient or get back into work, going back to studies or following a training, and getting your diplomas recognised and your experience validated.", "t": 429.49}, {"speaker": "Anna", "text": "And the fourth?", "t": 439.18}, {"speaker": "Tom", "text": "The fourth is \"Help and support\".", "t": 440.5}, {"speaker": "Tom", "text": "This gathers the support for harder situations — what to do when you have difficulties, the financial and in-kind aid that exists, support for foreign pupils joining school, and support for people with specific needs.", "t": 442.11}, {"speaker": "Anna", "text": "So the website almost mirrors the house — every kind of question has its place.", "t": 452.27}, {"speaker": "Tom", "text": "Exactly.", "t": 457.23}, {"speaker": "Tom", "text": "And one more nice thing — the Maison de l'Orientation organises events and workshops all year.", "t": 458.06}, {"speaker": "Tom", "text": "For example, workshops on how to write a CV — they even have one on making a video CV.", "t": 462.65}, {"speaker": "Tom", "text": "Information evenings about studying and working abroad.", "t": 467.2}, {"speaker": "Tom", "text": "And sessions for the parents of future apprentices.", "t": 470.05}, {"speaker": "Anna", "text": "So there's an agenda of events too.", "t": 472.44}, {"speaker": "Anna", "text": "Worth checking before you go.", "t": 474.91}, {"speaker": "Tom", "text": "Definitely.", "t": 476.88}, {"speaker": "Tom", "text": "The agenda is on the website, with all the dates and places.", "t": 477.65}, {"speaker": "Anna", "text": "Is there anything for people who are really stuck, or in difficulty?", "t": 480.94}, {"speaker": "Tom", "text": "Yes.", "t": 484.94}, {"speaker": "Tom", "text": "The website has a whole section for support and help — including what to do when you have difficulties, the financial and in-kind aid that exists, support for foreign pupils, and support for people with specific needs.", "t": 485.28}, {"speaker": "Tom", "text": "So you're never alone with the question.", "t": 495.36}, {"speaker": "Anna", "text": "And all of this — still free?", "t": 497.2}, {"speaker": "Tom", "text": "The guidance and information service is free.", "t": 499.53}, {"speaker": "Tom", "text": "That's the spirit of a public service like this.", "t": 501.87}, {"speaker": "Anna", "text": "Okay, Tom.", "t": 504.01}, {"speaker": "Anna", "text": "Let's make it really practical.", "t": 505.43}, {"speaker": "Anna", "text": "If I'm listening, and I — or my child — have one of these questions, what do I do?", "t": 507.48}, {"speaker": "Tom", "text": "Very simple.", "t": 512.75}, {"speaker": "Tom", "text": "If you want, book an appointment through MyGuichet.lu — choose online or in person.", "t": 513.57}, {"speaker": "Tom", "text": "Or, if you prefer, just walk in to the Maison de l'Orientation, 29 rue Aldringen in Luxembourg City, Monday to Friday, between 8 and 5, for free and anonymous advice.", "t": 516.43}, {"speaker": "Tom", "text": "And if you have a quick question, call the free line, 8002, 8181.", "t": 525.79}, {"speaker": "Anna", "text": "Book on MyGuichet, or simply walk in.", "t": 530.75}, {"speaker": "Anna", "text": "Easy.", "t": 533.46}, {"speaker": "Anna", "text": "Short summary to finish?", "t": 534.16}, {"speaker": "Tom", "text": "Sure.", "t": 535.99}, {"speaker": "Tom", "text": "The Maison de l'Orientation is a State house that brings many guidance services together in one place, in Luxembourg City.", "t": 536.38}, {"speaker": "Tom", "text": "It helps you choose your school path or your career — by understanding your abilities and interests.", "t": 542.7}, {"speaker": "Tom", "text": "The guidance space is free, and anonymous, mainly for people aged 14 to 22, but the house also helps adults and people changing career, and newcomers who need their diplomas or experience recognised.", "t": 547.17}, {"speaker": "Anna", "text": "And how to start?", "t": 557.56}, {"speaker": "Tom", "text": "Book through MyGuichet.lu, or walk in, Monday to Friday.", "t": 559.0}, {"speaker": "Tom", "text": "Free advice, and many experts under one roof.", "t": 561.66}, {"speaker": "Anna", "text": "So...", "t": 564.24}, {"speaker": "Anna", "text": "if you're not sure what to study, or what to do next — you don't have to figure it out alone.", "t": 564.95}, {"speaker": "Anna", "text": "There's a whole house ready to help.", "t": 570.07}, {"speaker": "Tom", "text": "Really.", "t": 572.4}, {"speaker": "Tom", "text": "Just go once, with your questions.", "t": 572.85}, {"speaker": "Tom", "text": "You'll leave with a clearer path.", "t": 574.5}, {"speaker": "Anna", "text": "That was our episode about the Maison de l'Orientation, part of the Biergerpakt — living together in Luxembourg, discovering the country, and finding your way.", "t": 575.91}, {"speaker": "Anna", "text": "Thank you so much for listening.", "t": 584.45}, {"speaker": "Tom", "text": "Thank you, everyone.", "t": 586.48}, {"speaker": "Tom", "text": "Take care...", "t": 587.79}, {"speaker": "Tom", "text": "and see you next time!", "t": 588.54}, {"speaker": "Anna", "text": "Bye bye!", "t": 589.78}], "questions": [{"text": "What is the Maison de l'Orientation?", "options": ["A private tutoring company", "A university in Luxembourg City", "A State service that brings many school- and career-guidance services together in one place", "An employment agency only for adults"], "correct": 2, "explanation": "It is a public administration that gathers, under one roof in Luxembourg City, many public services working on school and career guidance, for any citizen who wants help choosing their path."}, {"text": "What is the walk-in guidance space (“Espace Orientation”) like?", "options": ["It is free and anonymous, mainly for people aged 14 to 22, and you can come without an appointment", "It costs 50 euros and always requires an appointment", "It is only for Luxembourg citizens over 25", "It is open only one day per year"], "correct": 0, "explanation": "The guidance space offers free, anonymous advice, mainly for people aged about 14 to 22. You can simply walk in (Monday to Friday, 8:00–17:00), or book ahead to avoid waiting."}, {"text": "How do you book an appointment at the Maison de l'Orientation?", "options": ["By posting a letter", "Only by visiting in person first", "Through your bank", "Online through MyGuichet.lu, choosing an online or an in-person appointment"], "correct": 3, "explanation": "Appointments are booked online via MyGuichet.lu, where you choose an online/video or an in-person meeting. Booking is possible with or without authentication."}, {"text": "What does the orientation coaching session include?", "options": ["A written exam you must pass", "A guidance coaching session with an interests test – voluntary and by appointment", "A compulsory medical check", "A paid private lesson"], "correct": 1, "explanation": "The coaching session comes with an interests test that helps you discover what motivates you and which activities suit you. It is aimed at students, is voluntary, and requires an appointment."}, {"text": "Besides young pupils, who else can the Maison de l'Orientation help?", "options": ["Only primary school children", "Only company owners", "Adults changing career and newcomers too – including getting diplomas recognised and experience validated, via services such as ADEM guidance, CePAS, SIA and Euroguidance", "Nobody – it only hands out leaflets"], "correct": 2, "explanation": "Beyond pupils aged 14–22, the house helps adults re-orienting or returning to study, and newcomers who need diplomas recognised or experience validated, through services such as ADEM career guidance, CePAS, SIA, ATVA and Euroguidance."}]}, {"id": 8, "key": "infosenior", "number": "Episode 8", "audio": "podcast_infosenior.mp3", "title": "Info-Seniors – Finding the Right Help for Older People", "description": "The State's official information portal for older people in Luxembourg (infosenior.lu): its Public Register of approved, quality-checked senior services — care homes, assisted living, day care, home help, meals on wheels, telecare and activities — and who it helps and how.", "duration": 554.68, "topics": ["The infosenior.lu portal", "Run by the Ministry of Family", "Public Register of Services", "Only approved (“agréé”) services", "Care, home help & meals", "Telecare & day care", "Clubs Aktiv Plus & activities", "Dementia, isolation & mediation"], "segments": [{"speaker": "Anna", "text": "Hello, and welcome!", "t": 0.0}, {"speaker": "Anna", "text": "It's really nice to have you with us today.", "t": 1.53}, {"speaker": "Tom", "text": "Hello everyone!", "t": 4.27}, {"speaker": "Anna", "text": "This episode is part of the Biergerpakt.", "t": 5.34}, {"speaker": "Anna", "text": "That's a programme of living together in Luxembourg.", "t": 7.99}, {"speaker": "Anna", "text": "The idea is simple...", "t": 11.21}, {"speaker": "Anna", "text": "we want to help residents, and also cross-border workers, to discover Luxembourg — or re-discover it — and to meet new people.", "t": 12.72}, {"speaker": "Tom", "text": "Exactly.", "t": 20.22}, {"speaker": "Tom", "text": "And today's topic touches almost every family, sooner or later.", "t": 21.01}, {"speaker": "Tom", "text": "It's about growing older — and about a service that helps you find the right support.", "t": 24.23}, {"speaker": "Tom", "text": "It's called Info-Seniors.", "t": 27.81}, {"speaker": "Anna", "text": "Info-Seniors.", "t": 29.38}, {"speaker": "Anna", "text": "Okay, Tom, let's start simply.", "t": 30.71}, {"speaker": "Anna", "text": "What is it?", "t": 33.4}, {"speaker": "Tom", "text": "So, Info-Seniors is the official information service for older people in Luxembourg.", "t": 34.59}, {"speaker": "Tom", "text": "Its home on the internet is a website — infosenior dot l-u.", "t": 38.91}, {"speaker": "Anna", "text": "infosenior.lu.", "t": 42.12}, {"speaker": "Anna", "text": "And who is behind it?", "t": 43.66}, {"speaker": "Tom", "text": "It's run by the State — by the Ministry of Family.", "t": 45.23}, {"speaker": "Tom", "text": "So it's an official, public source.", "t": 47.55}, {"speaker": "Tom", "text": "Not a private company trying to sell you something.", "t": 49.34}, {"speaker": "Anna", "text": "Good to know.", "t": 51.58}, {"speaker": "Anna", "text": "And who is it for?", "t": 52.57}, {"speaker": "Anna", "text": "Only for older people themselves?", "t": 53.93}, {"speaker": "Tom", "text": "No, and this is important.", "t": 56.38}, {"speaker": "Tom", "text": "It's for seniors, yes — but also for their families, for the professionals who work with them, and really, for anyone interested.", "t": 57.79}, {"speaker": "Tom", "text": "So if you are worried about an ageing parent, or a neighbour, this is for you too.", "t": 63.48}, {"speaker": "Anna", "text": "That's reassuring.", "t": 67.34}, {"speaker": "Anna", "text": "Because often it's the children, or the family, who go looking for help.", "t": 68.71}, {"speaker": "Tom", "text": "Exactly.", "t": 72.83}, {"speaker": "Tom", "text": "Especially for cross-border workers — maybe your parents live in another country, and you want to understand what exists here.", "t": 73.62}, {"speaker": "Tom", "text": "Or the opposite — you work here, and you're arranging help for a parent in Luxembourg.", "t": 79.17}, {"speaker": "Anna", "text": "So, what do you actually find on the website?", "t": 83.22}, {"speaker": "Anna", "text": "What's the heart of it?", "t": 86.35}, {"speaker": "Tom", "text": "The heart of it is something called the Public Register of Services for Seniors.", "t": 87.78}, {"speaker": "Anna", "text": "A register.", "t": 91.57}, {"speaker": "Anna", "text": "That sounds official.", "t": 92.65}, {"speaker": "Anna", "text": "What's inside?", "t": 94.19}, {"speaker": "Tom", "text": "It's a complete, reliable list of the services and structures for older people in Luxembourg.", "t": 95.59}, {"speaker": "Tom", "text": "For each one, you find detailed information — what the service is, the conditions to use it, and the steps you have to take.", "t": 100.16}, {"speaker": "Anna", "text": "So not just a name and a phone number.", "t": 105.89}, {"speaker": "Anna", "text": "It tells me how to actually get the help.", "t": 108.57}, {"speaker": "Tom", "text": "Exactly.", "t": 111.4}, {"speaker": "Tom", "text": "What it is, who can use it, and how to start.", "t": 112.16}, {"speaker": "Tom", "text": "That's the useful part.", "t": 114.41}, {"speaker": "Anna", "text": "Now you said \"register\" and \"official\".", "t": 115.72}, {"speaker": "Anna", "text": "Is there something special about which services are listed?", "t": 117.93}, {"speaker": "Tom", "text": "Yes — and this is really the key point.", "t": 121.43}, {"speaker": "Tom", "text": "The register only lists services that are approved by the State.", "t": 123.38}, {"speaker": "Tom", "text": "In French, we say they have an \"agrément\".", "t": 126.28}, {"speaker": "Anna", "text": "An agrément.", "t": 128.38}, {"speaker": "Anna", "text": "So, an official authorisation.", "t": 129.53}, {"speaker": "Tom", "text": "Right.", "t": 132.0}, {"speaker": "Tom", "text": "In Luxembourg, anyone who offers care, accommodation, help or guidance to older people must have this approval from the Ministry.", "t": 132.45}, {"speaker": "Tom", "text": "To get it, they have to meet quality requirements.", "t": 138.78}, {"speaker": "Tom", "text": "And the Ministry carries out regular checks.", "t": 141.04}, {"speaker": "Anna", "text": "So if a service is in the register...", "t": 143.19}, {"speaker": "Tom", "text": "...it has been checked and approved by the State.", "t": 145.71}, {"speaker": "Tom", "text": "That's a real guarantee of quality.", "t": 147.64}, {"speaker": "Tom", "text": "You're not picking a name at random from the internet.", "t": 149.53}, {"speaker": "Anna", "text": "That's a big deal, especially for something as sensitive as caring for a parent.", "t": 152.08}, {"speaker": "Anna", "text": "And how recent is this register?", "t": 156.49}, {"speaker": "Tom", "text": "It's built on a law that's in force since the first of March, 2024.", "t": 158.74}, {"speaker": "Tom", "text": "And it's updated regularly, so the information stays reliable and up to date.", "t": 162.58}, {"speaker": "Anna", "text": "Perfect.", "t": 166.37}, {"speaker": "Anna", "text": "Okay, Tom — let's get concrete.", "t": 167.2}, {"speaker": "Anna", "text": "What kind of services can I find there?", "t": 169.81}, {"speaker": "Tom", "text": "A whole range, for every level of need.", "t": 172.58}, {"speaker": "Tom", "text": "Let me go through the main ones.", "t": 174.79}, {"speaker": "Tom", "text": "First — care homes, the residential structures, for people who can no longer live at home.", "t": 176.22}, {"speaker": "Anna", "text": "Okay, the classic retirement or care home.", "t": 180.72}, {"speaker": "Tom", "text": "Yes.", "t": 183.64}, {"speaker": "Tom", "text": "Then — assisted living, where you have your own home but with support and security nearby.", "t": 183.98}, {"speaker": "Tom", "text": "Then — day care centres, where a senior can spend the day, with activities and company, and go home in the evening.", "t": 188.15}, {"speaker": "Anna", "text": "Ah, that's nice for someone who's still at home but shouldn't be alone all day.", "t": 194.07}, {"speaker": "Tom", "text": "Exactly.", "t": 198.74}, {"speaker": "Tom", "text": "And it also gives the family a break.", "t": 199.51}, {"speaker": "Tom", "text": "Then there's help at home — household help, and nursing care that comes to you.", "t": 201.26}, {"speaker": "Tom", "text": "There's \"meals on wheels\" — warm meals delivered to your door.", "t": 204.57}, {"speaker": "Anna", "text": "Meals on wheels.", "t": 207.62}, {"speaker": "Anna", "text": "That's a lovely, practical one.", "t": 209.28}, {"speaker": "Tom", "text": "And there's telecare — sometimes called a telealarm.", "t": 211.46}, {"speaker": "Tom", "text": "It's a little device, often a button you wear, that lets you call for help immediately if you fall or feel unwell.", "t": 213.89}, {"speaker": "Anna", "text": "So you can stay at home, but with a safety net.", "t": 219.14}, {"speaker": "Anna", "text": "That gives real peace of mind.", "t": 222.14}, {"speaker": "Tom", "text": "That's the idea.", "t": 224.55}, {"speaker": "Tom", "text": "The goal of all of this — and it's the goal of the whole national policy — is to let people stay independent, at home, for as long as possible.", "t": 225.51}, {"speaker": "Anna", "text": "And you mentioned activities too?", "t": 232.45}, {"speaker": "Tom", "text": "Yes.", "t": 234.53}, {"speaker": "Tom", "text": "Beyond care, there are senior activities — for staying active, learning, and meeting people.", "t": 234.84}, {"speaker": "Tom", "text": "For example, there are the Clubs Aktiv Plus, the senior clubs all around the country, where older people meet, do activities, and stay connected.", "t": 239.5}, {"speaker": "Anna", "text": "Because staying active and social is part of staying healthy.", "t": 246.29}, {"speaker": "Tom", "text": "Completely.", "t": 250.01}, {"speaker": "Tom", "text": "Loneliness is a real risk as we age.", "t": 250.76}, {"speaker": "Tom", "text": "And that's one of the things the system tries hard to prevent.", "t": 252.97}, {"speaker": "Anna", "text": "Speaking of which — are there services for more specific situations?", "t": 255.55}, {"speaker": "Anna", "text": "Not everyone has the same needs.", "t": 259.74}, {"speaker": "Tom", "text": "Yes, and the website points you to specialised services too.", "t": 262.13}, {"speaker": "Tom", "text": "Let me give a few examples.", "t": 265.21}, {"speaker": "Tom", "text": "For memory problems and dementia, there's a national information centre — the Info-Zenter Demenz.", "t": 266.59}, {"speaker": "Tom", "text": "And there's the Alzheimer association, which even runs a help line, available around the clock, for urgent situations.", "t": 271.27}, {"speaker": "Anna", "text": "A 24-hour line for Alzheimer — that's so important for families in distress.", "t": 277.47}, {"speaker": "Tom", "text": "It really is.", "t": 282.67}, {"speaker": "Tom", "text": "Then, for the digital world — there's an organisation that helps seniors learn to use computers and smartphones, so they're not left behind.", "t": 283.46}, {"speaker": "Tom", "text": "For loneliness, there's a service of the Red Cross, where trained volunteers regularly visit isolated people.", "t": 289.85}, {"speaker": "Anna", "text": "Just to keep them company.", "t": 294.97}, {"speaker": "Anna", "text": "That's beautiful.", "t": 296.74}, {"speaker": "Tom", "text": "It is.", "t": 298.1}, {"speaker": "Tom", "text": "And for very difficult moments — there's palliative care and end-of-life support, and there's information about your rights and wishes for the end of life.", "t": 298.46}, {"speaker": "Tom", "text": "So the system covers the whole journey, with respect.", "t": 305.01}, {"speaker": "Anna", "text": "That's a caring approach.", "t": 307.81}, {"speaker": "Anna", "text": "And is there a place that works on the knowledge itself — research, training for the people who care?", "t": 309.47}, {"speaker": "Tom", "text": "Yes.", "t": 314.91}, {"speaker": "Tom", "text": "There's a competence centre for ageing that has existed for about thirty years.", "t": 315.23}, {"speaker": "Tom", "text": "It does three things — activities and learning for seniors, continuing education for care professionals, and research on ageing.", "t": 319.01}, {"speaker": "Tom", "text": "So the quality keeps improving over time.", "t": 324.96}, {"speaker": "Anna", "text": "So it's not standing still.", "t": 327.19}, {"speaker": "Anna", "text": "Good.", "t": 329.26}, {"speaker": "Anna", "text": "Tom, let's make this very real.", "t": 330.08}, {"speaker": "Anna", "text": "Can we take an example?", "t": 332.48}, {"speaker": "Tom", "text": "Of course.", "t": 334.19}, {"speaker": "Tom", "text": "Let's imagine your mother is eighty, she lives alone, and she's still quite independent — but you're starting to worry a little.", "t": 334.92}, {"speaker": "Anna", "text": "A very common situation.", "t": 340.67}, {"speaker": "Anna", "text": "So what does Info-Seniors do for me?", "t": 342.51}, {"speaker": "Tom", "text": "You go to the website, and you look at what fits.", "t": 345.11}, {"speaker": "Tom", "text": "Maybe, first, just meals on wheels, so she eats well every day.", "t": 347.28}, {"speaker": "Tom", "text": "Maybe a telecare button, for safety, in case she falls.", "t": 351.19}, {"speaker": "Tom", "text": "Maybe a Club Aktiv Plus nearby, so she sees people every week.", "t": 354.3}, {"speaker": "Anna", "text": "So I can build a kind of package — a little help here, a little there — to keep her safely at home.", "t": 357.78}, {"speaker": "Tom", "text": "Exactly.", "t": 363.97}, {"speaker": "Tom", "text": "And later, if she needs more, you already know where to look — day care a few days a week, then more home nursing, and only much later, if needed, a care home.", "t": 364.71}, {"speaker": "Tom", "text": "Step by step, at her pace.", "t": 372.55}, {"speaker": "Anna", "text": "And for each of those, the register tells me the conditions and the steps.", "t": 374.53}, {"speaker": "Tom", "text": "For each one.", "t": 378.96}, {"speaker": "Tom", "text": "So instead of panicking, you have a calm, clear map.", "t": 379.65}, {"speaker": "Anna", "text": "I really like that — a calm, clear map.", "t": 382.64}, {"speaker": "Anna", "text": "And if my mother doesn't speak much, or is afraid of technology?", "t": 385.54}, {"speaker": "Tom", "text": "Then the digital-skills service can help her learn, gently.", "t": 389.47}, {"speaker": "Tom", "text": "Or a volunteer can visit.", "t": 392.21}, {"speaker": "Tom", "text": "The point is, there's almost always something — you just have to know it exists.", "t": 393.64}, {"speaker": "Tom", "text": "And that's exactly what the portal is for — so you know it exists.", "t": 397.02}, {"speaker": "Anna", "text": "Now, Tom — a practical worry.", "t": 400.33}, {"speaker": "Anna", "text": "What if I have a problem with a service?", "t": 402.62}, {"speaker": "Anna", "text": "Or I just don't know who to ask?", "t": 405.06}, {"speaker": "Tom", "text": "Good question.", "t": 407.45}, {"speaker": "Tom", "text": "There is a national service for information and mediation in this field.", "t": 408.16}, {"speaker": "Tom", "text": "So if you need to be guided, or if there's a disagreement with a service, there's a neutral place that can help you find a solution.", "t": 411.41}, {"speaker": "Anna", "text": "So you're never completely on your own with it.", "t": 416.97}, {"speaker": "Tom", "text": "Never.", "t": 419.78}, {"speaker": "Tom", "text": "Between the website, the register, and that information and mediation service, there's always a door to knock on.", "t": 420.32}, {"speaker": "Anna", "text": "Let's zoom out for a second.", "t": 425.94}, {"speaker": "Anna", "text": "You said this is part of a bigger policy.", "t": 427.91}, {"speaker": "Anna", "text": "What's the big idea?", "t": 430.47}, {"speaker": "Tom", "text": "The big idea is what they call \"ageing well\".", "t": 431.99}, {"speaker": "Tom", "text": "The State wants older people to live as independently as possible, for as long as possible — and to stay part of society, not pushed to the side.", "t": 434.2}, {"speaker": "Tom", "text": "So the work covers many things — preparing for retirement, lifelong learning, volunteering, fighting isolation, the digital world, and connecting the generations.", "t": 441.13}, {"speaker": "Anna", "text": "Connecting the generations — young and old together.", "t": 449.27}, {"speaker": "Tom", "text": "Yes.", "t": 452.53}, {"speaker": "Tom", "text": "Ageing isn't only about care.", "t": 452.87}, {"speaker": "Tom", "text": "It's also about staying active, useful, and connected.", "t": 454.51}, {"speaker": "Tom", "text": "And there's also financial support — for people who don't have enough money to cover the cost of care, the State helps.", "t": 457.34}, {"speaker": "Anna", "text": "That's important — that money shouldn't be the barrier to getting care.", "t": 462.5}, {"speaker": "Anna", "text": "Okay, Tom, let's make it really practical.", "t": 466.2}, {"speaker": "Anna", "text": "If I'm listening, and I — or my parent — might need some help, what do I do?", "t": 469.31}, {"speaker": "Tom", "text": "Very simple.", "t": 474.22}, {"speaker": "Tom", "text": "Go to the website — infosenior dot l-u.", "t": 475.01}, {"speaker": "Tom", "text": "Look through the Public Register to find approved services — a care home, day care, help at home, meals, telecare — whatever fits the need.", "t": 477.32}, {"speaker": "Tom", "text": "For each one, you'll see what it is, the conditions, and the steps to take.", "t": 484.18}, {"speaker": "Tom", "text": "And if you're not sure, use the information and mediation service to be guided.", "t": 487.52}, {"speaker": "Anna", "text": "And because it's official, I can trust what I find there.", "t": 491.22}, {"speaker": "Tom", "text": "Exactly.", "t": 494.79}, {"speaker": "Tom", "text": "Official, free, and quality-checked.", "t": 495.61}, {"speaker": "Tom", "text": "That's the whole point.", "t": 497.84}, {"speaker": "Anna", "text": "Short summary to finish?", "t": 498.99}, {"speaker": "Tom", "text": "Sure.", "t": 500.79}, {"speaker": "Tom", "text": "Info-Seniors, on infosenior dot l-u, is the State's information portal for older people in Luxembourg.", "t": 501.18}, {"speaker": "Tom", "text": "Its heart is the Public Register of Services for Seniors — a reliable, regularly updated list of services approved and checked by the Ministry.", "t": 504.49}, {"speaker": "Tom", "text": "You'll find care homes, assisted living, day care, home help and nursing, meals on wheels, telecare, and senior activities — with the conditions and the steps for each.", "t": 511.54}, {"speaker": "Anna", "text": "And the message for today?", "t": 519.67}, {"speaker": "Tom", "text": "When it comes to growing older — yours, or a loved one's — you don't have to search blindly.", "t": 521.42}, {"speaker": "Tom", "text": "There's one official, trustworthy place to start, and there's help to guide you.", "t": 525.54}, {"speaker": "Anna", "text": "So...", "t": 529.04}, {"speaker": "Anna", "text": "whether it's for yourself, your parents, or a neighbour — remember the name.", "t": 529.72}, {"speaker": "Anna", "text": "Info-Seniors.", "t": 533.77}, {"speaker": "Anna", "text": "infosenior.lu.", "t": 535.09}, {"speaker": "Tom", "text": "Really.", "t": 536.76}, {"speaker": "Tom", "text": "One website, and a whole network of support behind it.", "t": 537.23}, {"speaker": "Anna", "text": "That was our episode about Info-Seniors, part of the Biergerpakt — living together in Luxembourg, discovering the country, and looking out for each other.", "t": 540.16}, {"speaker": "Anna", "text": "Thank you so much for listening.", "t": 548.65}, {"speaker": "Tom", "text": "Thank you, everyone.", "t": 550.62}, {"speaker": "Tom", "text": "Take care...", "t": 551.88}, {"speaker": "Tom", "text": "and see you next time!", "t": 552.61}, {"speaker": "Anna", "text": "Bye bye!", "t": 553.82}], "questions": [{"text": "What is Info-Seniors (infosenior.lu)?", "options": ["A private retirement-home chain", "The State's official information portal for older people in Luxembourg, run by the Ministry of Family", "A pension savings account", "A social network for retirees"], "correct": 1, "explanation": "Info-Seniors, at infosenior.lu, is the official public information portal for older people, run by the Ministry of Family Affairs – not a private company. It is for seniors, their families, professionals and anyone interested."}, {"text": "What is special about the services listed in the Public Register of Services for Seniors?", "options": ["Anyone can add their own service to the list", "They are only services located in Luxembourg City", "They are all approved (“agréé”) by the State and subject to regular quality checks", "They are ranked by price only"], "correct": 2, "explanation": "The register lists only services approved by the Ministry (with an “agrément”). To be approved, providers must meet quality requirements, and the Ministry carries out regular checks – so a listed service has been vetted by the State. The register is based on the law in force since 1 March 2024 and is updated regularly."}, {"text": "For each service, what information does the register give you?", "options": ["What the service is, the conditions to use it, and the steps to take", "Only a phone number", "Only customer reviews", "Nothing – you must visit in person to learn anything"], "correct": 0, "explanation": "For every approved service the register explains what it is, the conditions for accessing it, and the steps to take – so you know not just the name, but how to actually obtain the help."}, {"text": "Which of these is an example of a service you can find through Info-Seniors?", "options": ["Free flight tickets for retirees", "A tax-free shopping card", "Telecare (a call-for-help button) and meals on wheels delivered to your home", "A car-leasing discount"], "correct": 2, "explanation": "The register covers care homes, assisted living, day care centres, home help and nursing, meals on wheels, telecare (a telealarm button), and senior activities such as the Clubs Aktiv Plus – all aimed at helping people stay independent at home as long as possible."}, {"text": "If you don't know who to ask, or you have a disagreement with a service, what can help?", "options": ["Nothing – you are on your own", "Only a private lawyer", "You must move to a care home first", "A national information and mediation service that can guide you and help find a solution"], "correct": 3, "explanation": "Besides the website and the register, there is a national information and mediation service for the field of services for older people. It can guide you and help resolve a disagreement with a service – so you are never left on your own."}]}, {"id": 9, "key": "accessibilite", "number": "Episode 9", "title": "Accessibility for Everyone – Luxembourg’s Three Promises", "description": "What accessibilite.lu is and the three areas it brings together: digital accessibility of public websites and apps (Law of 28 May 2019), accessible buildings, streets and housing through universal design (Law of 7 January 2022), and accessible products and services under the European Accessibility Act (applicable since 28 June 2025, monitored by OSAPS).", "audio": "podcast_accessibilite.mp3", "duration": 900.74, "topics": ["The accessibilite.lu hub", "Digital accessibility (Law of 2019)", "Perceivable, operable, understandable, robust", "Accessibility declarations & complaints", "Infrastructure & universal design", "Deadline of 2032 for existing places", "Products & services (European Accessibility Act)", "OSAPS & reporting via MyGuichet.lu"], "segments": [{"speaker": "Anna", "text": "Hello, and welcome!", "t": 0.0}, {"speaker": "Anna", "text": "It's really nice to have you with us today.", "t": 2.44}, {"speaker": "Tom", "text": "Hello everyone!", "t": 5.41}, {"speaker": "Anna", "text": "This episode is part of the Biergerpakt.", "t": 7.4}, {"speaker": "Anna", "text": "That's a programme of living together in Luxembourg.", "t": 10.46}, {"speaker": "Anna", "text": "The idea is simple... we want to help residents, and also cross-border workers, to discover Luxembourg — or re-discover it — and to meet new people.", "t": 14.0}, {"speaker": "Tom", "text": "Exactly.", "t": 23.25}, {"speaker": "Tom", "text": "And today's topic is one that touches every single one of us, sooner or later.", "t": 25.15}, {"speaker": "Tom", "text": "It's about accessibility.", "t": 30.16}, {"speaker": "Anna", "text": "Accessibility.", "t": 32.8}, {"speaker": "Anna", "text": "Okay, Tom — that's a big word.", "t": 34.87}, {"speaker": "Anna", "text": "What do we actually mean by it?", "t": 38.04}, {"speaker": "Tom", "text": "Good question.", "t": 40.74}, {"speaker": "Tom", "text": "Accessibility means making the world usable by everyone — including people with a disability.", "t": 42.62}, {"speaker": "Tom", "text": "A person in a wheelchair, a person who can't see well, a person who can't hear well, an older person who's a bit slower than before.", "t": 48.64}, {"speaker": "Anna", "text": "So it's about removing barriers.", "t": 56.39}, {"speaker": "Tom", "text": "Exactly.", "t": 59.17}, {"speaker": "Tom", "text": "And here's the key idea — and it comes from the World Health Organization.", "t": 61.08}, {"speaker": "Tom", "text": "Disability isn't only a health problem.", "t": 65.64}, {"speaker": "Tom", "text": "It comes from the meeting between a person and the world around them.", "t": 68.89}, {"speaker": "Tom", "text": "If the world is built badly, the person is disabled by it.", "t": 73.09}, {"speaker": "Tom", "text": "If the world is built well, the barrier disappears.", "t": 77.2}, {"speaker": "Anna", "text": "Ah, I like that.", "t": 81.07}, {"speaker": "Anna", "text": "So the problem isn't always the person — it's often the building, or the website, or the machine.", "t": 83.4}, {"speaker": "Tom", "text": "Precisely.", "t": 89.57}, {"speaker": "Tom", "text": "And that's why Luxembourg has built an official place online to bring it all together — a website called accessibilite dot l-u.", "t": 91.48}, {"speaker": "Anna", "text": "accessibilite.lu.", "t": 98.59}, {"speaker": "Anna", "text": "And who is behind it?", "t": 101.41}, {"speaker": "Tom", "text": "It's the State — the Government of Luxembourg.", "t": 103.59}, {"speaker": "Tom", "text": "So it's official, public information.", "t": 106.93}, {"speaker": "Tom", "text": "And the website is a kind of front door, that opens onto three big areas.", "t": 110.16}, {"speaker": "Anna", "text": "Three areas.", "t": 115.05}, {"speaker": "Anna", "text": "Okay, let's take them one by one.", "t": 117.08}, {"speaker": "Anna", "text": "What's the first?", "t": 120.14}, {"speaker": "Tom", "text": "The first is digital accessibility.", "t": 122.13}, {"speaker": "Tom", "text": "That means websites and mobile apps.", "t": 125.3}, {"speaker": "Tom", "text": "Making them usable for people with a disability.", "t": 128.34}, {"speaker": "Anna", "text": "So, the online world.", "t": 132.06}, {"speaker": "Tom", "text": "Yes.", "t": 134.74}, {"speaker": "Tom", "text": "Think about it — today you do so much online.", "t": 136.36}, {"speaker": "Tom", "text": "You check your taxes, you book an appointment, you read the news.", "t": 139.76}, {"speaker": "Tom", "text": "Now imagine you're blind, and you use a screen reader — a programme that reads the page out loud.", "t": 144.05}, {"speaker": "Tom", "text": "If the website is built badly, the screen reader gets lost, and you're stuck.", "t": 149.57}, {"speaker": "Anna", "text": "And you can't do the simple thing everyone else does easily.", "t": 154.56}, {"speaker": "Tom", "text": "Right.", "t": 158.35}, {"speaker": "Tom", "text": "So Luxembourg passed a law — it's from the 28th of May, 2019.", "t": 159.95}, {"speaker": "Tom", "text": "And it says that public sector websites and apps — the State, the communes, public bodies — must be accessible.", "t": 165.11}, {"speaker": "Anna", "text": "So the official, public websites have a duty to be usable by everyone.", "t": 171.86}, {"speaker": "Tom", "text": "They have a legal duty.", "t": 176.79}, {"speaker": "Tom", "text": "And there's a simple way to remember what \"accessible\" means here.", "t": 179.12}, {"speaker": "Tom", "text": "Four words.", "t": 183.31}, {"speaker": "Tom", "text": "The content must be perceivable, operable, understandable, and robust.", "t": 185.28}, {"speaker": "Anna", "text": "Let's unpack those, slowly.", "t": 190.53}, {"speaker": "Tom", "text": "Sure.", "t": 193.35}, {"speaker": "Tom", "text": "Perceivable — you can perceive it.", "t": 194.98}, {"speaker": "Tom", "text": "For example, every image has a text description, so a screen reader can describe it.", "t": 197.8}, {"speaker": "Tom", "text": "Operable — you can operate it.", "t": 203.33}, {"speaker": "Tom", "text": "For example, you can use the whole site with just a keyboard, not only a mouse.", "t": 206.11}, {"speaker": "Anna", "text": "Because some people can't use a mouse.", "t": 211.38}, {"speaker": "Tom", "text": "Exactly.", "t": 214.29}, {"speaker": "Tom", "text": "Understandable — the page behaves in a clear, predictable way, and helps you fix mistakes.", "t": 216.19}, {"speaker": "Tom", "text": "And robust — it works with assistive technologies, today and in the future.", "t": 222.08}, {"speaker": "Anna", "text": "Perceivable, operable, understandable, robust.", "t": 227.2}, {"speaker": "Anna", "text": "That's a nice checklist.", "t": 231.31}, {"speaker": "Anna", "text": "And how do we know if a website actually follows the rules?", "t": 233.69}, {"speaker": "Tom", "text": "Each public website must publish what's called an accessibility declaration.", "t": 237.6}, {"speaker": "Tom", "text": "It's an honest statement that says — we are fully compliant, partly compliant, or not compliant.", "t": 242.57}, {"speaker": "Tom", "text": "And it lists the problems that still exist.", "t": 248.67}, {"speaker": "Anna", "text": "So it's transparent.", "t": 252.04}, {"speaker": "Anna", "text": "They have to admit what's not perfect yet.", "t": 254.28}, {"speaker": "Tom", "text": "Exactly.", "t": 257.43}, {"speaker": "Tom", "text": "And — this is important — if you find a problem, you can complain.", "t": 259.33}, {"speaker": "Tom", "text": "Every site must give you a way to report a barrier.", "t": 263.68}, {"speaker": "Tom", "text": "They have to answer you, normally within one month.", "t": 267.34}, {"speaker": "Tom", "text": "And if you're not satisfied, you can turn to the State information service, or even the ombudsman — the médiateur.", "t": 270.89}, {"speaker": "Anna", "text": "So you're not powerless.", "t": 277.73}, {"speaker": "Anna", "text": "If a public website blocks you, there's a door to knock on.", "t": 280.06}, {"speaker": "Tom", "text": "Always.", "t": 284.15}, {"speaker": "Tom", "text": "That's the whole point.", "t": 285.9}, {"speaker": "Tom", "text": "Okay — shall we go to the second area?", "t": 288.17}, {"speaker": "Anna", "text": "Yes please.", "t": 291.25}, {"speaker": "Anna", "text": "We've done the digital world.", "t": 293.2}, {"speaker": "Anna", "text": "What's next?", "t": 295.61}, {"speaker": "Tom", "text": "The second area is infrastructure.", "t": 297.5}, {"speaker": "Tom", "text": "That means the physical world — buildings, public spaces, and streets.", "t": 300.66}, {"speaker": "Anna", "text": "Ah, the concrete world.", "t": 305.59}, {"speaker": "Anna", "text": "Ramps, doors, lifts.", "t": 308.2}, {"speaker": "Tom", "text": "Exactly.", "t": 311.11}, {"speaker": "Tom", "text": "Can you enter the building?", "t": 313.01}, {"speaker": "Tom", "text": "Is there a ramp as well as steps?", "t": 315.3}, {"speaker": "Tom", "text": "Is the door wide enough for a wheelchair?", "t": 318.09}, {"speaker": "Tom", "text": "Is there a lift?", "t": 321.13}, {"speaker": "Tom", "text": "Are there things to help a blind person find their way?", "t": 323.09}, {"speaker": "Anna", "text": "And is there a law for this too?", "t": 326.58}, {"speaker": "Tom", "text": "There is.", "t": 329.11}, {"speaker": "Tom", "text": "It's the law of the 7th of January, 2022, and it came into force on the 1st of July, 2023.", "t": 330.9}, {"speaker": "Tom", "text": "And it's built on a beautiful idea called universal design.", "t": 338.16}, {"speaker": "Anna", "text": "Universal design.", "t": 342.4}, {"speaker": "Anna", "text": "What does that mean?", "t": 344.56}, {"speaker": "Tom", "text": "It means designing a place, from the very start, so that everyone can use it.", "t": 346.53}, {"speaker": "Tom", "text": "Not a special side entrance for some people, and the main entrance for the others.", "t": 351.63}, {"speaker": "Tom", "text": "One place, that works for all.", "t": 356.47}, {"speaker": "Anna", "text": "So instead of building a barrier and then fixing it later...", "t": 359.4}, {"speaker": "Tom", "text": "...you build it right the first time.", "t": 363.4}, {"speaker": "Tom", "text": "And here's the clever part — it's actually cheaper.", "t": 366.12}, {"speaker": "Tom", "text": "The United Nations says it: if you design for everyone from the beginning, it costs much less than removing barriers from a building that's already finished.", "t": 369.68}, {"speaker": "Anna", "text": "That makes complete sense.", "t": 377.99}, {"speaker": "Anna", "text": "It's harder and more expensive to add a lift to an old building than to plan it from day one.", "t": 380.53}, {"speaker": "Tom", "text": "Exactly.", "t": 386.06}, {"speaker": "Tom", "text": "And the new law goes further than the old one.", "t": 387.96}, {"speaker": "Tom", "text": "It's not only about public buildings.", "t": 391.15}, {"speaker": "Tom", "text": "It also covers public roads, and collective housing — buildings with many homes inside.", "t": 394.21}, {"speaker": "Anna", "text": "And for buildings that already exist?", "t": 399.82}, {"speaker": "Anna", "text": "You can't rebuild everything overnight.", "t": 402.86}, {"speaker": "Tom", "text": "No, and the law is realistic.", "t": 405.84}, {"speaker": "Tom", "text": "New buildings and big renovations must follow the rules now.", "t": 408.9}, {"speaker": "Tom", "text": "But for places that already exist and are open to the public, there's a deadline to become accessible — the 1st of January, 2032.", "t": 412.9}, {"speaker": "Anna", "text": "So there's time, but there's also a clear target.", "t": 421.08}, {"speaker": "Anna", "text": "Good.", "t": 424.7}, {"speaker": "Anna", "text": "And who can help with all this — for someone building or renovating?", "t": 426.2}, {"speaker": "Tom", "text": "The infrastructure portal on accessibilite.lu has the rules, the procedures, and a toolbox.", "t": 430.48}, {"speaker": "Tom", "text": "So an architect, a commune, or an owner can find what they need to do it right.", "t": 436.86}, {"speaker": "Anna", "text": "Lovely.", "t": 441.87}, {"speaker": "Anna", "text": "Okay, Tom — that's digital, and infrastructure.", "t": 443.56}, {"speaker": "Anna", "text": "What's the third area?", "t": 447.76}, {"speaker": "Tom", "text": "The third one is the newest, and maybe the most surprising.", "t": 449.94}, {"speaker": "Tom", "text": "It's the accessibility of products and services.", "t": 453.88}, {"speaker": "Anna", "text": "Products and services.", "t": 457.69}, {"speaker": "Anna", "text": "Now that sounds very broad.", "t": 459.96}, {"speaker": "Anna", "text": "What does it include?", "t": 462.46}, {"speaker": "Tom", "text": "A lot of everyday things.", "t": 464.58}, {"speaker": "Tom", "text": "Think about a bank machine — an ATM.", "t": 467.04}, {"speaker": "Tom", "text": "A ticket machine at the station.", "t": 470.31}, {"speaker": "Tom", "text": "An online shop.", "t": 473.05}, {"speaker": "Tom", "text": "A banking app.", "t": 475.21}, {"speaker": "Tom", "text": "An e-book.", "t": 477.16}, {"speaker": "Tom", "text": "Smartphones and computers.", "t": 479.0}, {"speaker": "Tom", "text": "These are the products and services we all use, all the time.", "t": 481.65}, {"speaker": "Anna", "text": "And the idea is they should work for people with a disability too.", "t": 485.91}, {"speaker": "Tom", "text": "Exactly.", "t": 490.11}, {"speaker": "Tom", "text": "This comes from a European law — people call it the European Accessibility Act.", "t": 492.01}, {"speaker": "Tom", "text": "Luxembourg put it into national law with the law of the 8th of March, 2023.", "t": 497.11}, {"speaker": "Tom", "text": "And it started to apply on the 28th of June, 2025.", "t": 502.57}, {"speaker": "Anna", "text": "So this one is very recent — it's basically just begun.", "t": 507.2}, {"speaker": "Tom", "text": "Just begun.", "t": 511.37}, {"speaker": "Tom", "text": "And it's a real change.", "t": 513.27}, {"speaker": "Tom", "text": "For the first time, it's not only the State that has duties — it's private companies too.", "t": 515.61}, {"speaker": "Anna", "text": "Ah, so businesses now have to think about accessibility.", "t": 520.85}, {"speaker": "Tom", "text": "Yes.", "t": 524.96}, {"speaker": "Tom", "text": "If you make or sell certain products and services, they have to be accessible.", "t": 526.59}, {"speaker": "Tom", "text": "Now — there's an exception for the very small businesses.", "t": 531.51}, {"speaker": "Tom", "text": "Roughly speaking, the rules focus on companies with more than ten employees and a certain size of turnover.", "t": 535.39}, {"speaker": "Tom", "text": "So the tiny shop on the corner isn't treated the same as a big bank.", "t": 541.73}, {"speaker": "Anna", "text": "That seems fair.", "t": 546.44}, {"speaker": "Anna", "text": "And who keeps an eye on all this?", "t": 548.58}, {"speaker": "Tom", "text": "There's a new office for exactly this.", "t": 551.12}, {"speaker": "Tom", "text": "In short it's called OSAPS — the office that watches over the accessibility of products and services.", "t": 554.16}, {"speaker": "Tom", "text": "It does two jobs.", "t": 560.1}, {"speaker": "Tom", "text": "It checks that products and services on the market follow the rules.", "t": 562.32}, {"speaker": "Tom", "text": "And it helps businesses — with guides, tools, and advice — to get it right.", "t": 566.58}, {"speaker": "Anna", "text": "So it's not only a police officer.", "t": 571.49}, {"speaker": "Anna", "text": "It's also a helper.", "t": 574.42}, {"speaker": "Tom", "text": "Both.", "t": 576.6}, {"speaker": "Tom", "text": "Carrot and stick.", "t": 578.16}, {"speaker": "Tom", "text": "And here's the part for us, the citizens — if you find a product or a service that isn't accessible, you can report it.", "t": 580.24}, {"speaker": "Anna", "text": "How do I do that?", "t": 587.05}, {"speaker": "Tom", "text": "Online, through MyGuichet.lu — the State's digital platform.", "t": 589.1}, {"speaker": "Tom", "text": "And you can even do it without logging in, if you prefer.", "t": 593.7}, {"speaker": "Tom", "text": "So it's easy to raise your hand and say — this machine, this service, doesn't work for me.", "t": 597.75}, {"speaker": "Anna", "text": "I love that the three areas connect like that.", "t": 602.91}, {"speaker": "Anna", "text": "You report a faulty product through a public website... which itself has to be accessible... in a building that should also be accessible.", "t": 606.25}, {"speaker": "Tom", "text": "Exactly.", "t": 614.2}, {"speaker": "Tom", "text": "It's one big circle.", "t": 616.1}, {"speaker": "Tom", "text": "Digital, infrastructure, products and services.", "t": 618.52}, {"speaker": "Tom", "text": "Three promises, one goal.", "t": 622.52}, {"speaker": "Anna", "text": "Let's make it really concrete, Tom.", "t": 625.39}, {"speaker": "Anna", "text": "Can we follow one person through a normal day?", "t": 628.47}, {"speaker": "Tom", "text": "Of course.", "t": 631.55}, {"speaker": "Tom", "text": "Let's imagine someone — let's call her Maria.", "t": 633.35}, {"speaker": "Tom", "text": "Maria has low vision.", "t": 636.82}, {"speaker": "Tom", "text": "She doesn't see well.", "t": 639.21}, {"speaker": "Anna", "text": "Okay.", "t": 641.52}, {"speaker": "Anna", "text": "Maria wakes up.", "t": 643.13}, {"speaker": "Anna", "text": "What's her day like, in a fully accessible Luxembourg?", "t": 645.25}, {"speaker": "Tom", "text": "She picks up her phone to check an official document.", "t": 649.12}, {"speaker": "Tom", "text": "The public website is built well — so her screen reader reads it out clearly.", "t": 652.78}, {"speaker": "Tom", "text": "That's the digital part.", "t": 657.58}, {"speaker": "Anna", "text": "Good.", "t": 660.0}, {"speaker": "Anna", "text": "Then she goes out.", "t": 661.49}, {"speaker": "Tom", "text": "She walks to the commune office.", "t": 663.57}, {"speaker": "Tom", "text": "The street has guidance she can feel under her feet, the building has a clear entrance, and a lift inside.", "t": 666.35}, {"speaker": "Tom", "text": "That's the infrastructure part.", "t": 672.47}, {"speaker": "Anna", "text": "And then?", "t": 675.26}, {"speaker": "Tom", "text": "On the way home she stops at a ticket machine.", "t": 676.86}, {"speaker": "Tom", "text": "It speaks the instructions out loud, and the buttons are easy to feel.", "t": 680.22}, {"speaker": "Tom", "text": "That's the products and services part.", "t": 684.82}, {"speaker": "Tom", "text": "Maria gets through her whole day — on her own, with dignity.", "t": 687.91}, {"speaker": "Anna", "text": "Without needing to ask a stranger for help at every step.", "t": 692.0}, {"speaker": "Tom", "text": "That's the dream.", "t": 695.81}, {"speaker": "Tom", "text": "Independence and dignity.", "t": 697.84}, {"speaker": "Tom", "text": "And that's what these three laws are slowly building.", "t": 700.47}, {"speaker": "Anna", "text": "And honestly — this helps far more people than we think.", "t": 703.87}, {"speaker": "Anna", "text": "Not only people with a permanent disability.", "t": 707.94}, {"speaker": "Tom", "text": "So true.", "t": 711.22}, {"speaker": "Tom", "text": "Think of a parent pushing a pram — they love a ramp too.", "t": 713.19}, {"speaker": "Tom", "text": "Think of someone with a heavy suitcase, or a broken arm.", "t": 717.06}, {"speaker": "Tom", "text": "Think of an older person whose eyes and ears are getting tired.", "t": 721.04}, {"speaker": "Tom", "text": "Accessibility helps everyone, at some point in life.", "t": 724.96}, {"speaker": "Anna", "text": "It's the classic idea — design for the people who need it most, and you make life better for absolutely everyone.", "t": 728.96}, {"speaker": "Tom", "text": "Exactly.", "t": 735.88}, {"speaker": "Tom", "text": "A curb ramp was made for wheelchairs — but the whole town uses it.", "t": 737.79}, {"speaker": "Anna", "text": "Okay, Tom — let's bring it home.", "t": 742.13}, {"speaker": "Anna", "text": "If I'm listening, what should I remember, and what can I do?", "t": 745.32}, {"speaker": "Tom", "text": "Three simple things.", "t": 749.32}, {"speaker": "Tom", "text": "First — remember the website.", "t": 751.61}, {"speaker": "Tom", "text": "accessibilite dot l-u.", "t": 754.29}, {"speaker": "Tom", "text": "It's the official front door to all three areas.", "t": 757.03}, {"speaker": "Anna", "text": "accessibilite.lu.", "t": 760.5}, {"speaker": "Anna", "text": "Got it.", "t": 763.32}, {"speaker": "Tom", "text": "Second — if a public website blocks you, you have the right to complain, and to get an answer.", "t": 764.92}, {"speaker": "Tom", "text": "Don't just give up — report it.", "t": 770.73}, {"speaker": "Anna", "text": "And third?", "t": 773.38}, {"speaker": "Tom", "text": "Third — if a product or a service isn't accessible, you can report that too, through MyGuichet.lu.", "t": 775.05}, {"speaker": "Tom", "text": "Your voice helps make things better, for you and for the next person.", "t": 781.45}, {"speaker": "Anna", "text": "And if you're a professional — an architect, a business owner, a website manager?", "t": 785.61}, {"speaker": "Tom", "text": "Then the website is for you in a different way.", "t": 790.81}, {"speaker": "Tom", "text": "It has the laws, the standards, the toolboxes — everything you need to do your part.", "t": 794.09}, {"speaker": "Tom", "text": "Because accessibility isn't a favour.", "t": 799.5}, {"speaker": "Tom", "text": "It's becoming the normal way to do things.", "t": 802.76}, {"speaker": "Anna", "text": "A short summary to finish?", "t": 805.97}, {"speaker": "Tom", "text": "Sure.", "t": 808.43}, {"speaker": "Tom", "text": "Luxembourg has one official hub — accessibilite.lu — for three areas of accessibility.", "t": 810.05}, {"speaker": "Tom", "text": "Digital, with the law of 2019, for public websites and apps.", "t": 816.2}, {"speaker": "Tom", "text": "Infrastructure, with the law of 2022, for accessible buildings, streets, and housing, built on universal design, with a deadline of 2032 for existing public places.", "t": 821.12}, {"speaker": "Tom", "text": "And products and services, the newest, from the European Accessibility Act, applying since June 2025, watched over by the OSAPS office — with private companies now involved too.", "t": 832.16}, {"speaker": "Anna", "text": "And the message for today?", "t": 843.02}, {"speaker": "Tom", "text": "Accessibility isn't only for \"other people\".", "t": 844.75}, {"speaker": "Tom", "text": "It's for all of us — today, or tomorrow.", "t": 848.45}, {"speaker": "Tom", "text": "A world built for everyone is simply a better world to live in.", "t": 851.81}, {"speaker": "Anna", "text": "So... whether you're a citizen who hits a barrier, or a professional who builds things — remember the front door.", "t": 855.84}, {"speaker": "Anna", "text": "accessibilite.lu.", "t": 862.93}, {"speaker": "Tom", "text": "One website, three promises, and a country slowly opening every door.", "t": 865.75}, {"speaker": "Anna", "text": "That was our episode about accessibility, part of the Biergerpakt — living together in Luxembourg, discovering the country, and looking out for each other.", "t": 870.76}, {"speaker": "Anna", "text": "Thank you so much for listening.", "t": 879.8}, {"speaker": "Tom", "text": "Thank you, everyone.", "t": 882.41}, {"speaker": "Tom", "text": "Take care... and see you next time!", "t": 884.75}, {"speaker": "Anna", "text": "Bye bye!", "t": 887.68}], "questions": [{"text": "What is accessibilite.lu?", "options": ["A private company selling accessibility equipment", "The official Government of Luxembourg hub that brings together three areas of accessibility: digital, infrastructure, and products & services", "A disability benefits application", "A map of wheelchair-friendly restaurants"], "correct": 1, "explanation": "accessibilite.lu is the official public hub of the Government of Luxembourg. It opens onto three portals: digital accessibility, infrastructure accessibility, and accessibility of products and services."}, {"text": "Under the law of 28 May 2019 on digital accessibility, who must make their websites and mobile apps accessible?", "options": ["Every private website in Luxembourg", "Public sector bodies – the State, the communes and public-law bodies", "Only online shops", "Only social media platforms"], "correct": 1, "explanation": "The law of 28 May 2019 requires public sector websites and mobile apps (the State, communes and public-law bodies) to be accessible, following the European standard EN 301 549."}, {"text": "What are the four key principles of digital accessibility?", "options": ["Fast, cheap, modern and colourful", "Perceivable, operable, understandable and robust", "Private, secure, encrypted and backed-up", "Mobile, desktop, tablet and watch"], "correct": 1, "explanation": "Accessible digital content must be perceivable (e.g. text descriptions for images), operable (e.g. usable with a keyboard), understandable (clear and predictable) and robust (works with assistive technologies)."}, {"text": "What idea is the infrastructure law of 7 January 2022 built on, and what is the deadline for existing public places?", "options": ["Separate entrances for disabled people; deadline 2025", "Universal design – places usable by everyone from the start; existing public places accessible by 1 January 2032", "Demolishing all old buildings; deadline 2030", "Voluntary guidelines with no deadline"], "correct": 1, "explanation": "The law (in force since 1 July 2023) is based on universal design – designing places usable by everyone from the start. New builds and major works must comply now; existing places open to the public must be accessible by 1 January 2032."}, {"text": "The accessibility of products and services comes from the European Accessibility Act. Since when does it apply, and how can you report a product or service that isn't accessible?", "options": ["Since 2019; by calling the police", "Since 28 June 2025; online via MyGuichet.lu (to the OSAPS office)", "Since 2030; only by letter", "It does not apply in Luxembourg yet"], "correct": 1, "explanation": "Luxembourg transposed the European Accessibility Act (Law of 8 March 2023), applicable since 28 June 2025. The OSAPS office monitors compliance, and anyone can report a non-accessible product or service online via MyGuichet.lu."}]}, {"id": 10, "key": "zukunftskeess", "number": "Episode 10", "title": "The Zukunftskeess – Money and Support for Your Children", "description": "The Caisse pour l’avenir des enfants (Children’s Future Fund, cae.lu) is the State fund for family benefits in Luxembourg: the birth allowance (paid in three parts linked to health check-ups), the monthly family allowance that grows at ages 6 and 12 and can last to 25 for students, and the automatic back-to-school allowance – plus parental-leave income, childcare vouchers and extra help for children with a disability. Applications go through MyGuichet.lu.", "audio": "podcast_zukunftskeess.mp3", "duration": 934.1, "topics": ["The Zukunftskeess (CAE)", "Birth allowance in 3 parts", "Linked to medical check-ups", "Monthly family allowance", "Grows at age 6 and 12, up to 25", "Back-to-school allowance (automatic)", "Cross-border workers & differential supplement", "Apply via MyGuichet.lu"], "segments": [{"speaker": "Anna", "text": "Hello, and welcome!", "t": 0.0}, {"speaker": "Anna", "text": "It's really nice to have you with us today.", "t": 2.49}, {"speaker": "Tom", "text": "Hello everyone!", "t": 5.53}, {"speaker": "Anna", "text": "This episode is part of the Biergerpakt.", "t": 7.57}, {"speaker": "Anna", "text": "That's a programme of living together in Luxembourg.", "t": 10.67}, {"speaker": "Anna", "text": "The idea is simple... we want to help residents, and also cross-border workers, to discover Luxembourg — or re-discover it — and to meet new people.", "t": 14.25}, {"speaker": "Tom", "text": "Exactly.", "t": 23.64}, {"speaker": "Tom", "text": "And today's topic is one that brings a lot of joy, and also a lot of questions.", "t": 25.57}, {"speaker": "Tom", "text": "It's about children — and the money and support the State gives to families.", "t": 30.59}, {"speaker": "Anna", "text": "And there's one office at the centre of all this.", "t": 35.03}, {"speaker": "Anna", "text": "Tom, tell us its name.", "t": 38.34}, {"speaker": "Tom", "text": "It's called the Zukunftskeess.", "t": 40.96}, {"speaker": "Tom", "text": "In English we can say the Children's Future Fund.", "t": 43.6}, {"speaker": "Tom", "text": "In French it's the Caisse pour l'avenir des enfants.", "t": 47.15}, {"speaker": "Tom", "text": "People also use the short name — C-A-E.", "t": 50.9}, {"speaker": "Anna", "text": "Zukunftskeess.", "t": 54.23}, {"speaker": "Anna", "text": "That's a lovely name — the \"future fund\".", "t": 56.32}, {"speaker": "Anna", "text": "Let's start simply.", "t": 59.63}, {"speaker": "Anna", "text": "What is it?", "t": 61.84}, {"speaker": "Tom", "text": "The Zukunftskeess is the official State fund that pays family benefits in Luxembourg.", "t": 63.64}, {"speaker": "Tom", "text": "So, the money for raising children.", "t": 68.9}, {"speaker": "Tom", "text": "Its home on the internet is c-a-e dot l-u.", "t": 71.97}, {"speaker": "Anna", "text": "cae.lu.", "t": 75.63}, {"speaker": "Anna", "text": "And it's official — it's the State.", "t": 78.11}, {"speaker": "Tom", "text": "Completely official.", "t": 81.16}, {"speaker": "Tom", "text": "It's part of the social security system.", "t": 83.53}, {"speaker": "Tom", "text": "Not a private company.", "t": 86.9}, {"speaker": "Tom", "text": "And it handles all the main benefits connected to having and raising children.", "t": 89.3}, {"speaker": "Anna", "text": "Okay.", "t": 94.03}, {"speaker": "Anna", "text": "So if I have a baby, or I have children already, this is the office that helps me.", "t": 95.65}, {"speaker": "Tom", "text": "Exactly.", "t": 101.13}, {"speaker": "Tom", "text": "Let me give you the big picture first.", "t": 103.06}, {"speaker": "Tom", "text": "There are really three main money benefits.", "t": 106.13}, {"speaker": "Tom", "text": "The birth allowance, around the time the baby is born.", "t": 109.28}, {"speaker": "Tom", "text": "The family allowance, every month as the child grows.", "t": 113.25}, {"speaker": "Tom", "text": "And the back-to-school allowance, once a year for school.", "t": 117.11}, {"speaker": "Anna", "text": "Birth, monthly, and back-to-school.", "t": 121.11}, {"speaker": "Anna", "text": "Let's take them one at a time.", "t": 124.4}, {"speaker": "Anna", "text": "Start with the birth.", "t": 127.04}, {"speaker": "Tom", "text": "So, the birth allowance — in French, the prime de naissance.", "t": 129.12}, {"speaker": "Tom", "text": "It's a flat amount paid around the birth of a child.", "t": 133.47}, {"speaker": "Tom", "text": "The total is about one thousand seven hundred and forty euros.", "t": 136.98}, {"speaker": "Anna", "text": "That's a real help, right when a family needs it.", "t": 141.4}, {"speaker": "Anna", "text": "And is it paid all at once?", "t": 145.06}, {"speaker": "Tom", "text": "No — and this is the clever part.", "t": 147.61}, {"speaker": "Tom", "text": "It comes in three equal parts, of about five hundred and eighty euros each.", "t": 150.7}, {"speaker": "Tom", "text": "And each part is linked to taking care of mother and baby.", "t": 155.72}, {"speaker": "Anna", "text": "Tell me about the three parts.", "t": 159.63}, {"speaker": "Tom", "text": "The first is the prenatal allowance — before the birth.", "t": 162.2}, {"speaker": "Tom", "text": "To get it, the expectant mother goes to her medical check-ups during pregnancy — examinations with the doctor, and also a dental check.", "t": 166.2}, {"speaker": "Anna", "text": "So the first part rewards looking after yourself, and the baby, during pregnancy.", "t": 174.04}, {"speaker": "Tom", "text": "Exactly.", "t": 179.61}, {"speaker": "Tom", "text": "The second part is the birth allowance itself — paid after the birth, with a check-up for the mother.", "t": 181.54}, {"speaker": "Tom", "text": "And the third part is the postnatal allowance — paid after the child's medical check-ups in the first two years of life.", "t": 187.34}, {"speaker": "Anna", "text": "Ah, I see the idea.", "t": 194.02}, {"speaker": "Anna", "text": "The money is tied to health checks — for mum and for baby.", "t": 196.55}, {"speaker": "Tom", "text": "That's the whole philosophy.", "t": 200.59}, {"speaker": "Tom", "text": "It's not only money — it's a gentle way to make sure mother and child see the doctor at the right times.", "t": 203.21}, {"speaker": "Tom", "text": "And here's a nice detail — the three parts are independent.", "t": 208.9}, {"speaker": "Tom", "text": "If you miss the conditions for one part, you can still receive the others.", "t": 212.98}, {"speaker": "Anna", "text": "Good to know.", "t": 217.82}, {"speaker": "Anna", "text": "And how long do you have to apply?", "t": 219.66}, {"speaker": "Tom", "text": "Generally within one year — for the first two parts, within a year of the birth.", "t": 222.33}, {"speaker": "Tom", "text": "And for the postnatal part, within a year of the child's second birthday.", "t": 227.43}, {"speaker": "Tom", "text": "The forms come from your doctor, the maternity hospital, or the commune — and you send them to the Zukunftskeess.", "t": 232.23}, {"speaker": "Anna", "text": "Perfect.", "t": 238.76}, {"speaker": "Anna", "text": "Okay — that's the birth.", "t": 240.49}, {"speaker": "Anna", "text": "Now the big one, I think.", "t": 243.06}, {"speaker": "Anna", "text": "The monthly family allowance.", "t": 245.88}, {"speaker": "Tom", "text": "Yes.", "t": 248.54}, {"speaker": "Tom", "text": "This is the one most people know.", "t": 250.21}, {"speaker": "Tom", "text": "In Luxembourgish people often just say \"Kannergeld\" — children's money.", "t": 253.11}, {"speaker": "Tom", "text": "It's paid every single month, for each child.", "t": 257.82}, {"speaker": "Anna", "text": "From when to when?", "t": 261.42}, {"speaker": "Tom", "text": "From the month the child is born, until they turn eighteen.", "t": 263.44}, {"speaker": "Tom", "text": "And — this is important — it can continue up to the age of twenty-five if the young person is still in secondary school, or doing an apprenticeship.", "t": 267.48}, {"speaker": "Anna", "text": "So as long as the child is still at school, the support keeps going.", "t": 275.61}, {"speaker": "Anna", "text": "And how much is it?", "t": 280.31}, {"speaker": "Tom", "text": "It's set per child, per month.", "t": 282.44}, {"speaker": "Tom", "text": "Right now it's a bit over three hundred euros per child each month.", "t": 285.4}, {"speaker": "Tom", "text": "And here's a key point — it grows as the child gets older.", "t": 289.73}, {"speaker": "Anna", "text": "It grows?", "t": 293.59}, {"speaker": "Anna", "text": "How does that work?", "t": 295.39}, {"speaker": "Tom", "text": "There are two steps up.", "t": 297.43}, {"speaker": "Tom", "text": "The amount increases when the child turns six.", "t": 299.82}, {"speaker": "Tom", "text": "And it increases again when the child turns twelve.", "t": 303.37}, {"speaker": "Tom", "text": "The idea is simple — older children cost more.", "t": 307.06}, {"speaker": "Anna", "text": "That makes sense — teenagers are expensive!", "t": 310.94}, {"speaker": "Anna", "text": "So a young child gets the base amount, a child over six gets a bit more, and a child over twelve gets more again.", "t": 314.59}, {"speaker": "Tom", "text": "Exactly.", "t": 321.98}, {"speaker": "Tom", "text": "Now — one thing I should be honest about.", "t": 323.91}, {"speaker": "Tom", "text": "These amounts are tied to the cost of living.", "t": 327.04}, {"speaker": "Tom", "text": "They go up over time, with what's called the index.", "t": 330.39}, {"speaker": "Tom", "text": "So for the exact figure today, you check the official page — it's the \"social parameters\" page on guichet dot l-u.", "t": 334.1}, {"speaker": "Anna", "text": "Good.", "t": 341.32}, {"speaker": "Anna", "text": "We give the idea, but the precise number — always check the official source.", "t": 342.85}, {"speaker": "Anna", "text": "When is the money actually paid each month?", "t": 348.07}, {"speaker": "Tom", "text": "Every month, and at the latest by the twenty-fifth of the month.", "t": 351.2}, {"speaker": "Tom", "text": "It lands in your bank account that day or the next.", "t": 355.37}, {"speaker": "Tom", "text": "So it's regular, reliable money you can count on.", "t": 359.01}, {"speaker": "Anna", "text": "And do I have to ask for it again every month?", "t": 362.85}, {"speaker": "Tom", "text": "No.", "t": 366.14}, {"speaker": "Tom", "text": "You apply once, when the child is born or when you arrive in Luxembourg.", "t": 367.82}, {"speaker": "Tom", "text": "After that it just comes automatically.", "t": 372.53}, {"speaker": "Tom", "text": "You only need to tell the Zukunftskeess if something changes.", "t": 375.7}, {"speaker": "Anna", "text": "Okay.", "t": 379.77}, {"speaker": "Anna", "text": "So that's birth, and monthly.", "t": 381.39}, {"speaker": "Anna", "text": "Now the third — back-to-school.", "t": 384.2}, {"speaker": "Tom", "text": "Yes — the back-to-school allowance.", "t": 387.04}, {"speaker": "Tom", "text": "In French, the allocation de rentrée scolaire.", "t": 390.09}, {"speaker": "Tom", "text": "It's an extra amount, once a year, to help with the cost of going back to school.", "t": 393.93}, {"speaker": "Tom", "text": "Books, bags, supplies.", "t": 399.32}, {"speaker": "Anna", "text": "Every parent knows that August feeling — buying everything for the new school year.", "t": 402.21}, {"speaker": "Tom", "text": "Exactly.", "t": 407.31}, {"speaker": "Tom", "text": "And here's the good news — you don't have to apply for it separately.", "t": 409.24}, {"speaker": "Tom", "text": "If your child already gets the family allowance, the back-to-school allowance comes automatically.", "t": 413.44}, {"speaker": "Anna", "text": "Automatically.", "t": 419.5}, {"speaker": "Anna", "text": "I love that.", "t": 421.54}, {"speaker": "Anna", "text": "And when does it arrive?", "t": 423.47}, {"speaker": "Tom", "text": "In August, just before the school year.", "t": 425.76}, {"speaker": "Tom", "text": "And the amount depends on the child's age.", "t": 428.93}, {"speaker": "Tom", "text": "For children from six to eleven, it's around one hundred and fifteen euros.", "t": 432.33}, {"speaker": "Tom", "text": "For children twelve and over, it's around two hundred and thirty-five euros.", "t": 437.33}, {"speaker": "Anna", "text": "So again — older child, bigger amount.", "t": 442.1}, {"speaker": "Anna", "text": "The same logic.", "t": 445.67}, {"speaker": "Tom", "text": "The same logic all the way through.", "t": 447.85}, {"speaker": "Tom", "text": "Younger children, base amounts.", "t": 450.73}, {"speaker": "Tom", "text": "Older children, more support.", "t": 453.66}, {"speaker": "Anna", "text": "Tom, let me ask about a worry many families have.", "t": 456.55}, {"speaker": "Anna", "text": "What about cross-border workers?", "t": 460.41}, {"speaker": "Anna", "text": "People who work in Luxembourg but live in France, Belgium, or Germany?", "t": 463.1}, {"speaker": "Tom", "text": "Great question — and very important here, because so many people commute.", "t": 467.98}, {"speaker": "Tom", "text": "The short answer is — yes, if you work in Luxembourg and pay into the Luxembourg social security system, your children can have the right to the family allowance, even if they live across the border.", "t": 472.89}, {"speaker": "Anna", "text": "Even if the children live in another country?", "t": 483.22}, {"speaker": "Tom", "text": "Even then.", "t": 486.33}, {"speaker": "Tom", "text": "This comes from European rules.", "t": 488.23}, {"speaker": "Tom", "text": "Now, there's a detail — if you already receive a family benefit in your country of residence, Luxembourg doesn't pay twice.", "t": 491.19}, {"speaker": "Tom", "text": "It pays the difference — what they call a differential supplement — so you receive the higher of the two.", "t": 498.43}, {"speaker": "Anna", "text": "So you're not worse off.", "t": 504.16}, {"speaker": "Anna", "text": "You get topped up to the Luxembourg level.", "t": 506.51}, {"speaker": "Tom", "text": "That's the idea.", "t": 509.61}, {"speaker": "Tom", "text": "And it works for pensioners too — a retired cross-border worker with a Luxembourg pension keeps the right to the family allowance.", "t": 511.77}, {"speaker": "Anna", "text": "That's reassuring for a lot of families.", "t": 518.85}, {"speaker": "Anna", "text": "Now — let's talk about how you actually deal with the Zukunftskeess.", "t": 522.07}, {"speaker": "Anna", "text": "Is it a lot of paperwork?", "t": 526.73}, {"speaker": "Tom", "text": "It's much easier than it used to be.", "t": 529.2}, {"speaker": "Tom", "text": "Most things can be done online, through MyGuichet.lu — the State's digital platform.", "t": 532.08}, {"speaker": "Tom", "text": "You can apply for the family allowance there, with a secure login like LuxTrust or the eID card.", "t": 537.59}, {"speaker": "Anna", "text": "Ah, MyGuichet.lu — we've talked about that in another episode.", "t": 543.63}, {"speaker": "Tom", "text": "Exactly — it's the online door to the administration.", "t": 548.58}, {"speaker": "Tom", "text": "And through it you can also send documents to the Zukunftskeess, change your bank details, or get a payment certificate.", "t": 552.56}, {"speaker": "Tom", "text": "There's even an online assistant that guides you through the family allowance application, step by step.", "t": 559.44}, {"speaker": "Anna", "text": "And if someone isn't comfortable online?", "t": 565.41}, {"speaker": "Tom", "text": "Then you can still do it on paper.", "t": 568.37}, {"speaker": "Tom", "text": "The forms are on the website, and also at the commune.", "t": 571.32}, {"speaker": "Tom", "text": "You fill them in and send them by post.", "t": 575.18}, {"speaker": "Tom", "text": "And if you have questions, you can call the Zukunftskeess, or visit their offices — they're on the Boulevard Royal, in Luxembourg City.", "t": 578.22}, {"speaker": "Anna", "text": "So there's always a way — online, by post, or in person.", "t": 585.97}, {"speaker": "Anna", "text": "Now Tom, are these three benefits everything the Zukunftskeess does?", "t": 590.7}, {"speaker": "Anna", "text": "Or is there more?", "t": 595.34}, {"speaker": "Tom", "text": "There's more.", "t": 597.32}, {"speaker": "Tom", "text": "Let me mention two other important things it's involved in.", "t": 599.31}, {"speaker": "Tom", "text": "First — for parents who take time off work to look after a young child, there's parental leave, and the Zukunftskeess pays the parental leave income during that time.", "t": 603.27}, {"speaker": "Anna", "text": "So when a mum or dad pauses their job for the baby, they're not left with nothing.", "t": 611.97}, {"speaker": "Tom", "text": "Right — there's a replacement income while they're on parental leave.", "t": 617.3}, {"speaker": "Tom", "text": "And second — there's the childcare voucher, the chèque-service accueil.", "t": 621.39}, {"speaker": "Tom", "text": "It makes crèches, day care, and supervised activities cheaper for families.", "t": 625.92}, {"speaker": "Anna", "text": "So that's help with the cost of childcare — which can be a huge expense.", "t": 631.14}, {"speaker": "Tom", "text": "A huge expense, yes.", "t": 635.93}, {"speaker": "Tom", "text": "So the Zukunftskeess really sits at the centre of family life — from pregnancy, to the baby years, to school, to childcare, to time off work.", "t": 638.71}, {"speaker": "Anna", "text": "And there's also extra support for children with special needs, isn't there?", "t": 647.1}, {"speaker": "Tom", "text": "There is.", "t": 651.92}, {"speaker": "Tom", "text": "For a child with a disability, there's a special supplementary allowance on top of the normal family allowance.", "t": 653.74}, {"speaker": "Tom", "text": "So families who need more help, get more help.", "t": 660.34}, {"speaker": "Anna", "text": "That's a caring system.", "t": 663.93}, {"speaker": "Anna", "text": "Tom, let's make it really concrete.", "t": 666.33}, {"speaker": "Anna", "text": "Can we follow one family?", "t": 669.48}, {"speaker": "Tom", "text": "Of course.", "t": 671.92}, {"speaker": "Tom", "text": "Let's imagine a couple — they're expecting their first baby.", "t": 673.74}, {"speaker": "Anna", "text": "Exciting!", "t": 677.71}, {"speaker": "Anna", "text": "So where does the Zukunftskeess come in, from the very start?", "t": 679.51}, {"speaker": "Tom", "text": "Even before the birth.", "t": 683.75}, {"speaker": "Tom", "text": "During the pregnancy, the mother goes to her check-ups, and the dental visit — and that opens the first part of the birth allowance, the prenatal part.", "t": 686.13}, {"speaker": "Tom", "text": "About five hundred and eighty euros.", "t": 694.34}, {"speaker": "Anna", "text": "Then the baby arrives.", "t": 697.45}, {"speaker": "Tom", "text": "The baby arrives.", "t": 699.78}, {"speaker": "Tom", "text": "They register the birth at the commune, and that triggers the second part of the birth allowance.", "t": 702.0}, {"speaker": "Tom", "text": "And they make one application for the monthly family allowance — through MyGuichet.lu.", "t": 707.62}, {"speaker": "Anna", "text": "And from then on, the monthly money starts.", "t": 713.19}, {"speaker": "Tom", "text": "Every month, by the twenty-fifth — a bit over three hundred euros, automatically.", "t": 716.72}, {"speaker": "Tom", "text": "Then, over the first two years, they take the baby to its medical check-ups, and that unlocks the third part of the birth allowance.", "t": 722.21}, {"speaker": "Anna", "text": "So in the first two years, they've received all three parts of the birth allowance, plus the monthly allowance.", "t": 729.56}, {"speaker": "Tom", "text": "Exactly.", "t": 736.18}, {"speaker": "Tom", "text": "The child turns six — the monthly amount goes up a step, and the back-to-school allowance begins each August.", "t": 738.11}, {"speaker": "Tom", "text": "The child turns twelve — another step up.", "t": 744.48}, {"speaker": "Tom", "text": "And it all continues, right through school, possibly to age twenty-five.", "t": 747.79}, {"speaker": "Anna", "text": "And the parents only really did one big thing — they applied once, and kept their details up to date.", "t": 752.85}, {"speaker": "Tom", "text": "That's the beauty of it.", "t": 759.38}, {"speaker": "Tom", "text": "Apply once, keep your information current, and the support flows.", "t": 761.69}, {"speaker": "Tom", "text": "Calm and predictable, through the whole childhood.", "t": 766.35}, {"speaker": "Anna", "text": "I really like that picture.", "t": 769.86}, {"speaker": "Anna", "text": "Okay Tom — let's bring it home.", "t": 772.5}, {"speaker": "Anna", "text": "If I'm listening, and I have children, or one on the way — what should I do?", "t": 775.54}, {"speaker": "Tom", "text": "Three simple steps.", "t": 780.6}, {"speaker": "Tom", "text": "First — go to the website, c-a-e dot l-u, or to MyGuichet.lu.", "t": 782.98}, {"speaker": "Tom", "text": "That's where everything starts.", "t": 787.8}, {"speaker": "Anna", "text": "cae.lu.", "t": 790.39}, {"speaker": "Anna", "text": "Got it.", "t": 792.88}, {"speaker": "Tom", "text": "Second — if you're expecting, start the birth allowance early, by going to your check-ups, and apply for the monthly family allowance when the baby is born.", "t": 794.52}, {"speaker": "Tom", "text": "You only do it once.", "t": 802.96}, {"speaker": "Anna", "text": "And third?", "t": 805.44}, {"speaker": "Tom", "text": "Third — keep your details up to date, especially your bank account and your situation.", "t": 807.15}, {"speaker": "Tom", "text": "And if your child turns eighteen but stays in school, send back the form to keep the allowance going up to twenty-five.", "t": 812.46}, {"speaker": "Anna", "text": "And for cross-border workers?", "t": 819.17}, {"speaker": "Tom", "text": "Same office, same website.", "t": 821.7}, {"speaker": "Tom", "text": "If you work in Luxembourg, your children may have the right too — so don't assume you're not eligible.", "t": 824.51}, {"speaker": "Tom", "text": "Check with the Zukunftskeess.", "t": 830.36}, {"speaker": "Anna", "text": "A short summary to finish?", "t": 833.06}, {"speaker": "Tom", "text": "Sure.", "t": 835.57}, {"speaker": "Tom", "text": "The Zukunftskeess — the Children's Future Fund, cae.lu — is the State office for family benefits in Luxembourg.", "t": 837.21}, {"speaker": "Tom", "text": "Three main ones.", "t": 844.52}, {"speaker": "Tom", "text": "A birth allowance of about one thousand seven hundred euros, in three parts, linked to health check-ups.", "t": 846.71}, {"speaker": "Tom", "text": "A monthly family allowance for each child — a bit over three hundred euros — that grows at age six and age twelve, and can last until twenty-five if the child stays in school.", "t": 852.98}, {"speaker": "Tom", "text": "And a back-to-school allowance each August, automatically.", "t": 862.46}, {"speaker": "Tom", "text": "Plus parental leave income, childcare vouchers, and extra help for children with special needs.", "t": 866.73}, {"speaker": "Anna", "text": "And the message for today?", "t": 872.54}, {"speaker": "Tom", "text": "If you have children in Luxembourg, this support is yours by right — and it's easier to get than people think.", "t": 874.83}, {"speaker": "Tom", "text": "One office, one website, and a system that walks beside your family for years.", "t": 881.0}, {"speaker": "Anna", "text": "So... whether you're a new parent, an old hand, or a cross-border worker — remember the name.", "t": 886.18}, {"speaker": "Anna", "text": "The Zukunftskeess.", "t": 892.33}, {"speaker": "Anna", "text": "cae.lu.", "t": 894.55}, {"speaker": "Tom", "text": "One fund, looking after the future of your children.", "t": 897.03}, {"speaker": "Tom", "text": "That's exactly what the name says.", "t": 900.83}, {"speaker": "Anna", "text": "That was our episode about the Zukunftskeess, part of the Biergerpakt — living together in Luxembourg, discovering the country, and looking out for each other.", "t": 903.78}, {"speaker": "Anna", "text": "Thank you so much for listening.", "t": 913.02}, {"speaker": "Tom", "text": "Thank you, everyone.", "t": 915.66}, {"speaker": "Tom", "text": "Take care... and see you next time!", "t": 918.04}, {"speaker": "Anna", "text": "Bye bye!", "t": 921.01}], "questions": [{"text": "What is the Zukunftskeess (Caisse pour l’avenir des enfants / CAE)?", "options": ["A private savings plan for children", "The official State fund that pays family benefits in Luxembourg", "A children’s bank account", "A daycare chain"], "correct": 1, "explanation": "The Zukunftskeess – the Children’s Future Fund (cae.lu) – is the official State fund, part of social security, that pays family benefits such as the birth allowance, the monthly family allowance and the back-to-school allowance."}, {"text": "How is the birth allowance (about €1,740) paid, and what is it linked to?", "options": ["In one payment, with no conditions", "In three equal parts of about €580, each linked to medical check-ups for mother and child (prenatal, birth, postnatal)", "Only if you have a second child", "As a monthly top-up for two years"], "correct": 1, "explanation": "The birth allowance totals about €1,740.09, paid in three independent instalments of €580.03 – prenatal, birth and postnatal – each tied to completing the medical examinations for mother and baby."}, {"text": "Until what age is the monthly family allowance normally paid, and how does the amount change as the child grows?", "options": ["Until age 12, and it never changes", "From birth until 18 (up to 25 if still in secondary school or an apprenticeship); the amount increases at age 6 and again at age 12", "Only between ages 6 and 16", "Until age 30 for everyone"], "correct": 1, "explanation": "The family allowance is paid per child from the month of birth until 18 – and up to 25 if the young person is still in secondary education or an apprenticeship. The amount steps up at age 6 and again at age 12."}, {"text": "How do you get the back-to-school allowance, and when is it paid?", "options": ["You must apply separately every July", "It is paid automatically to children already receiving the family allowance, in August each year", "Only families with three or more children receive it", "It is paid in December"], "correct": 1, "explanation": "Children who already receive the family allowance get the back-to-school allowance automatically, paid in August. The amount depends on age (around €115 for ages 6–11 and €235 for 12 and over)."}, {"text": "You work in Luxembourg but your children live in France, Belgium or Germany. What is the position on family allowance?", "options": ["You get nothing because the children live abroad", "If you are covered by Luxembourg social security, your children can be entitled; if a benefit is already paid in the country of residence, Luxembourg pays a differential supplement (top-up)", "You must move the children to Luxembourg first", "You receive double the amount automatically"], "correct": 1, "explanation": "Under European rules, children of cross-border workers covered by Luxembourg social security can be entitled to the family allowance even if they live abroad. If a similar benefit is already paid in the country of residence, Luxembourg pays the difference so the family receives the higher amount."}]}];
